// Permite obtener el nombre de cada mes
function nombre_meses($num_mes)
{
	if ($num_mes == 1) {
		return "ENERO";
	}
	if ($num_mes == 2) {
		return "FEBRERO";
	}
	if ($num_mes == 3) {
		return "MARZO";
	}
	if ($num_mes == 4) {
		return "ABRIL";
	}
	if ($num_mes == 5) {
		return "MAYO";
	}
	if ($num_mes == 6) {
		return "JUNIO";
	}
	if ($num_mes == 7) {
		return "JULIO";
	}
	if ($num_mes == 8) {
		return "AGOSTO";
	}
	if ($num_mes == 9) {
		return "SEPTIEMBRE";
	}
	if ($num_mes == 10) {
		return "OCTUBRE";
	}
	if ($num_mes == 11) {
		return "NOVIEMBRE";
	}
	if ($num_mes == 12) {
		return "DICIEMBRE";
	}
}

function f_getTipoPagoValorizacion($enlace, $id_valorizacion)
{
	$q_tipo_pago = "
								SELECT
										vc.usa_anticipo,
										vc.id_cuentabancaria
								FROM
										valorizacion_compramineral vc
								WHERE
										vc.id = $id_valorizacion;
						";

	$res_tipo_pago = mysqli_query($enlace, $q_tipo_pago);
	$tipo_pago = "";
	if ($res_tipo_pago && mysqli_num_rows($res_tipo_pago) > 0) {
		$row = mysqli_fetch_assoc($res_tipo_pago);

		$usa_anticipo = (is_null($row['usa_anticipo'])) ? 0 : $row['usa_anticipo'];
		$id_cuentabancaria = (is_null($row['id_cuentabancaria'])) ? 0 : $row['id_cuentabancaria'];
		// return var_dump("Usa anticipo: $usa_anticipo  |  ID Cuenta: $id_cuentabancaria");

		// si usa anticipoy tiene id de cuenta bancaria, es mixto
		if ($usa_anticipo == 1 && $id_cuentabancaria != 0) {
			$tipo_pago = "mixto";
			// si usa anticipo y no tiene una cuenta bancaria, es anticipo
		} elseif ($usa_anticipo == 1 && $id_cuentabancaria == 0) {
			$tipo_pago = "anticipo";
			// si no usa anticipo pero tiene cuenta bancaria, entonces es banco
		} elseif ($usa_anticipo == 0 && $id_cuentabancaria != 0) {
			$tipo_pago = "banco";
		}
		return $tipo_pago;
	}

	throw new Exception("No se encontro informacion del tipo de pago de la valorizacion.");
}

function f_UpdateAllComprobantesStatus($enlace)
{
	$q = "SELECT Id FROM comprobante_pago cp where cp.estado != 'X'";
	$res = mysqli_query($enlace, $q);

	if (!$res) {
		return false;
	}

	$processed = 0;
	while ($row = mysqli_fetch_assoc($res)) {
		if (f_UpdateComprobanteStatus($enlace, $row['Id'])) {
			$processed++;
		}
	}

	return $processed;
}

function f_UpdateComprobanteStatus($enlace, $id_comprobante)
{
	$id_comprobante = intval($id_comprobante);

	// 1. Obtener la "hoja de ruta" del comprobante (Lo que DEBE ser)
	$q = "SELECT
                id_valorizacion,
                sub_total AS monto_objetivo_neto,
                total_detraccion_soles AS monto_objetivo_detraccion,
                estado
          FROM comprobante_pago
          WHERE aprobo_contabilidad = 1 
            AND aprobo_comercial = 1 
            AND aprobo_documentaria = 1 
			AND estado != 'X'
            AND Id = $id_comprobante";

	$res = mysqli_query($enlace, $q);
	if (!$res || mysqli_num_rows($res) == 0)
		return false;

	$row = mysqli_fetch_assoc($res);
	if ($row['estado'] == 'X')
		return false;

	$id_valorizacion = intval($row['id_valorizacion']);
	$monto_objetivo_neto = floatval($row['monto_objetivo_neto']);
	$monto_objetivo_detraccion = floatval($row['monto_objetivo_detraccion']);
	$tipo_pago = f_getTipoPagoValorizacion($enlace, $id_valorizacion);

	// 2. Calcular lo PAGADO REALMENTE (Lo que ES)
	$pagos_realizados_neto = 0.0;
	$pagos_realizados_detraccion = 0.0;

	if ($id_valorizacion > 0) {
		// PAGOS NETOS (Moneda 2: Transferencias o Anticipos)
		if ($tipo_pago == "banco" || $tipo_pago == "mixto") {
			$q_neto = "SELECT SUM(monto_pago) as total 
                       FROM comprobante_pago_pagos 
                       WHERE id_comprobante_pago = $id_comprobante 
                         AND id_moneda_destino = 2 AND estado = 'A'";
			$res_neto = mysqli_query($enlace, $q_neto);
			if ($res_neto && $r = mysqli_fetch_assoc($res_neto))
				$pagos_realizados_neto += floatval($r['total']);
		}

		if ($tipo_pago == "anticipo" || $tipo_pago == "mixto") {
			$q_ant = "SELECT SUM(monto_retirado) as total 
                      FROM proveedor_anticipo_transaccion 
                      WHERE id_valorizacion_compramineral = $id_valorizacion AND estado = 'A'";
			$res_ant = mysqli_query($enlace, $q_ant);
			if ($res_ant && $r = mysqli_fetch_assoc($res_ant))
				$pagos_realizados_neto += floatval($r['total']);
		}

		// PAGOS DETRACCIÓN (Moneda 1: Siempre por tabla de pagos)
		$q_det = "SELECT SUM(monto_pago) as total 
                  FROM comprobante_pago_pagos 
                  WHERE id_comprobante_pago = $id_comprobante 
                    AND id_moneda_destino = 1 AND estado = 'A'";
		$res_det = mysqli_query($enlace, $q_det);
		if ($res_det && $r = mysqli_fetch_assoc($res_det)) {
			$pagos_realizados_detraccion = floatval($r['total']);
		}
	}

	// 3. Validación con margen de error (Epsilon)
	$epsilon = 0.5;
	$cumple_neto = ($pagos_realizados_neto >= ($monto_objetivo_neto - $epsilon));
	$cumple_detraccion = ($pagos_realizados_detraccion >= ($monto_objetivo_detraccion - $epsilon));

	// 4. Asignación de nuevo estado
	if ($cumple_neto && $cumple_detraccion) {
		$estados = ['mixto' => 'A', 'anticipo' => 'C', 'banco' => 'B'];
		$nuevo_estado = $estados[$tipo_pago] ?? 'P';
	} else {
		$nuevo_estado = 'P';
	}

	$q_update = "UPDATE comprobante_pago SET estado = '$nuevo_estado' WHERE Id = $id_comprobante";
	return mysqli_query($enlace, $q_update);
}

function f_GrabarImagenes_RecepcionAcompanantes(
	$enlace,
	$id_registro,
	$arr_acompanantes
) {
	$estado = 1;

	// Recupera variables
	// $id_registro = mysqli_real_escape_string($enlace, $_POST["id_registro"]);
	// $arr_acompanantes = $_POST["arr_acompanantes"];
	// $usuario_registro = $_SESSION["usu_usuario"];

	// Graba datos de recepción
	$arr_acompanantes = json_decode($arr_acompanantes, true);

	foreach ($arr_acompanantes as $acompanante) {
		$cod_auto = $acompanante["cod_auto"];
		$imagen = trim($acompanante["imagen"]);

		if (strlen($imagen) > 0) {
			// $imagenBase64Comprimida = f_ComprimirImagenes($imagen);

			// Eliminar la cabecera de datos si existe (por ejemplo, "data:image/png;base64,")
			if (preg_match("/^data:image\/(\w+);base64,/", $imagen, $type)) {
				$base64String = substr($imagen, strpos($imagen, ",") + 1);
				$type = strtolower($type[1]); // jpg, png, gif, etc.
			} else {
				die("El formato base64 no es válido.");
			}

			// Decodificar el base64
			$imagenData = base64_decode($base64String);

			if ($imagenData === false) {
				die("La decodificación de la imagen falló.");
			}

			// Generar un nombre aleatorio único con fecha y hora
			$date = date("Ymd_His"); // Fecha y hora (ejemplo: 20250114_134500)
			$randomHash = bin2hex(random_bytes(16)); // Genera 32 caracteres aleatorios (128 bits en hexadecimal)
			$fileName = $date . "_" . $randomHash . "." . $type;

			// Especificar la ruta y el nombre del archivo para guardar la imagen
			$filePath = "../files/recepcion/" . $fileName;

			// Guardar la imagen
			file_put_contents($filePath, $imagenData);

			$imagenBase64Comprimida = "";
			$imagenBase64URL = $fileName;
		} else {
			$imagenBase64Comprimida = "";
			$imagenBase64URL = "";
		}

		// Consulta para guardar el acompanante en la tabla correspondiente
		$q_save = "UPDATE controlingresovehiculo_acompanantes SET ";
		$q_save .=
			"   imagen = " .
			(strlen($imagenBase64Comprimida) == 0
				? "NULL"
				: "'" . $imagenBase64Comprimida . "'");
		$q_save .=
			"   ,imagen_url = " .
			(strlen($imagenBase64URL) == 0
				? "NULL"
				: "'" . $imagenBase64URL . "'");
		$q_save .= " WHERE id_controlingreso = " . $id_registro;
		$q_save .= "   AND cod_auto = " . $cod_auto . "; ";

		if ($res_save = mysqli_query($enlace, $q_save)) {
		} else {
			$estado = 0;
		}
	}

	return $estado;
}

