// Proceso de compresión de Imágenes
function f_ComprimirImagenes($imagenBase64)
{
	// Decodificar la imagen base64
	$imagenDecodificada = base64_decode(
		preg_replace("#^data:image/\w+;base64,#i", "", $imagenBase64)
	);

	// Crear una imagen a partir de los datos decodificados
	$imagenOriginal = imagecreatefromstring($imagenDecodificada);

	if ($imagenOriginal === false) {
		// No se pudo crear la imagen original, manejar el error
		return false;
	}

	// Crear una imagen comprimida
	$imagenComprimida = imagecreatetruecolor(
		imagesx($imagenOriginal),
		imagesy($imagenOriginal)
	);

	// Manejar el tipo de imagen
	$imageType = exif_imagetype($imagenBase64);

	switch ($imageType) {
		case IMAGETYPE_JPEG:
			// Si es JPEG, copiar y comprimir
			imagecopyresampled(
				$imagenComprimida,
				$imagenOriginal,
				0,
				0,
				0,
				0,
				imagesx($imagenOriginal),
				imagesy($imagenOriginal),
				imagesx($imagenOriginal),
				imagesy($imagenOriginal)
			);

			break;

		case IMAGETYPE_PNG:
			// Si es PNG, copiar y comprimir
			imagecopyresampled(
				$imagenComprimida,
				$imagenOriginal,
				0,
				0,
				0,
				0,
				imagesx($imagenOriginal),
				imagesy($imagenOriginal),
				imagesx($imagenOriginal),
				imagesy($imagenOriginal)
			);

			break;

		// Agrega más casos según sea necesario para otros tipos de imagen (por ejemplo, IMAGETYPE_GIF, IMAGETYPE_BMP, etc.)
		default:
			// Tipo de imagen no compatible, manejar el error
			return false;
	}
	// // ------------
	// // Decodificar la imagen base64
	// $imagenDecodificada = base64_decode(preg_replace('#^data:image/\w+;base64,#i', '', $imagenBase64));

	// // Crear una imagen a partir de los datos decodificados
	// $imagenOriginal = imagecreatefromstring($imagenDecodificada);

	// // Crear una imagen comprimida
	// $imagenComprimida = imagecreatetruecolor(imagesx($imagenOriginal), imagesy($imagenOriginal));

	// // Comprimir la imagen copiándola en la imagen comprimida
	// imagecopyresampled($imagenComprimida, $imagenOriginal, 0, 0, 0, 0, imagesx($imagenOriginal), imagesy($imagenOriginal), imagesx($imagenOriginal), imagesy($imagenOriginal));

	// Guardar la imagen comprimida en un buffer de salida
	ob_start();
	imagejpeg($imagenComprimida, null, 15); // El tercer parámetro representa la calidad de compresión (ajústalo según tus necesidades)
	$imagenComprimidaBase64 =
		"data:image/jpeg;base64," . base64_encode(ob_get_clean());

	return $imagenComprimidaBase64;
}

// Obtener Peso Seco en función a la Humedad
function f_GetPesoSeco($tmh, $h2o)
{
	if (strlen(trim($tmh)) > 0 && strlen(trim($h2o)) > 0) {
		// Obtiene factor de humedad
		$factor = (100 - $h2o) / 100;

		// Obtiene Peso Seco
		$peso_seco = $tmh * $factor;
	} else {
		$peso_seco = "";
	}

	return $peso_seco;
}

// Proceso de eliminación de Lote de Programación - Despachos Segundo tramo
function f_Eliminar_DespachoSegundoTramo_ProgramacionLote(
	$enlace,
	$id_programacionlote,
	$fechahora_registro,
	$usuario_registro
) {
	$estado = 0;

	// Obtiene el id_validaciondatos
	$id_validaciondatos = 0;

	$q_datos =
		"SELECT id_validaciondatos
											FROM despachos_segundotramo_programacion_detalle
										 WHERE Id = " . $id_programacionlote;

	if ($res_datos = mysqli_query($enlace, $q_datos)) {
		if (mysqli_num_rows($res_datos) > 0) {
			while ($row_datos = mysqli_fetch_array($res_datos)) {
				$id_validaciondatos = $row_datos["id_validaciondatos"];
			}
		}
	}

	// Guardando Log
	$q_log =
		"INSERT INTO despachos_segundotramo_programacion_detalle_log (Id, id_programacion, id_validaciondatos, cod_lote, num_parte, codigo_gel, id_planta, id_modalidadenvio, codigo_despacho, codigo_despacho_comercializacion, codigo_planta, TMH, fechahora_registro, usuario_registro, fechahora_log, usuario_log) ";
	$q_log .=
		"SELECT *,
													'" .
		$fechahora_registro .
		"',
													'" .
		$usuario_registro .
		"'
										 FROM despachos_segundotramo_programacion_detalle
										WHERE Id = " .
		$id_programacionlote;

	if ($res_save = mysqli_query($enlace, $q_log)) {
		$q_delete = "DELETE FROM despachos_segundotramo_programacion_detalle";
		$q_delete .= " WHERE Id = " . $id_programacionlote;

		if ($res_delete = mysqli_query($enlace, $q_delete)) {
		}
	}

	// Eliminando la Distribución del Lote seleccionado
	$q_delete3 =
		"DELETE FROM despachos_segundotramo_distribucion_lotes
											WHERE id_validaciondatos = " . $id_validaciondatos;

	if ($res_delete3 = mysqli_query($enlace, $q_delete3)) {
		$estado = 1;
	}

	return $estado;
}

