	return $estado;
}

// Proceso utilizado para actualizar la Presentación de Cargas en los despachos, donde la mayor distribución siempre es Granel.
function f_Update_DespachoSegundoTramo_PresentacionCarga(
	$enlace,
	$id_distribucionunidad
) {
	// 1. Obtiene el Id del Item con el mayor peso distribuido
	$id_registro = 0;

	$q_idregistro =
		"SELECT Id
													 FROM despachos_segundotramo_distribucion_lotes
													WHERE id_distribucionunidad = " .
		$id_distribucionunidad .
		"
												 ORDER BY peso_distribuido DESC
												 LIMIT 1";

	if ($res_idregistro = mysqli_query($enlace, $q_idregistro)) {
		if (mysqli_num_rows($res_idregistro) > 0) {
			while ($row_idregistro = mysqli_fetch_array($res_idregistro)) {
				$id_registro = $row_idregistro["Id"];
			}
		}
	}

	// 2. Actualiza Presentación
	$q_update = "UPDATE despachos_segundotramo_distribucion_lotes SET";
	$q_update .= "   id_tipocarga = 1";
	$q_update .= " WHERE Id = " . $id_registro;

	if ($res_update = mysqli_query($enlace, $q_update)) {
		$q_update = "UPDATE despachos_segundotramo_distribucion_lotes SET";
		$q_update .= "   id_tipocarga = 5";
		$q_update .=
			" WHERE Id IN (SELECT Id
																				FROM (SELECT Id
																								FROM despachos_segundotramo_distribucion_lotes
																							 WHERE id_distribucionunidad = " .
			$id_distribucionunidad .
			"
																								 AND Id <> " .
			$id_registro .
			") AS DATOS)";

		if ($res_update = mysqli_query($enlace, $q_update)) {
		}
	}
}

// Proceso para Recalcular los Tickets de balanza
function f_RecalcularTicketsBalanza($enlace, $id_registro)
{
	$estado = false;

	// Obtiene los datos del periodo del correlativo
	$cod_anho = "";
	$cod_mes = "";
	$cod_dia = "";

	$q_datos =
		"SELECT IFNULL(tFechaInicialBalanza, dFechaIngreso) AS FECHA
											FROM catalogolotes
										 WHERE id_CatalogoLotes = " . $id_registro;

	if ($res_datos = mysqli_query($enlace, $q_datos)) {
		if (mysqli_num_rows($res_datos) > 0) {
			while ($row_datos = mysqli_fetch_array($res_datos)) {
				$cod_anho = explode("-", $row_datos["FECHA"])[0];
				$cod_mes = explode("-", $row_datos["FECHA"])[1];
				$cod_dia = explode("-", $row_datos["FECHA"])[2];
			}
		}
	}

	// Actualizando los registro con los nuevos correlativos
	// $q_update = "UPDATE correlativo_ticketsbalanza SET";
	// $q_update .= "   correlativo = correlativo - 1";
	// $q_update .= " WHERE cod_anho = ".$cod_anho;
	// $q_update .= "   AND cod_mes = ".$cod_mes;
	// $q_update .= "   AND cod_dia = ".$cod_dia;
	// $q_update .= "   AND id_lote > ".$id_registro;

	$q_update = "UPDATE correlativo_ticketsbalanza SET";
	$q_update .= "   correlativo = correlativo - 1";
	$q_update .= " WHERE id_lote > " . $id_registro;

	if ($res_update = mysqli_query($enlace, $q_update)) {
		$q_delete = "DELETE FROM correlativo_ticketsbalanza";
		$q_delete .= " WHERE id_lote = " . $id_registro;

		if ($res_delete = mysqli_query($enlace, $q_delete)) {
			// Actualizando los correlativos en la tabla de Lotes: "catalogolotes"
			// $q_update = "UPDATE catalogolotes SET";
			// $q_update .= "   nNro_ticketsBalanza = (SELECT CONCAT(LPAD(T.cod_dia, 2, '0'),
			// 																											LPAD(T.cod_mes, 2, '0'),
			// 																											SUBSTRING(T.cod_anho, 3), '-',
			// 																											LPAD(T.correlativo, 3, '0'))
			// 																					FROM correlativo_ticketsbalanza T
			// 																				 WHERE T.id_lote = catalogolotes.id_CatalogoLotes)";
			// $q_update .= " WHERE YEAR(IFNULL(tFechaInicialBalanza, dFechaIngreso)) = ".$cod_anho;
			// $q_update .= "   AND MONTH(IFNULL(tFechaInicialBalanza, dFechaIngreso)) = ".$cod_mes;
			// $q_update .= "   AND DAY(IFNULL(tFechaInicialBalanza, dFechaIngreso)) = ".$cod_dia;
			// $q_update .= "   AND id_CatalogoLotes > ".$id_registro;

			$q_update = "UPDATE catalogolotes SET";
			$q_update .= "   nNro_ticketsBalanza = (SELECT T.correlativo
																												FROM correlativo_ticketsbalanza T
																											 WHERE T.id_lote = catalogolotes.id_CatalogoLotes)";
			$q_update .= " WHERE id_CatalogoLotes > " . $id_registro;

			if ($res_update = mysqli_query($enlace, $q_update)) {
				$estado = true;
			}
		}
	}

	return $estado;
}

// Función equivalente a "REDONDEAR.MAX" de Excel
function f_Redondear_Mas($valor, $num_decimales)
{
	// Obteniendo la parte decimal
	$decimales = explode(".", $valor)[1];

	if (strlen($decimales) == 0) {
		$valor = $valor . ".00";
	} else {
		$valor =
			ceil($valor * pow(10, $num_decimales)) / pow(10, $num_decimales);
	}

	return $valor;
}

// Función para Generar Códigos de Planta para Colibrí (Programación de Despachos - 2do tramo)
function f_SetCodigosPlanta(
	$enlace,
	$id_planta,
	$id_programacion,
	$fecha_registro,
	$usuario_registro
) {
	if ($id_planta == 3) {
		// 1. Obtiene el Prefijo del Código de Planta
		$correlativo_prefijo = "";

		$q_prefijo =
			"SELECT correlativo_prefijo
													FROM tbconfig_plantas
												 WHERE Id = " . $id_planta;

		if ($res_prefijo = mysqli_query($enlace, $q_prefijo)) {
			if (mysqli_num_rows($res_prefijo) > 0) {
				while ($row_prefijo = mysqli_fetch_array($res_prefijo)) {
					$correlativo_prefijo = $row_prefijo["correlativo_prefijo"];
				}
			}
		}

		// 2. Obtiene el ultimo correlativo de la Programación anterior
		$ultimo_codigo = "";

		$q_ultimo =
			"SELECT MAX(D.codigo_planta) AS ULTIMO_CODIGO
												 FROM despachos_segundotramo_programacion_detalle D
												WHERE D.id_programacion = (SELECT D_x.id_programacion
																										 FROM despachos_segundotramo_programacion_detalle D_x
																										WHERE D_x.id_planta = " .
			$id_planta .
			"
																											AND D_x.id_programacion < " .
			$id_programacion .
			"
																									 ORDER BY D_x.id_programacion DESC
																									 LIMIT 1)";

		if ($res_ultimo = mysqli_query($enlace, $q_ultimo)) {
			if (mysqli_num_rows($res_ultimo) > 0) {
				while ($row_ultimo = mysqli_fetch_array($res_ultimo)) {
					$ultimo_codigo = $row_ultimo["ULTIMO_CODIGO"];
					$ultimo_codigo = substr(
						$ultimo_codigo,
						strpos($ultimo_codigo, "-") + 1
					);
				}
			}
		}

		// 3. Elimina los Correlativos que puedan existir en la tabla de correlativos de planta, menos los creados en balanza
		$q_delete =
			"DELETE FROM correlativo_plantas
												WHERE id_programaciondetalle IN (SELECT Id
																													 FROM despachos_segundotramo_programacion_detalle
																													WHERE id_programacion = " .
			$id_programacion .
			")";

		if ($res_delete = mysqli_query($enlace, $q_delete)) {
		}

		// 3. Asigna los Códigos de Planta por cada Lote
		$new_codigo = intval($ultimo_codigo);

		$q_detalle =
			"SELECT Id,
															 cod_lote
													FROM despachos_segundotramo_programacion_detalle
												 WHERE id_programacion = " .
			$id_programacion .
			"
												ORDER BY cod_lote";

		if ($res_detalle = mysqli_query($enlace, $q_detalle)) {
			if (mysqli_num_rows($res_detalle) > 0) {
				while ($row_detalle = mysqli_fetch_array($res_detalle)) {
					// Verificar si es un Lote con Código de Planta creado en balanza
					$q_verify =
						"SELECT codigo_planta
																 FROM correlativo_plantas
																WHERE codlote_balanza = '" .
						$row_detalle["cod_lote"] .
						"'";

					if ($res_verify = mysqli_query($enlace, $q_verify)) {
						if (mysqli_num_rows($res_verify) > 0) {
							while (
								$row_verify = mysqli_fetch_array($res_verify)
							) {
								$q_update =
									"UPDATE despachos_segundotramo_programacion_detalle SET";
								$q_update .=
									"   codigo_planta = '" .
									$row_verify["codigo_planta"] .
									"'";
								$q_update .=
									" WHERE Id = " . $row_detalle["Id"];

								if (
									$res_update = mysqli_query(
										$enlace,
										$q_update
									)
								) {
								}
							}
						} else {
							// Recorre los siguientes códigos hasta encontrar uno disponible
							$c = 1;

							while ($c < 999) {
								$new_codigo++;

								$q_verify =
									"SELECT codigo_planta
																				 FROM correlativo_plantas
																				WHERE correlativo = " .
									$new_codigo .
									"
																					AND is_creadoenbalanza = 1";

								if (
									$res_verify = mysqli_query(
										$enlace,
										$q_verify
									)
								) {
									if (mysqli_num_rows($res_verify) == 0) {
										// Asigna el nuevo correlativo
										$correlaivo_planta =
											$correlativo_prefijo .
											str_pad(
												$new_codigo,
												4,
												"0",
												STR_PAD_LEFT
											);

										$q_update =
											"UPDATE despachos_segundotramo_programacion_detalle SET";
										$q_update .=
											"   codigo_planta = '" .
											$correlaivo_planta .
											"'";
										$q_update .=
											" WHERE Id = " . $row_detalle["Id"];

										if (
											$res_update = mysqli_query(
												$enlace,
												$q_update
											)
										) {
										}

										// Inserta el correlativo en la tabla de correlativos planta
										$q_insert = "INSERT INTO correlativo_plantas (id_planta, id_programaciondetalle, correlativo,
																																							codigo_planta, fechahora_registro, usuario_registro)
																						 VALUES (";
										$q_insert .= $id_planta . ", ";
										$q_insert .= $row_detalle["Id"] . ", ";
										$q_insert .= $new_codigo . ", ";
										$q_insert .=
											"'" . $correlaivo_planta . "', ";
										$q_insert .=
											"'" . $fecha_registro . "', ";
										$q_insert .=
											"'" . $usuario_registro . "')";

										if (
											$res_insert = mysqli_query(
												$enlace,
												$q_insert
											)
										) {
											$c = 999;
										}
									}
								}

								$c++;
							}
						}
					}
				}
			}
		}
	}
}

// Función para Generar Códigos de Comercialización para Colibrí (Programación de Despachos - 2do tramo)
function f_SetCodigosComercializacion(
