								) == 0 &&
								$nuevocorrelativo_viii == 0
							) {
								$is_newcodigo = 1;
								// $new_codigo ++;

								// Asigna el nuevo correlativo
								// 1. Obtiene el Prefijo del Código de Planta
								$correlativo_prefijo = "";

								$q_prefijo =
									"SELECT " .
									($row_detalle["ID_MODALIDADENVIO"] == 5
										? "correlativo_prefijo_comercializacion_viiisac"
										: "correlativo_prefijo_comercializacion") .
									" AS correlativo_prefijo_comercializacion
																						FROM tbconfig_plantas
																					 WHERE Id = " .
									$id_planta;

								if (
									$res_prefijo = mysqli_query(
										$enlace,
										$q_prefijo
									)
								) {
									if (mysqli_num_rows($res_prefijo) > 0) {
										while (
											$row_prefijo = mysqli_fetch_array(
												$res_prefijo
											)
										) {
											$correlativo_prefijo =
												$row_prefijo[
													"correlativo_prefijo_comercializacion"
												];
										}
									}
								}

								// 2. Obtiene el ultimo correlativo de Comercialización de la Programación anterior
								$ultimo_codigo = 0;

								$q_ultimo =
									"SELECT MAX(D.codigo_despacho_comercializacion) AS ULTIMO_CODIGO
																					 FROM despachos_segundotramo_programacion_detalle D
																					WHERE D.id_programacion = (SELECT D_x.id_programacion
																																			 FROM despachos_segundotramo_programacion_detalle D_x
																																			WHERE D_x.id_planta = " .
									$id_planta .
									"
																																				AND D_x.id_programacion < " .
									$id_programacion .
									"
																																				AND codigo_despacho_comercializacion LIKE '" .
									($row_detalle["ID_MODALIDADENVIO"] == 5
										? "CVIII"
										: "CAUM") .
									"%'
																																		 ORDER BY D_x.id_programacion DESC
																																		 LIMIT 1)";

								if (
									$res_ultimo = mysqli_query(
										$enlace,
										$q_ultimo
									)
								) {
									if (mysqli_num_rows($res_ultimo) > 0) {
										while (
											$row_ultimo = mysqli_fetch_array(
												$res_ultimo
											)
										) {
											$ultimo_codigo =
												$row_ultimo["ULTIMO_CODIGO"];
											// $ultimo_codigo = substr($ultimo_codigo, strpos($ultimo_codigo, 'M') + 1);
											$ultimo_codigo = str_replace(
												"CAUM",
												"",
												$ultimo_codigo
											);
											$ultimo_codigo = str_replace(
												"CVIII",
												"",
												$ultimo_codigo
											);
										}
									}
								}

								$new_codigo = intval($ultimo_codigo) + 1;

								if ($is_addlote == 1) {
									$new_codigo++;

									$correlativo_comercializacion =
										$correlativo_prefijo .
										str_pad(
											$new_codigo,
											4,
											"0",
											STR_PAD_LEFT
										);
								}

								$correlativo_comercializacion =
									$correlativo_prefijo .
									str_pad($new_codigo, 4, "0", STR_PAD_LEFT);

								if ($row_detalle["ID_MODALIDADENVIO"] == 5) {
									$nuevocorrelativo_viii = 1;
								}
							} else {
								if ($row_detalle["ID_MODALIDADENVIO"] != 5) {
									$correlativo_comercializacion =
										$row_detalle[
											"codigo_despacho_comercializacion"
										];
								}
							}
						}

						// Asigna el Correlativo
						$q_update =
							"UPDATE despachos_segundotramo_programacion_detalle SET";
						$q_update .=
							"   codigo_despacho_comercializacion = '" .
							$correlativo_comercializacion .
							"'";
						$q_update .= " WHERE Id = " . $row_detalle["Id"];

						if ($res_update = mysqli_query($enlace, $q_update)) {
						}

						// Inserta el correlativo en la tabla de correlativos de Comercialización
						if ($is_newcodigo == 1) {
							// Elimina los Correlativos que puedan existir en la tabla, menos los creados en balanza
							$q_delete =
								"DELETE FROM correlativo_despacho_comercializacion
																			WHERE id_programacion = " .
								$id_programacion .
								"
																				AND id_modalidadenvio = " .
								$row_detalle["ID_MODALIDADENVIO"];

							if (
								$res_delete = mysqli_query($enlace, $q_delete)
							) {
							}

							// Inserta el Nuevo Código
							$q_insert =
								"INSERT INTO correlativo_despacho_comercializacion (id_programacion, id_planta, id_modalidadenvio, correlativo, codigo, fechahora_registro, usuario_registro) VALUES (";
							$q_insert .= $id_programacion . ", ";
							$q_insert .= $id_planta . ", ";
							$q_insert .=
								$row_detalle["ID_MODALIDADENVIO"] . ", ";
							$q_insert .= $new_codigo . ", ";
							$q_insert .=
								"'" . $correlativo_comercializacion . "', ";
							$q_insert .= "'" . $fecha_registro . "', ";
							$q_insert .= "'" . $usuario_registro . "')";

							if (
								$res_insert = mysqli_query($enlace, $q_insert)
							) {
							}
						}
					}
				}
			}
		}
	}
}

// Función para Obtener la diferencia de horas
function f_GetDiferenciaHoras($fecha_inicio, $fecha_fin)
{
	// Crear objetos DateTime para las fechas de inicio y fin
	$inicio = new DateTime($fecha_inicio);
	$fin = new DateTime($fecha_fin);

	// Calcular la diferencia entre las fechas
	$diferencia = $inicio->diff($fin);

	// Obtener la diferencia en horas
	$horas = $diferencia->h;
	$horas += $diferencia->days * 24;

	// Si la diferencia también incluye minutos, sumar fracción de hora
	if ($diferencia->i > 0) {
		$horas += $diferencia->i / 60;
	}

	return number_format($horas, 2, ".", "");
}

// Permite obtener el total de toneladas distribuídas como complemento de la Programación del Segundo Tramo
function f_GetTonelajeDistribuidoComplementos(
	$enlace,
	$id_distribucionlote_padre
) {
	$total_tonelaje = 0;

	$q_tonelaje =
		"SELECT SUM(peso_distribuido) AS TONELADAS
											 FROM despachos_segundotramo_distribucion_lotes
											WHERE is_complemento_de = " . $id_distribucionlote_padre;

	if ($res_tonelaje = mysqli_query($enlace, $q_tonelaje)) {
		if (mysqli_num_rows($res_tonelaje) > 0) {
			while ($row_tonelaje = mysqli_fetch_array($res_tonelaje)) {
				$total_tonelaje += $row_tonelaje["TONELADAS"];
			}
		}
	}

	return $total_tonelaje;
}

// Permite Verificar y Actualizar el estado de lotes a "Despachado"
function f_UpdateEstadoDespachado($enlace, $id_controlIngresoVehiculo)
{
	// 1. Obtiene Id de Unidad y fecha de ingreso a planta del Ingreso de Vigilancia
	$id_unidadtransporte = 0;
	$fecha_ingresoplanta = "";

	$q_datos =
		"SELECT U.id_transporte,
													 CI.dFechaIngreso
											FROM controlingresovehiculo CI
													 INNER JOIN transporte U ON CI.placa = U.cplaca
										 WHERE CI.id_controlIngresoVehiculo = " . $id_controlIngresoVehiculo;

	if ($res_datos = mysqli_query($enlace, $q_datos)) {
		if (mysqli_num_rows($res_datos) > 0) {
			while ($row_datos = mysqli_fetch_array($res_datos)) {
				$id_unidadtransporte = $row_datos["id_transporte"];
				$fecha_ingresoplanta = $row_datos["dFechaIngreso"];
			}
		}
	}

	// 2. Identifica los lotes de esa Unidad en la Programación de Despachos
	$programacion_codlote = "";

	$q_datos2 =
		"SELECT DISTINCT
														DL.cod_lote
											 FROM despachos_segundotramo_distribucion_unidades U
														INNER JOIN despachos_segundotramo_programacion P ON U.id_programacion = P.Id
														INNER JOIN despachos_segundotramo_distribucion_lotes DL ON U.Id = DL.id_distribucionunidad
											WHERE U.id_unidad = " .
		$id_unidadtransporte .
		"
												AND '" .
		$fecha_ingresoplanta .
		"' BETWEEN U.fecha_ingresoplanta AND P.fechaestimada_despacho";

	if ($res_datos2 = mysqli_query($enlace, $q_datos2)) {
		if (mysqli_num_rows($res_datos2) > 0) {
			while ($row_datos2 = mysqli_fetch_array($res_datos2)) {
				$programacion_codlote = $row_datos2["cod_lote"];

				// 3. Obtiene la Unidad asignada de cada Lote de la Unidad Principal.
				//		Si no tuviera partes adicionales, se debe actualizar el registro a "Despachado".
				$is_despachado = 1;

				$q_datos3 =
					"SELECT id_distribucionunidad
															FROM despachos_segundotramo_distribucion_lotes
														 WHERE cod_lote = '" .
					$programacion_codlote .
					"'";

				if ($res_datos3 = mysqli_query($enlace, $q_datos3)) {
					if (mysqli_num_rows($res_datos3) > 0) {
						while ($row_datos3 = mysqli_fetch_array($res_datos3)) {
							$id_distribucionunidad =
								$row_datos3["id_distribucionunidad"];

							// 4. Obtiene los datos de la unidad asociada a la parte del Lote a inspeccionar
							$q_datos4 =
								"SELECT T.cplaca,
																					 U.fecha_ingresoplanta,
																					 P.fechaestimada_despacho
																			FROM despachos_segundotramo_distribucion_unidades U
																					 INNER JOIN transporte T ON U.id_unidad = T.id_transporte
																					 INNER JOIN despachos_segundotramo_programacion P ON U.id_programacion = P.Id
																		 WHERE U.Id = " . $id_distribucionunidad;

							if (
								$res_datos4 = mysqli_query($enlace, $q_datos4)
							) {
								if (mysqli_num_rows($res_datos4) > 0) {
									while (
										$row_datos4 = mysqli_fetch_array(
											$res_datos4
										)
									) {
										$placa = $row_datos4["cplaca"];
										$fecha_ingresoplanta =
											$row_datos4["fecha_ingresoplanta"];
										$fecha_estimadadespacho =
											$row_datos4[
												"fechaestimada_despacho"
											];

										// 5. Finalmente, inspecciona si la unidad de la parte del lote también tiene salida
										$q_datos5 =
											"SELECT fechahora_salida
																							 FROM controlingresovehiculo
																							WHERE placa = '" .
											$placa .
											"'
																								AND dFechaIngreso BETWEEN '" .
											$fecha_ingresoplanta .
											"' AND '" .
											$fecha_estimadadespacho .
											"'";

										if (
											$res_datos5 = mysqli_query(
												$enlace,
												$q_datos5
											)
										) {
											if (
												mysqli_num_rows($res_datos5) > 0
											) {
												while (
													$row_datos5 = mysqli_fetch_array(
														$res_datos5
													)
												) {
													if (
														strlen(
															$row_datos5[
																"fechahora_salida"
															]
														) == 0
													) {
														$is_despachado = 0;
													}
												}
											}
										}
									}
								}
							}
						}
					}
				}

				// 6. Actualiza el Estado de cada lote
				if ($is_despachado == 1) {
					$q_update =
						"UPDATE despachos_primertramo_validaciondatos SET";
					$q_update .= "  despacho_id_estadolote = 8";
					$q_update .=
						" WHERE lote_cod_lote = '" .
						$programacion_codlote .
						"'";

					if ($res_datos = mysqli_query($enlace, $q_update)) {
					}
				}
			}
		}
	}
}

// Genera el html de Muestreos de Operaciones por Planta y Lote
function g_GetOperacionesMuestreosxLote(
	$enlace,
	$item_planta,
	$pos_row,
	$cod_lote,
	$is_gestioncomercial
) {
	$html = "";
	$d = 1;

	$q_datos =
		"SELECT Id,
												 fecha_muestreo,
												 numero_muestreo,
												 observacion
