									 WHERE item_planta = " .
		$item_planta .
		"
										 AND cod_lote = '" .
		$cod_lote .
		"'
									ORDER BY fecha_muestreo";

	if ($res_datos = mysqli_query($enlace, $q_datos)) {
		if (mysqli_num_rows($res_datos) > 0) {
			while ($row_datos = mysqli_fetch_array($res_datos)) {
				$html .=
					'<div class="d-flex" style="padding: 5px; border: solid; border-width: 1px; border-color: #E6E9ED; border-radius: 7px; margin-bottom: 3px; background-color: #C7FFED;">';
				$html .= '	<div class="d-flex">';
				$html .= '		<table style="width: 100%">';
				$html .= '			<tr style="font-size: 12px;">';
				$html .=
					'				<td rowspan="2" style="border-right: solid; border-right-width: 1px; border-right-color: #D9D9D9; padding-right: 5px; border-top-left-radius: 5px; border-bottom-left-radius: 5px; width: 15px; background-color: #FFF587;">';
				$html .= "					" . $d . ". ";
				$html .= "				</td>";

				if ($is_gestioncomercial != 1) {
					$html .=
						'				<td rowspan="2" style="padding-right: 5px; border-top-right-radius: 5px; border-bottom-right-radius: 5px; width: 15px; background-color: #FFF587;">';
					$html .=
						'					<label style="border: solid; border-width: 1px; border-color: #D9D9D9; border-radius: 7px; padding-top: 3px; padding-bottom: 3px; padding-left: 4px; padding-right: 4px; background-color: #F29F05; color: #ffffff; cursor: pointer;" onclick="f_AddMuestreo(' .
						$item_planta .
						", " .
						$pos_row .
						", 1, " .
						$row_datos["Id"] .
						", '" .
						$row_datos["fecha_muestreo"] .
						"', " .
						$row_datos["numero_muestreo"] .
						", '" .
						$row_datos["observacion"] .
						"'" .
						');">';
					$html .= '      			<i class="bi bi-pencil-square"></i>';
					$html .= "      		</label><br>";
					$html .=
						'					<label style="border: solid; border-width: 1px; border-color: #D9D9D9; border-radius: 7px; padding-left: 6px; padding-right: 6px; padding-bottom: 1px; background-color: #FF5F5D; color: #ffffff; font-weight: bold; cursor: pointer; text-align: center; height: 20px;" onclick="f_EliminarMuestreo(' .
						$row_datos["Id"] .
						", " .
						$item_planta .
						", " .
						$pos_row .
						');">X</label>';
					$html .= "				</td>";
				}

				$html .=
					'				<td style="border-right: solid; border-right-width: 1px; border-right-color: #D9D9D9; padding-right: 5px;">';
				$html .=
					'					Fecha: <label style="font-weight: bold;">' .
					$row_datos["fecha_muestreo"] .
					"</label>";
				$html .= "				</td>";

				$html .= '				<td style="padding-left: 5px;">';
				$html .=
					'					N°: <label style="font-weight: bold;">' .
					$row_datos["numero_muestreo"] .
					"</label>";
				$html .= "				</td>";
				$html .= "			</tr>";

				$html .= '			<tr style="font-size: 12px;">';
				$html .= '				<td colspan="2">';

				if (strlen($row_datos["observacion"]) > 0) {
					$html .=
						'					Obs: <label style="font-weight: bold;">' .
						$row_datos["observacion"] .
						"</label>";
				}

				$html .= "				</td>";
				$html .= "			</tr>";
				$html .= "		</table>";
				$html .= "	</div>";
				$html .= "</div>";

				$d++;
			}
		}
	}

	return $html;
}

// Obtiene la Fecha y Hora de Despacho Real
function f_GetFechaHoraDespachoReal($enlace, $lote)
{
	$fecha_despacho = "";

	$q_datos =
		"SELECT CI.fechahora_salida
										FROM despachos_segundotramo_programacion_detalle PD
												 INNER JOIN despachos_segundotramo_programacion P ON PD.id_programacion = P.Id
												 INNER JOIN despachos_segundotramo_distribucion_unidades U ON P.Id = U.id_programacion
												 INNER JOIN despachos_segundotramo_distribucion_lotes DL ON U.Id = DL.id_distribucionunidad
													 AND PD.cod_lote = DL.cod_lote
												 INNER JOIN transporte UN ON U.id_unidad = UN.id_transporte
												 INNER JOIN controlingresovehiculo CI ON CI.placa = UN.cplaca
													 AND CI.dFechaIngreso BETWEEN U.fecha_ingresoplanta AND P.fechaestimada_despacho
									 WHERE PD.cod_lote = '" .
		$lote .
		"'";

	if ($res_datos = mysqli_query($enlace, $q_datos)) {
		if (mysqli_num_rows($res_datos) > 0) {
			while ($row_datos = mysqli_fetch_array($res_datos)) {
				$fecha_despacho = $row_datos["fechahora_salida"];
			}
		}
	}

	return $fecha_despacho;
}

// Migra Lotes al Consolidado de Cierre Contable
function f_MigrarLotes_CierreContable(
	$enlace,
	$id_tipoingreso,
	$arr_idregistros,
	$g_fecha,
	$usuario_registro
) {
	$l = 0;
	$arr_idregistros = explode(", ", $arr_idregistros);
	$idregistro_new = 0;

	while ($l < count($arr_idregistros)) {
		$q_datos =
			"INSERT INTO consolidado_lotes_cierrecontable(id_registro, cod_lote, lote_item, id_tipoingreso, fecha_ingresobalanza, placa1, placa2, numguia_remitente, numguia_transportista, transportista_ruc, transportista_razonsocial, id_tipovehiculo, conductor_licencia, conductor_nombres, id_tipocarga, num_bigbag, id_zonaorigen, proveedorminero_ruc, proveedorminero_razonsocial, encargadomuestra_nombres, remitente_ruc, remitente_razonsocial, id_producto, id_tipomineral, observacion, fecha_pesoinicial, fecha_pesofinal, peso_bruto, peso_tara, peso_neto, fechahora_registro, fechahora_usuario) ";

		if ($id_tipoingreso == 1) {
			$q_datos .=
				"SELECT V.Id,
															V.lote_cod_lote,
															V.lote_ticket_orden,
															" .
				$id_tipoingreso .
				",
															DATE(V.lote_pesoinicial_fechahoraregistro) AS FECHA_INGRESOBALANZA,
															V.balanza_placa,
															V.balanza_placa2,
															CONCAT(V.guiaremitente_serie, '-', V.guiaremitente_numero) AS GUIA_REMITENTE,
															CONCAT(V.guiatransportista_serie, '-', V.guiatransportista_numero) AS GUIA_TRANSPORTISTA,
															CL_T.documento AS TRANSPORTISTA_RUC,
															UPPER(CL_T.razon_social) AS TRANSPORTISTA_RAZONSOCIAL,
															T.id_tipovehiculo,
															CD.licencia_conducir AS CONDUCTOR_LICENCIA,
															CD.nombres AS CONDUCTOR_NOMBRES,
															V.lote_id_tipocarga,
															NULL,
															V.lote_id_zonaorigen,
															CL.documento AS PROVEEDORMINERO_RUC,
															UPPER(CL.razon_social) AS PROVEEDORMINERO_RAZONSOCIAL,
															UPPER(EM.nombres) AS ENCARGADO_MUESTRA,
															NULL,
															NULL,
															V.lote_id_producto,
															V.lote_id_tipomineral,
															V.despacho_observacion,
															V.lote_pesoinicial_fechahoraregistro,
															V.lote_pesofinal_fechahoraregistro,
															V.lote_peso_inicial AS lote_peso_bruto,
															V.lote_peso_final AS lote_peso_tara,
															V.lote_peso_neto,
															'" .
				$g_fecha .
				"',
															'" .
				$usuario_registro .
				"'
												 FROM despachos_primertramo_validaciondatos V
															LEFT JOIN transporte T ON V.balanza_placa = T.cplaca
															INNER JOIN tb_clientes CL_T ON T.id_Transportista = CL_T.Id
															INNER JOIN tbconfig_conductores CD ON V.guias_idchofer = CD.Id
															LEFT JOIN tb_clientes CL ON V.lote_id_proveedorminero = CL.Id
															LEFT JOIN tbconfig_encargadosmuestra EM ON V.lote_id_encargadomuestra = EM.Id
												WHERE V.Id = " .
				$arr_idregistros[$l];
		} else {
			$q_datos .=
				"SELECT DISTINCT
															DL.Id,
															PD.cod_lote,
															/*DL.num_parte,*/

															(CASE WHEN (SELECT COUNT(DL_x.Id)
																						FROM despachos_segundotramo_distribucion_lotes DL_x
																					 WHERE DL_x.is_complemento_de = DL.Id) > 0
																 THEN 1
															 ELSE CASE WHEN DL.is_complemento = 1
																			THEN (SELECT 1 + (COUNT(CC_x.Id) + 1)
																							FROM consolidado_lotes_cierrecontable CC_x
																						 WHERE CC_x.cod_lote = PD.cod_lote
																							 AND CC_x.id_tipoingreso = 2
																							 AND lote_item <> 1)
																		ELSE DL.num_parte END END),

															" .
				$id_tipoingreso .
				",
															/*DATE(DL.peso_bruto_fechahoraregistro) AS FECHA_INGRESOBALANZA,*/
															DL.guias_fecha,
															DL.guias_placa1 AS PLACA1,
															DL.guias_placa2 AS PLACA2,
															CONCAT(DL.guiaremitente_serie, '-', DL.guiaremitente_numero) AS GUIA_REMITENTE,
															CONCAT(DL.guiatransportista_serie, '-', DL.guiatransportista_numero) AS GUIA_TRANSPORTISTA,
															TR.documento AS TRANSPORTISTA_RUC,
															TR.razon_social AS TRANSPORTISTA_RAZONSOCIAL,
															UN.id_tipovehiculo,
															CH.licencia_conducir AS CONDUCTOR_DNI,
															CH.nombres AS CONDUCTOR_NOMBRES,
															DL.id_tipocarga,
															DL.num_bigbag,
															24,
															NULL,
															NULL,
															NULL,
															RE.ruc AS REMITENTE_RUC,
															RE.razon_social AS REMITENTE_RAZONSOCIAL,
															V.lote_id_producto,
															V.lote_id_tipomineral,
															DL.observacion,
															/*DL.peso_bruto_fechahoraregistro,
															DL.peso_tara_fechahoraregistro,*/
															DL.guias_fecha,
															DL.guias_fecha,
															DL.peso_bruto,
															DL.peso_tara,
															DL.peso_neto,
															'" .
				$g_fecha .
				"',
															'" .
				$usuario_registro .
				"'
												 FROM despachos_segundotramo_programacion_detalle PD
															INNER JOIN despachos_segundotramo_programacion P ON PD.id_programacion = P.Id
															INNER JOIN despachos_segundotramo_distribucion_unidades U ON P.Id = U.id_programacion
															INNER JOIN despachos_segundotramo_distribucion_lotes DL ON U.Id = DL.id_distribucionunidad
															AND PD.cod_lote = DL.cod_lote
															INNER JOIN transporte UN ON U.id_unidad = UN.id_transporte
															LEFT JOIN transporte UN2 ON U.id_unidad2 = UN2.id_transporte
															INNER JOIN tb_clientes TR ON UN.id_Transportista = TR.Id
															INNER JOIN tbconfig_plantas PL ON PD.id_planta = PL.Id
															LEFT JOIN tbconfig_modalidadenvio ME ON PD.id_modalidadenvio = ME.Id
															INNER JOIN despachos_primertramo_validaciondatos V ON PD.cod_lote = V.lote_cod_lote
															INNER JOIN tbconfig_conductores CH ON DL.guias_idchofer = CH.Id
															INNER JOIN tbconfig_remitentessegundotramo RE ON DL.guias_iddestino = RE.id_destino
															AND DL.guias_idmodalidadenvio = RE.id_modalidadenvio
												WHERE DL.Id = " .
				$arr_idregistros[$l];
		}

		if ($res_datos = mysqli_query($enlace, $q_datos)) {
			$idregistro_new = mysqli_insert_id($enlace);

			// Genera los Número de Ticket del Cierre Contable (Primer y Segundo Tramo)
			// 1. Obtiene le Fecha del nuevo registro
			$fecha_x = "";

			$q_fecha =
				"SELECT fecha_ingresobalanza
														FROM consolidado_lotes_cierrecontable
													 WHERE Id = " . $idregistro_new;

			if ($res_fecha = mysqli_query($enlace, $q_fecha)) {
				if (mysqli_num_rows($res_fecha) > 0) {
					while ($row_fecha = mysqli_fetch_array($res_fecha)) {
						$fecha_x = $row_fecha["fecha_ingresobalanza"];
					}
				}
			}

			// 2. Obtiene el N° de Ticket asignado a los registros anteriores
			$c = 1;
			$correlativo_x = 0; // Para identificar el Correlativo de cada registro
			$continuar = 1; // Ayuda a saber cuando continuar

			$q_numticket =
				"SELECT num_ticketbalanza
																FROM consolidado_lotes_cierrecontable
															 WHERE fecha_ingresobalanza = '" .
				$fecha_x .
				"'
																 AND Id <> " .
				$idregistro_new .
				"
															ORDER BY num_ticketbalanza";

			if ($res_numticket = mysqli_query($enlace, $q_numticket)) {
				if (mysqli_num_rows($res_numticket) > 0) {
					while (
						$row_numticket = mysqli_fetch_array($res_numticket)
					) {
						// 3. Identifica el Correlativo de cada registro

						$correlativo_x = explode(
							"-",
							$row_numticket["num_ticketbalanza"]
						)[1];
						$correlativo_x = intval($correlativo_x);

						// 4. Crea un Array para buscar el Nuevo Correlativo
						while ($c < 10000) {
							if ($c == $correlativo_x) {
								$c++;

								break;
							}

							if ($c != $correlativo_x) {
								// Setea Prefijo
								$prefijo = explode("-", $fecha_x);
								$prefijo =
									$prefijo[2] .
									$prefijo[1] .
									substr($prefijo[0], 2);

								// Setea Correlativo
								$correlativo =
									$prefijo .
									"-" .
									str_pad($c, 3, "0", STR_PAD_LEFT);

								// Actualiza Correlativo
								$q_update =
									"UPDATE consolidado_lotes_cierrecontable SET";
								$q_update .=
									"   num_ticketbalanza = '" .
									$correlativo .
									"'";
								$q_update .= " WHERE Id = " . $idregistro_new;

								if (
									$q_update = mysqli_query($enlace, $q_update)
								) {
									$continuar = 0;

									break 2;
								}
							}

							$c++;
						}
					}
				}
			}

			// Asigna el Correlativo
			if ($continuar == 1) {
				// Setea Prefijo
				$prefijo = explode("-", $fecha_x);
				$prefijo = $prefijo[2] . $prefijo[1] . substr($prefijo[0], 2);

				// Setea Correlativo
				$correlativo =
					$prefijo . "-" . str_pad($c, 3, "0", STR_PAD_LEFT);

				// Actualiza Correlativo
				$q_update = "UPDATE consolidado_lotes_cierrecontable SET";
				$q_update .= "   num_ticketbalanza = '" . $correlativo . "'";
				$q_update .= " WHERE Id = " . $idregistro_new;

				if ($q_update = mysqli_query($enlace, $q_update)) {
				}
			}
		}

		$l++;
	}
}

