// Generar Códigos Internos de L.Q.
function f_GetCodigosInternos_LQ(
	$id_recepcion,
	$g_fecha,
	$g_anho,
	$g_mes,
	$g_dia,
	$usuario_registro
) {
	// Definiendo conexión para la función
	$enlace_f = mysqli_connect(
		"192.99.154.9",
		"root",
		"yellowblue1968",
		"aumbd",
		"3340"
	);

	// 1. Obtiene el último correlativo
	$correlativo = "0";

	$q_newcodigo =
		"SELECT IFNULL(MAX(correlativo), 0) AS CORRELATIVO
													FROM recepcion_codigosinternos_lq
												 WHERE anho = " .
		$g_anho .
		"
													 AND mes = " .
		$g_mes .
		"
													 /*AND dia = " .
		$g_dia .
		"*/";

	if ($res_newcodigo = mysqli_query($enlace_f, $q_newcodigo)) {
		if (mysqli_num_rows($res_newcodigo) > 0) {
			while ($row_newcodigo = mysqli_fetch_array($res_newcodigo)) {
				$correlativo = $row_newcodigo["CORRELATIVO"];
			}
		}
	}

	// 2. Asigna los correlativos a los detalles de la recepción (muestras)
	$cod_interno = 0;
	$correlativo++;

	$q_muestras =
		"SELECT Id
												 FROM recepcion_ensayos_detalle
												WHERE id_cabecera = " .
		$id_recepcion .
		"
											 ORDER BY Id";

	if ($res_muestras = mysqli_query($enlace_f, $q_muestras)) {
		if (mysqli_num_rows($res_muestras) > 0) {
			while ($row_muestras = mysqli_fetch_array($res_muestras)) {
				$cod_interno = $row_muestras["Id"];

				// 3. Inserta el registro del código interno en la tabla de Códigos Internos
				$q_insertCI = "INSERT INTO recepcion_codigosinternos_lq (cod_recepcion, cod_detalle, anho, mes, dia, correlativo,
																																				 fechahora_registro, usuario_registro) VALUES (";
				$q_insertCI .= $id_recepcion . ", ";
				$q_insertCI .= $row_muestras["Id"] . ", ";
				$q_insertCI .= $g_anho . ", ";
				$q_insertCI .= $g_mes . ", ";
				$q_insertCI .= $g_dia . ", ";
				$q_insertCI .= $correlativo . ", ";
				$q_insertCI .= "'" . $g_fecha . "', ";
				$q_insertCI .= "'" . $usuario_registro . "')";

				if ($res_insertCI = mysqli_query($enlace_f, $q_insertCI)) {
					$id_ci = mysqli_insert_id($enlace_f);

					// 4. Actualiza el Código Interno en cada muestra
					$q_updateCI =
						"UPDATE recepcion_ensayos_detalle SET
																					id_codinterno = " .
						$id_ci .
						",
																					cod_interno = '" .
						str_pad($g_dia, 2, "0", STR_PAD_LEFT) .
						str_pad($g_mes, 2, "0", STR_PAD_LEFT) .
						substr($g_anho, 2, 2) .
						"-" .
						str_pad($correlativo, 4, "0", STR_PAD_LEFT) .
						"'
																		WHERE Id = " .
						$row_muestras["Id"];

					if ($res_updateCI = mysqli_query($enlace_f, $q_updateCI)) {
					}
				}

				$correlativo++;
			}
		}
	}
}

// Verifica si la muestra tiene análisis de Humedad
function f_ValidaTieneHumedad($id_ensayosdetalle)
{
	$tiene_h2o = 0;

	// Definiendo conexión para la función
	$enlace_f = mysqli_connect(
		"192.99.154.9",
		"root",
		"yellowblue1968",
		"aumbd",
		"3340"
	);

	// 1. Obtiene análisis de Precios Generales
	$q_analisis =
		"SELECT EA.is_humedad
												 FROM recepcion_ensayos_analisis REA
															INNER JOIN tb_ensayos_analisisclasificaciones_detalle ACD ON REA.cod_analisis = ACD.Id
															INNER JOIN tb_ensayos_analisisclasificaciones C ON ACD.cod_clasificacion = C.Id
															INNER JOIN tb_ensayos_analisis EA ON ACD.cod_analisis = EA.Id
												WHERE REA.id_detalle IN (" .
		$id_ensayosdetalle .
		")
													AND is_paquete = 0
													AND is_paquetecliente = 0
											 ORDER BY EA.orden";

	if ($res_analisis = mysqli_query($enlace_f, $q_analisis)) {
		if (mysqli_num_rows($res_analisis) > 0) {
			while ($row_analisis = mysqli_fetch_array($res_analisis)) {
				if ($row_analisis["is_humedad"] == 1) {
					$tiene_h2o = 1;

					break;
				}
			}
		}
	}

	// 2. Obtiene análisis de Paquetes Generales
	$q_paquetes =
		"SELECT REA.cod_analisis
												 FROM recepcion_ensayos_analisis REA
															INNER JOIN tb_ensayos_analisisclasificaciones_paquetes P ON REA.cod_analisis = P.Id
															INNER JOIN tb_ensayos_analisisclasificaciones C ON P.cod_clasificacion = C.Id
												WHERE REA.id_detalle IN (" .
		$id_ensayosdetalle .
		")
													AND REA.is_paquete = 1";

	if ($res_paquetes = mysqli_query($enlace_f, $q_paquetes)) {
		if (mysqli_num_rows($res_paquetes) > 0) {
			while ($row_paquetes = mysqli_fetch_array($res_paquetes)) {
				$q_analisispaquete =
					"SELECT A.is_humedad
																		 FROM tb_ensayos_analisisclasificaciones_paquetes_detalle D
																					INNER JOIN tb_ensayos_analisis A ON D.cod_analisis = A.Id
																		WHERE D.cod_paquete = " . $row_paquetes["cod_analisis"];

				if (
					$res_analisispaquete = mysqli_query(
						$enlace_f,
						$q_analisispaquete
					)
				) {
					if (mysqli_num_rows($res_analisispaquete) > 0) {
						while (
							$row_analisispaquete = mysqli_fetch_array(
								$res_analisispaquete
							)
						) {
							if ($row_analisispaquete["is_humedad"] == 1) {
								$tiene_h2o = 1;

								break;
							}
						}
					}
				}
			}
		}
	}

	// 3. Obtiene análisis de Paquetes de Clientes
	$q_paquetes =
		"SELECT REA.cod_analisis
												 FROM recepcion_ensayos_analisis REA
															INNER JOIN tb_ensayos_analisisclasificaciones_paquetesclientes P ON REA.cod_analisis = P.Id
															INNER JOIN tb_ensayos_analisisclasificaciones C ON P.cod_clasificacion = C.Id
												WHERE REA.id_detalle IN (" .
		$id_ensayosdetalle .
		")
													AND REA.is_paquetecliente = 1";

	if ($res_paquetes = mysqli_query($enlace_f, $q_paquetes)) {
		if (mysqli_num_rows($res_paquetes) > 0) {
			while ($row_paquetes = mysqli_fetch_array($res_paquetes)) {
				$q_analisispaquete =
					"SELECT A.is_humedad
																		 FROM tb_ensayos_analisisclasificaciones_paquetesclientes_detalle D
																					INNER JOIN tb_ensayos_analisis A ON D.cod_analisis = A.Id
																		WHERE D.cod_paquete = " . $row_paquetes["cod_analisis"];

				if (
					$res_analisispaquete = mysqli_query(
						$enlace_f,
						$q_analisispaquete
					)
				) {
					if (mysqli_num_rows($res_analisispaquete) > 0) {
						while (
							$row_analisispaquete = mysqli_fetch_array(
								$res_analisispaquete
							)
						) {
							if ($row_analisispaquete["is_humedad"] == 1) {
								$tiene_h2o = 1;

								break;
							}
						}
					}
				}
			}
		}
	}

	return $tiene_h2o;
}

// Criterio de aceptación para Análisis de Humedad
function f_AnalisisHumedad_CriterioAceptacion($id_cabecera)
{
	// Definiendo conexión para la función
	$enlace_f = mysqli_connect(
		"192.99.154.9",
		"root",
		"yellowblue1968",
		"aumbd",
		"3340"
	);

	// Obtiene los porcentajes
	$c = 1;
	$porc_item1 = 999.999;
	$porc_item2 = 999.999;

	$q_datos =
		"SELECT IFNULL(porc_humedad, 999.999) AS PORC
											FROM analisislq_humedad_analisis
										 WHERE id_cabecera = " . $id_cabecera;

	if ($res_datos = mysqli_query($enlace_f, $q_datos)) {
		if (mysqli_num_rows($res_datos) > 0) {
			while ($row_datos = mysqli_fetch_array($res_datos)) {
				if ($c == 1) {
					$porc_item1 = $row_datos["PORC"];
				} else {
					$porc_item2 = $row_datos["PORC"];
				}

				$c++;
			}
		}
	}

	// Valida la existencia del Porcentaje
	$e = 0;

	if ($porc_item1 != 999.999) {
		$e++;
	}

	if ($porc_item2 != 999.999) {
		$e++;
	}

	// Determina el criterio de aceptación
	if ($e < 2) {
		return "";
	} else {
		$is_reanalisis = 0;
		$bgcolor = "#93D94E";

		$_prom = round(($porc_item1 + $porc_item2) / 2, 2);
		$_diff = abs($porc_item1 - $porc_item2);

		if ($_prom >= 3 && $_diff >= 0.25) {
			$is_reanalisis = 1;
		}

		if ($_prom < 3 && $_diff >= 0.22) {
			$is_reanalisis = 1;
		}

		if ($is_reanalisis == 1) {
			$bgcolor = "#FF5F5D";
		}

		return $bgcolor;
	}
}

