		"3340"
	);

	// 1. Obtiene análisis de Precios Generales
	$q_analisis =
		"SELECT EA.is_aas
												 FROM recepcion_ensayos_analisis REA
															INNER JOIN tb_ensayos_analisisclasificaciones_detalle ACD ON REA.cod_analisis = ACD.Id
															INNER JOIN tb_ensayos_analisisclasificaciones C ON ACD.cod_clasificacion = C.Id
															INNER JOIN tb_ensayos_analisis EA ON ACD.cod_analisis = EA.Id
												WHERE REA.id_detalle IN (" .
		$id_ensayosdetalle .
		")
													AND is_paquete = 0
													AND is_paquetecliente = 0
											 ORDER BY EA.orden";

	if ($res_analisis = mysqli_query($enlace_f, $q_analisis)) {
		if (mysqli_num_rows($res_analisis) > 0) {
			while ($row_analisis = mysqli_fetch_array($res_analisis)) {
				if ($row_analisis["is_aas"] == 1) {
					$tiene_aas = 1;

					break;
				}
			}
		}
	}

	// 2. Obtiene análisis de Paquetes Generales
	$q_paquetes =
		"SELECT REA.cod_analisis
												 FROM recepcion_ensayos_analisis REA
															INNER JOIN tb_ensayos_analisisclasificaciones_paquetes P ON REA.cod_analisis = P.Id
															INNER JOIN tb_ensayos_analisisclasificaciones C ON P.cod_clasificacion = C.Id
												WHERE REA.id_detalle IN (" .
		$id_ensayosdetalle .
		")
													AND REA.is_paquete = 1";

	if ($res_paquetes = mysqli_query($enlace_f, $q_paquetes)) {
		if (mysqli_num_rows($res_paquetes) > 0) {
			while ($row_paquetes = mysqli_fetch_array($res_paquetes)) {
				$q_analisispaquete =
					"SELECT A.is_aas
																		 FROM tb_ensayos_analisisclasificaciones_paquetes_detalle D
																					INNER JOIN tb_ensayos_analisis A ON D.cod_analisis = A.Id
																		WHERE D.cod_paquete = " . $row_paquetes["cod_analisis"];

				if (
					$res_analisispaquete = mysqli_query(
						$enlace_f,
						$q_analisispaquete
					)
				) {
					if (mysqli_num_rows($res_analisispaquete) > 0) {
						while (
							$row_analisispaquete = mysqli_fetch_array(
								$res_analisispaquete
							)
						) {
							if ($row_analisispaquete["is_aas"] == 1) {
								$tiene_aas = 1;

								break;
							}
						}
					}
				}
			}
		}
	}

	// 3. Obtiene análisis de Paquetes de Clientes
	$q_paquetes =
		"SELECT REA.cod_analisis
												 FROM recepcion_ensayos_analisis REA
															INNER JOIN tb_ensayos_analisisclasificaciones_paquetesclientes P ON REA.cod_analisis = P.Id
															INNER JOIN tb_ensayos_analisisclasificaciones C ON P.cod_clasificacion = C.Id
												WHERE REA.id_detalle IN (" .
		$id_ensayosdetalle .
		")
													AND REA.is_paquetecliente = 1";

	if ($res_paquetes = mysqli_query($enlace_f, $q_paquetes)) {
		if (mysqli_num_rows($res_paquetes) > 0) {
			while ($row_paquetes = mysqli_fetch_array($res_paquetes)) {
				$q_analisispaquete =
					"SELECT A.is_aas
																		 FROM tb_ensayos_analisisclasificaciones_paquetesclientes_detalle D
																					INNER JOIN tb_ensayos_analisis A ON D.cod_analisis = A.Id
																		WHERE D.cod_paquete = " . $row_paquetes["cod_analisis"];

				if (
					$res_analisispaquete = mysqli_query(
						$enlace_f,
						$q_analisispaquete
					)
				) {
					if (mysqli_num_rows($res_analisispaquete) > 0) {
						while (
							$row_analisispaquete = mysqli_fetch_array(
								$res_analisispaquete
							)
						) {
							if ($row_analisispaquete["is_aas"] == 1) {
								$tiene_aas = 1;

								break;
							}
						}
					}
				}
			}
		}
	}

	return $tiene_aas;
}

// Verifica si la Fecha de Entrega de Resultados cruza domingos
function f_VerificaFechaEntrega($fecha_entrega)
{
	$fecha_entrega_x = explode(" ", $fecha_entrega)[0];
	$hora_entrega_x = substr(explode(" ", $fecha_entrega)[1], 0, 5);

	$g_date_x = $g_date;

	if ($fecha_entrega > $g_date) {
		while ($g_date_x <= $fecha_entrega_x) {
			// Averigua si es domingo
			if (date("w", strtotime($g_date_x)) == 0) {
				$fecha_entrega_x = date(
					"Y-m-d",
					strtotime($fecha_entrega_x . " + 1 days")
				);

				break;
			}

			$g_date_x = date("Y-m-d", strtotime($g_date_x . " + 1 days"));
		}

		// Averigua si la fecha de entrega final también es domingo
		if (date("w", strtotime($fecha_entrega_x)) == 0) {
			$fecha_entrega_x = date(
				"Y-m-d",
				strtotime($fecha_entrega_x . " + 1 days")
			);
		}

		$fecha_entrega_x = $fecha_entrega_x . " " . $hora_entrega_x;
	}

	return $fecha_entrega_x;
}

function generateRandomString($length = 15)
{
	return substr(sha1(rand()), 0, $length);
}

// Cambiar el formato de Fecha PE (Tomado de /global/auxiliares_js.php
function f_FormatFecha($fechahora, $show_hora = 1)
{
	if (strtolower($fechahora) === "hoy") {
		return $show_hora ? date("d/m/Y H:i:s") : date("d/m/Y");
	}

	// Intentar crear la fecha desde diferentes formatos
	$fecha = DateTime::createFromFormat("Y-m-d H:i:s", $fechahora);

	// Si no tiene hora, agregar "00:00:00" por defecto
	if (!$fecha) {
		$fecha = DateTime::createFromFormat("Y-m-d", $fechahora);

		if ($fecha) {
			$fecha->setTime(0, 0, 0);
		}
	}

	if (!$fecha) {
		error_log("Formato de fecha no válido: " . $fechahora);

		return null;
	}

	return $show_hora ? $fecha->format("d/m/Y H:i:s") : $fecha->format("d/m/Y");
}

// Función principal para generar el código GEL
function f_GenerarCodigoGel(
	$enlace,
	$arr_lotes,
	$g_anho,
	$g_fecha,
	$usuario_registro
) {
	foreach ($arr_lotes as $lote) {
		$id = $lote["id"];

		// 1. Obtener la fecha de llegada
		$fecha_llegada = f_ObtenerFechaLlegada($enlace, $id);

		if (!$fecha_llegada) {
			continue;
		}

		// 2. Obtener el siguiente código GEL disponible
		$codigo_gel_x = f_ObtenerCodigoGel($enlace, $fecha_llegada);

		$codigo_gel = explode("|", $codigo_gel_x)[0];
		$correlativo = explode("|", $codigo_gel_x)[1];

		if ($codigo_gel) {
			// 3. Actualizar el registro con el nuevo código GEL
			$q_insert =
				"INSERT INTO correlativo_codigosgel (cod_anho, fecha_llegadaplanta, correlativo, codigo_gel, id_validaciondatos, fechahora_registro, usuario_registro) VALUES (";
			$q_insert .= $g_anho . ", ";
			$q_insert .= "'" . $fecha_llegada . "', ";
			$q_insert .= $correlativo . ", ";
			$q_insert .= "'" . $codigo_gel . "', ";
			$q_insert .= $id . ", ";
			$q_insert .= "'" . $g_fecha . "', ";
			$q_insert .= "'" . $usuario_registro . "')";

			if ($res_datos = mysqli_query($enlace, $q_insert)) {
				$idregistro_new = mysqli_insert_id($enlace);
			}

			// // 4. Reasignar códigos GEL a registros posteriores si no están cerrados
			//   f_ReasignarCodigosGEL($enlace, $correlativo, $idregistro_new, $g_fecha, $usuario_registro);

			// 4. Reasignar códigos GEL a registros posteriores si no están cerrados
			f_ReasignarCodigosGEL(
				$enlace,
				$fecha_llegada,
				$correlativo,
				$g_fecha,
				$usuario_registro
			);
		}
	}

	// 5. Actualizar tabla consolidada
	$q_update = "UPDATE despachos_primertramo_validaciondatos VD
														INNER JOIN correlativo_codigosgel CG ON VD.Id = CG.id_validaciondatos
												SET VD.codigo_gel = CG.codigo_gel,
														VD.codigo_gel_fechahoraregistro = IFNULL(CG.fechahora_registro_reasignado, CG.fechahora_registro),
														VD.codigo_gel_usuarioregistro = IFNULL(CG.usuario_registro_reasignado, CG.usuario_registro)";

	if ($res_update = mysqli_query($enlace, $q_update)) {
		return 1;
	}
}

// Función de utilidad para logging
function saveLog($datos)
{
	try {
		// Carpeta 'logs' en el mismo nivel que este script
		$directorio = __DIR__ . DIRECTORY_SEPARATOR . 'logs';

		// un nombre de archivo por día para no sobrescribir todo siempre
		$nombreArchivo = 'log_' . date('Y-m-d') . '.json';
		$rutaCompleta = $directorio . DIRECTORY_SEPARATOR . $nombreArchivo;

		// Crear directorio si no existe con permisos totales
		if (!is_dir($directorio)) {
			mkdir($directorio, 0777, true);
			chmod($directorio, 0777); // para Linux
		}

		// Limpieza de caracteres especiales (\r, \n, \t) ---
		$limpiar = function ($item) use (&$limpiar) {
			if (is_array($item)) {
				return array_map($limpiar, $item);
			}
			if (is_string($item)) {
				return str_replace(["\r", "\n", "\t"], ' ', $item);
			}
			return $item;
		};
		$datosLimpios = $limpiar($datos);

		// Agregamos una marca de tiempo al registro para saber cuándo ocurrió exactamente
		$registro = [
			'timestamp' => date('Y-m-d H:i:s'),
			'data' => $datosLimpios
		];

		// Si el archivo ya existe, leemos y añadimos, si no, creamos nuevo array
		$listaLogs = [];
		if (file_exists($rutaCompleta)) {
			$contenidoActual = file_get_contents($rutaCompleta);
			$listaLogs = json_decode($contenidoActual, true) ?: [];
		}

		$listaLogs[] = $registro;

		// Convertir a JSON
		// JSON_UNESCAPED_SLASHES evita las barras extra en rutas de Windows
		$jsonContenido = json_encode($listaLogs, JSON_PRETTY_PRINT | JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES);

		// Escribir y forzar permisos
		if (file_put_contents($rutaCompleta, $jsonContenido) !== false) {
			chmod($rutaCompleta, 0777);
			return true;
		}

		return false;

	} catch (Exception $e) {
		// si todo falla, enviamos al log del servidor
		// error_log("Fallo crítico en saveLog: " . $e->getMessage());
		return false;
	}
}

function f_Guia_GenerarCodigoGel(
    $enlace,
    array  $arr_lote_ids,
    string $guia_remitente,
    string $guia_fechahoraemision,
    string $planta_fechallegada,
    string $g_fecha,
    string $g_anho
): int {
    if (empty($arr_lote_ids)) return 0;

    $lote_ids_str          = implode(", ", array_map("intval", $arr_lote_ids));
    $guia_remitente_esc    = mysqli_real_escape_string($enlace, $guia_remitente);
    $guia_fechaemision_esc = mysqli_real_escape_string($enlace, $guia_fechahoraemision);

    // ----------------------------------------------------------
    // Lotes SIN código GEL dentro de los seleccionados
    // ----------------------------------------------------------
    $lotes_sin_gel = [];
    if ($rs = mysqli_query($enlace, "
        SELECT V.Id AS id_validaciondatos,
               V.lote_pesoinicial_fechahoraregistro AS fecha_llegada,
               V.guias_posicion
        FROM   despachos_primertramo_validaciondatos V
        WHERE  V.Id IN ($lote_ids_str)
          AND  V.codigo_gel IS NULL
        ORDER  BY V.guias_posicion ASC, V.Id ASC")) {
        while ($row = mysqli_fetch_assoc($rs)) $lotes_sin_gel[] = $row;
        mysqli_free_result($rs);
    }

    if (empty($lotes_sin_gel)) return 1;

    // ----------------------------------------------------------
    // Último código BJ de ESTA GUÍA
    // Ordenamos por correlativo DESC y luego por codigo_gel DESC
    // pero separamos: primero el mayor correlativo, luego dentro
    // de ese correlativo el que tenga letra más alta (o ninguna)
    // ----------------------------------------------------------
    $ultimo_codigo_guia      = null;
    $ultimo_correlativo_guia = 0;

    // Paso 1: ¿cuál es el mayor correlativo de esta guía?
    if ($rs = mysqli_query($enlace, "
        SELECT MAX(C.correlativo) AS max_corr
        FROM   despachos_primertramo_validaciondatos V
        INNER  JOIN correlativo_codigosgel C
                 ON C.id_validaciondatos = V.Id
                AND C.estado   = 'A'
                AND C.cod_anho = '$g_anho'
        WHERE  CONCAT(V.guiaremitente_serie,'-',V.guiaremitente_numero) = '$guia_remitente_esc'
          AND  V.guias_fechahoraemision = '$guia_fechaemision_esc'
          AND  V.codigo_gel IS NOT NULL")) {
        if ($row = mysqli_fetch_assoc($rs)) {
            $ultimo_correlativo_guia = intval($row["max_corr"]);
        }
        mysqli_free_result($rs);
    }

    if ($ultimo_correlativo_guia === 0) {
        // Guía nueva → correlativos nuevos sin letra
        return _asignarCodigosNuevos($enlace, $lotes_sin_gel, $g_fecha, $g_anho);
    }

    // Paso 2: dentro de ese correlativo, ¿hay alguno con letra?
    // Si hay letras, traer la última letra asignada (ORDER BY codigo_gel DESC)
    // Si no hay letras, traer el código sin letra
    $ultimo_codigo_guia      = null;
    $tiene_letra             = false;
    $ultima_letra_idx        = 0;

    if ($rs = mysqli_query($enlace, "
        SELECT C.codigo_gel
        FROM   despachos_primertramo_validaciondatos V
        INNER  JOIN correlativo_codigosgel C
                 ON C.id_validaciondatos = V.Id
                AND C.estado   = 'A'
                AND C.cod_anho = '$g_anho'
        WHERE  CONCAT(V.guiaremitente_serie,'-',V.guiaremitente_numero) = '$guia_remitente_esc'
          AND  V.guias_fechahoraemision = '$guia_fechaemision_esc'
          AND  V.codigo_gel IS NOT NULL
          AND  C.correlativo = $ultimo_correlativo_guia
        ORDER  BY V.codigo_gel DESC")) {

        // Recorremos todos y nos quedamos con el de mayor letra
        $max_letra_idx = 0;
        $codigo_sin_letra = null;

        while ($row = mysqli_fetch_assoc($rs)) {
            $cod = $row["codigo_gel"];
            if (preg_match('/([A-Z]+)$/', $cod, $m)) {
                $idx = _letraAIndice($m[1]);
                if ($idx > $max_letra_idx) {
                    $max_letra_idx   = $idx;
                    $ultimo_codigo_guia = $cod;
                    $tiene_letra     = true;
                    $ultima_letra_idx = $idx;
                }
            } else {
                $codigo_sin_letra = $cod;
            }
        }

        if (!$tiene_letra) {
            $ultimo_codigo_guia = $codigo_sin_letra;
        }

        mysqli_free_result($rs);
    }

    // ----------------------------------------------------------
    // CASO B1: Último código TIENE letra → continuar secuencia
    //          BJ-26-0009A → B   |   BJ-26-0009B → C
    // ----------------------------------------------------------
    if ($tiene_letra) {
        return _asignarCodigosConLetra(
            $enlace, $lotes_sin_gel,
            $ultimo_correlativo_guia,
            $ultima_letra_idx + 1,   // siguiente letra
            $g_fecha, $g_anho
        );
    }

    // ----------------------------------------------------------
    // CASO B2: Último código SIN letra
    //          ¿es el último correlativo global del año?
    // ----------------------------------------------------------
    $max_corr_global = 0;
    if ($rs = mysqli_query($enlace, "
        SELECT MAX(correlativo) AS max_corr
        FROM   correlativo_codigosgel
        WHERE  cod_anho = '$g_anho' AND estado = 'A'")) {
        if ($row = mysqli_fetch_assoc($rs)) $max_corr_global = intval($row["max_corr"]);
        mysqli_free_result($rs);
    }

    if ($ultimo_correlativo_guia >= $max_corr_global) {
        // B2a: ES la última guía → nuevos correlativos sin letra
        //      BJ-26-0009 → BJ-26-0010, BJ-26-0011 ...
        return _asignarCodigosNuevos($enlace, $lotes_sin_gel, $g_fecha, $g_anho);
    } else {
        // B2b: NO es la última → letras desde A
        //      BJ-26-0008 → BJ-26-0008A, BJ-26-0008B ...
        return _asignarCodigosConLetra(
            $enlace, $lotes_sin_gel,
            $ultimo_correlativo_guia, 1,
            $g_fecha, $g_anho
        );
    }
}

function _asignarCodigosNuevos(
    $enlace,
    array  $lotes,
    string $g_fecha,
    string $g_anho
): int {
    $usuario = $_SESSION["usu_usuario"];

    $siguiente = 1;
    if ($rs = mysqli_query($enlace, "
        SELECT IFNULL(MAX(correlativo), 0) AS max_corr
        FROM   correlativo_codigosgel
        WHERE  cod_anho = '$g_anho' AND estado = 'A'")) {
        if ($row = mysqli_fetch_assoc($rs)) $siguiente = intval($row["max_corr"]) + 1;
        mysqli_free_result($rs);
    }

    foreach ($lotes as $lote) {
        $id     = intval($lote["id_validaciondatos"]);
        $fec    = mysqli_real_escape_string($enlace, $lote["fecha_llegada"]);
        $codigo = sprintf("BJ-%02d-%04d", date("y"), $siguiente);

        mysqli_query($enlace, "DELETE FROM correlativo_codigosgel
                                WHERE id_validaciondatos = $id AND cod_anho = '$g_anho'");

        mysqli_query($enlace, "UPDATE despachos_primertramo_validaciondatos
                                SET    codigo_gel                   = '$codigo',
                                       codigo_gel_fechahoraregistro = '$g_fecha',
                                       codigo_gel_usuarioregistro   = '$usuario'
                                WHERE  Id = $id");

        mysqli_query($enlace, "INSERT INTO correlativo_codigosgel
                                   (cod_anho, fecha_llegadaplanta, correlativo, codigo_gel,
                                    id_validaciondatos, fechahora_registro, usuario_registro)
                               VALUES
                                   ($g_anho, '$fec', $siguiente, '$codigo',
                                    $id, '$g_fecha', '$usuario')");

        $siguiente++;
    }

    return 1;
}

function _asignarCodigosConLetra(
    $enlace,
    array  $lotes,
    int    $correlativo_base,
    int    $idx_letra_inicio,
    string $g_fecha,
    string $g_anho
): int {
    $usuario = $_SESSION["usu_usuario"];
    $idx     = $idx_letra_inicio;

    foreach ($lotes as $lote) {
        $id     = intval($lote["id_validaciondatos"]);
        $fec    = mysqli_real_escape_string($enlace, $lote["fecha_llegada"]);
        $sufijo = _indiceALetra($idx);
        $codigo = sprintf("BJ-%02d-%04d%s", date("y"), $correlativo_base, $sufijo);

        mysqli_query($enlace, "DELETE FROM correlativo_codigosgel
                                WHERE id_validaciondatos = $id AND cod_anho = '$g_anho'");

        mysqli_query($enlace, "UPDATE despachos_primertramo_validaciondatos
                                SET    codigo_gel                   = '$codigo',
                                       codigo_gel_fechahoraregistro = '$g_fecha',
                                       codigo_gel_usuarioregistro   = '$usuario'
                                WHERE  Id = $id");

        mysqli_query($enlace, "INSERT INTO correlativo_codigosgel
                                   (cod_anho, fecha_llegadaplanta, correlativo, codigo_gel,
                                    id_validaciondatos, fechahora_registro, usuario_registro)
                               VALUES
                                   ($g_anho, '$fec', $correlativo_base, '$codigo',
                                    $id, '$g_fecha', '$usuario')");

        $idx++;
    }

    return 1;
}

function _letraAIndice(string $letra): int {
    $v = 0;
    for ($i = 0; $i < strlen($letra); $i++) {
        $v = $v * 26 + (ord($letra[$i]) - 64);
    }
    return $v;
}

function _indiceALetra(int $n): string {
    $s = "";
    while ($n > 0) {
        $m = ($n - 1) % 26;
        $s = chr(65 + $m) . $s;
        $n = intval(($n - $m - 1) / 26);
    }
    return $s;
}

// Función para obtener la fecha de llegada del lote
function f_ObtenerFechaLlegada($enlace, $id)
{
	$q_fechallegada = "SELECT DATE(lote_pesoinicial_fechahoraregistro) AS fecha_llegada
												 FROM despachos_primertramo_validaciondatos
												 WHERE Id = $id";

	$res = mysqli_query($enlace, $q_fechallegada);

	if ($res && mysqli_num_rows($res) > 0) {
		$row = mysqli_fetch_assoc($res);

		return $row["fecha_llegada"];
	}

	return null;
}

// Función para obtener el código GEL disponible
function f_ObtenerCodigoGel($enlace, $fecha_llegada)
{
	$numero_gel = 0;

	// 1. Buscar el útimo correlativo en función a la Fecha de llegada
	$ultimo_correlativo = 0;

	$q_abierto = "SELECT correlativo
											FROM correlativo_codigosgel
											WHERE DATE(fecha_llegadaplanta) <= '$fecha_llegada'
											ORDER BY fecha_llegadaplanta DESC, correlativo DESC
											LIMIT 1";

	$res_abierto = mysqli_query($enlace, $q_abierto);

	while ($res_abierto && ($row_abierto = mysqli_fetch_assoc($res_abierto))) {
		$ultimo_correlativo = intval($row_abierto["correlativo"]);

		// $numero_gel = intval($row_abierto['correlativo']);
		// $is_cerrado = intval($row_abierto['is_cerrado']);

		// // Si el correlativo encontrado está abierto, lo usamos
		//   if ($is_cerrado == 0) {
		//     $numero_gel++;

		//     return sprintf("GEL-%02d-%04d", date("y"), $numero_gel) . '|' . $numero_gel;
		//   }
	}

	// 2. Busca el correlativo a Asignar
	$numero_gel = f_AsignarCodigoGEL($enlace, $ultimo_correlativo);

	return sprintf("GEL-%02d-%04d", date("y"), $numero_gel) . "|" . $numero_gel;
}

// Función para asignar código GEL disponible
function f_AsignarCodigoGEL($enlace, $ultimo_correlativo)
{
	// Averiguando el total de registros que se deberán asignar
	$r = 1;
	$total_registros = 0;

	$q_totalregistros = "SELECT COUNT(Id) AS _COUNT
															 FROM correlativo_codigosgel
															WHERE correlativo > $ultimo_correlativo";

	$res_totalregistros = mysqli_query($enlace, $q_totalregistros);

	while (
		$res_totalregistros &&
		($row_totalregistros = mysqli_fetch_assoc($res_totalregistros))
	) {
		$total_registros = $row_totalregistros["_COUNT"];
	}

	// Recorre todos los registros en busca de un correlativo disponible
	$ultimo_correlativo++;

	while ($r <= $total_registros) {
		$q_correlativo = "SELECT Id, is_cerrado
															FROM correlativo_codigosgel
														 WHERE correlativo = $ultimo_correlativo
														ORDER BY correlativo";

		if ($res_correlativo = mysqli_query($enlace, $q_correlativo)) {
			if (mysqli_num_rows($res_correlativo) > 0) {
				while (
					$row_correlativo = mysqli_fetch_array($res_correlativo)
				) {
					$cerrado = $row_correlativo["is_cerrado"];

					if ($cerrado == 0) {
						break 2;
					}
				}
			} else {
				break;
			}
		}

		$r++;
		$ultimo_correlativo++;
	}

	return $ultimo_correlativo;
}

// Función para reasignar códigos GEL posteriores (siempre que no estén cerrados)
function f_ReasignarCodigosGEL(
	$enlace,
	$fecha_llegada,
	$nuevo_correlativo,
	$g_fecha,
	$usuario_registro
) {
	$correlativo_asignado = 0;
	$nuevo_correlativo++;

	// Consulta para obtener los registros posteriores
	$q_posteriores = "SELECT Id, is_cerrado
													FROM correlativo_codigosgel
													WHERE DATE(fecha_llegadaplanta) > '$fecha_llegada'
													ORDER BY fecha_llegadaplanta, correlativo";

	$res_posteriores = mysqli_query($enlace, $q_posteriores);

	while ($row = mysqli_fetch_assoc($res_posteriores)) {
		// Busca los Correlativos disponibles para cada registro
		$correlativo_asignado = 0;
		$continue = true;

		if ($row["is_cerrado"] == 1) {
			continue;
		}

		while ($continue) {
			$q_correlativo = "SELECT Id, is_cerrado
																	FROM correlativo_codigosgel
																 WHERE correlativo = $nuevo_correlativo
																ORDER BY correlativo";

			if ($res_correlativo = mysqli_query($enlace, $q_correlativo)) {
				if (mysqli_num_rows($res_correlativo) > 0) {
					while (
						$row_correlativo = mysqli_fetch_array($res_correlativo)
					) {
						$cerrado = $row_correlativo["is_cerrado"];

						if ($cerrado == 1) {
							$nuevo_correlativo++;

							break;
						} else {
							$correlativo_asignado = $nuevo_correlativo;

							break 2;
						}
					}
				} else {
					$correlativo_asignado = $nuevo_correlativo;

					break;
				}
			}
		}

		// Asignando el correlativo
		if ($correlativo_asignado > 0) {
			$nuevo_codigo_gel = sprintf(
				"GEL-%02d-%04d",
				date("y"),
				$correlativo_asignado
			);

			$q_update =
				"UPDATE correlativo_codigosgel
															SET codigo_gel = '$nuevo_codigo_gel',
																	correlativo = $correlativo_asignado,
																	fechahora_registro_reasignado = '$g_fecha',
																	usuario_registro_reasignado = '$usuario_registro'
														WHERE Id = " . $row["Id"];

			mysqli_query($enlace, $q_update);
		}

		$nuevo_correlativo = $correlativo_asignado + 1;
	}
}

