// Graba imágenes de Imágenes Adicionales de Recepción de Unidades
function f_ActualizarImagenes_RecepcionImagenesAdicionales(
	$enlace,
	$id,
	$arr_imagenes
) {
	$estado = 1;

	// Graba datos de recepción
	$arr_imagenes = json_decode($arr_imagenes, true);

	foreach ($arr_imagenes as $imagen) {
		$imagen = trim($imagen["imagen"]);

		if (strlen($imagen) > 0) {
			echo "1";
			// Eliminar la cabecera de datos si existe (por ejemplo, "data:image/png;base64,")
			if (preg_match("/^data:image\/(\w+);base64,/", $imagen, $type)) {
				$base64String = substr($imagen, strpos($imagen, ",") + 1);
				$type = strtolower($type[1]); // jpg, png, gif, etc.
			} else {
				die("El formato base64 no es válido.");
			}

			// Decodificar el base64
			$imagenData = base64_decode($base64String);

			if ($imagenData === false) {
				die("La decodificación de la imagen falló.");
			}

			// Generar un nombre aleatorio único con fecha y hora
			$date = date("Ymd_His"); // Fecha y hora (ejemplo: 20250114_134500)
			$randomHash = bin2hex(random_bytes(16)); // Genera 32 caracteres aleatorios (128 bits en hexadecimal)
			$fileName = $date . "_" . $randomHash . "." . $type;

			// Especificar la ruta y el nombre del archivo para guardar la imagen
			$filePath = "../files/recepcion/" . $fileName;

			// Guardar la imagen
			file_put_contents($filePath, $imagenData);
			// $imagenBase64Comprimida = f_ComprimirImagenes($imagen);
			$imagenBase64Comprimida = "";
			$imagenBase64URL = $fileName;
		} else {
			$imagenBase64Comprimida = "";
			$imagenBase64URL = "";
		}

		// Consulta para guardar el imagen en la tabla correspondiente
		$q_save = "UPDATE controlingresovehiculo_imagenes SET ";
		$q_save .=
			"  imagen = " .
			(strlen($imagenBase64Comprimida) == 0
				? "NULL"
				: "'" . $imagenBase64Comprimida . "'");
		$q_save .=
			", imagen_url = " .
			(strlen($imagenBase64URL) == 0
				? "NULL"
				: "'" . $imagenBase64URL . "'");
		$q_save .= " WHERE Id = " . $id;

		if ($res_save = mysqli_query($enlace, $q_save)) {
		} else {
			$estado = 0;
		}
	}

	return $estado;
}

function get_KITCO_PrecioAU_PM($fecha = "")
{
	$url = "https://www.kitco.com/price/fixes/london-fix";

	$ch = curl_init();
	curl_setopt($ch, CURLOPT_URL, $url);
	curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
	curl_setopt($ch, CURLOPT_FOLLOWLOCATION, true);
	curl_setopt($ch, CURLOPT_SSL_VERIFYPEER, false); // solo si es necesario

	$html = curl_exec($ch);
	curl_close($ch);

	if (!$html) {
		return "ERROR";
	}

	libxml_use_internal_errors(true);
	$dom = new DOMDocument();
	$dom->loadHTML($html);
	libxml_clear_errors();

	$xpath = new DOMXPath($dom);
	$tables = $xpath->query("//table");

	$historial = [];

	foreach ($tables as $table) {
		$headers = $xpath->query(".//th", $table);
		if (
			$headers->length > 0 &&
			strpos($headers[1]->nodeValue, "Gold") !== false
		) {
			$rows = $xpath->query(".//tr", $table);
			foreach ($rows as $row) {
				$cols = $xpath->query(".//td", $row);
				if ($cols->length >= 2) {
					$fecha_raw = trim($cols[0]->nodeValue);
					$gold = trim($cols[1]->nodeValue);
					if (preg_match("/\d{2}-\w{3}-\d{4}/", $fecha_raw)) {
						$fecha_formateada = date(
							"Y-m-d",
							strtotime($fecha_raw)
						);
						if (strpos($gold, "/") !== false) {
							list($am, $pm) = explode("/", $gold);
							$historial[$fecha_formateada] = trim($pm);
						}
					}
				}
			}
		}
	}

	// Ordenar por fecha descendente (de más reciente a más antigua)
	krsort($historial);

	if ($fecha != "") {
		foreach ($historial as $f => $valor_pm) {
			if ($f <= $fecha && is_numeric($valor_pm)) {
				return $valor_pm;
			}
		}
		return "NO DISPONIBLE";
	} else {
		// Sin fecha: devuelve el más reciente
		foreach ($historial as $valor_pm) {
			if (is_numeric($valor_pm)) {
				return $valor_pm;
			}
		}
		return "NO DISPONIBLE";
	}
}

function f_SetValorizacionCorrelativo(
	$enlace,
	$id_valorizacion,
	$g_fecha,
	$usuario_registro
) {
	$estado = 0;

	// 1. Obtiene el último Correlativo
	$correlativo = "0";

	$q_newcodigo = "SELECT IFNULL(MAX(correlativo), 0) AS CORRELATIVO
												FROM correlativo_valorizacion_compramineral
											 /*WHERE anho = 0
												 AND mes = 0
												 AND dia = 0*/";

	if ($res_newcodigo = mysqli_query($enlace, $q_newcodigo)) {
		if (mysqli_num_rows($res_newcodigo) > 0) {
			while ($row_newcodigo = mysqli_fetch_array($res_newcodigo)) {
				$correlativo = $row_newcodigo["CORRELATIVO"] + 1;
			}
		}
	}

	// 2. Asignando correlativo
	$q_update = "UPDATE valorizacion_compramineral SET ";
	$q_update .= "  correlativo = '$correlativo'";
	$q_update .= " WHERE Id = $id_valorizacion";

	if ($res_update = mysqli_query($enlace, $q_update)) {
	}

	// 3. Guardando correlativo
	$q_insert =
		"INSERT INTO correlativo_valorizacion_compramineral (correlativo, id_valorizacion, fechahora_registro, usuario_registro) VALUES (";
	$q_insert .= "'$correlativo', ";
	$q_insert .= "$id_valorizacion, ";
	$q_insert .= "'$g_fecha', ";
	$q_insert .= "'$usuario_registro')";

	if ($res_insert = mysqli_query($enlace, $q_insert)) {
		$estado = 1;
	}

	return $estado;
}

// Proceso de inserción masiva de código de lotes en tabla despachos_primertramo_validaciondatos
function f_Insertar_DespachoPrimerTramo_ValidacionDatos($enlace)
{
	$estado = 0;

	// Obtiene los datos de Balanza pendientes por importar a la tabla de Validación de Datos del Primer Tramo de Despachos.
	$q_insert = "INSERT INTO despachos_primertramo_validaciondatos (balanza_id_controlingresovehiculo, 
										 balanza_id_tipoingresounidad, balanza_placa, balanza_placa2, balanza_id_transportista,
										 balanza_id_tipovehiculo, balanza_id_chofer, balanza_fechahoraregistro, lote_id_lote,
										 lote_cod_lote, lote_num_ticket, lote_id_tipocarga, lote_id_zonaorigen, lote_id_proveedorminero,
										 lote_id_encargadomuestra, lote_id_producto, lote_id_tipomineral, lote_peso_inicial,
										 lote_pesoinicial_fechahoraregistro, lote_peso_final, lote_pesofinal_fechahoraregistro, lote_peso_bruto,
										 lote_peso_tara, lote_peso_neto, lote_peso_pendiente_envio, despacho_id_estadolote, unidad_capacidad,
										 unidad_tara, unidad_idmarca, balanza_observacion, despacho_id_modalidadenvio, unidad_capacidad2,
										 unidad_tara2, unidad_idmarca2)";

	$q_insert .= "SELECT B.id_controlIngresoVehiculo,
														 B.id_tipoingresounidad,
														 B.placa,
														 B.placa2,
														 B.id_transportista,
														 B.id_tipovehiculo,
														 B.id_choferes,
														 CONCAT(B.dFechaIngreso, ' ', B.dhoraingresoPlanta) AS FECHAHORA_INGRESOPLANTA,
														 L.id_CatalogoLotes,
														 L.ccod_Lote,
														 L.nNro_ticketsBalanza,
														 L.balanza_id_tipocarga,
														 L.balanza_id_zonaorigen,
														 L.balanza_id_proveedorminero,
														 L.balanza_id_encargadomuestra,
														 L.balanza_id_producto,
														 L.balanza_id_tipomineral,
														 L.nPeso_InicialBalanza,
														 CONCAT(L.tFechaInicialBalanza, ' ', L.tHoraInicialBalanza) AS PESOINICIAL_FECHAHORA,
														 L.nPeso_FinalBalanza,
														 CONCAT(L.dFechaFinalBalanza, ' ', L.tHoraFinalBalanza) AS PESOFINAL_FECHAHORA,
														 L.nPeso_InicialBalanza,
														 L.nPeso_FinalBalanza,
														 (L.nPeso_InicialBalanza - L.nPeso_FinalBalanza),
														 (L.nPeso_InicialBalanza - L.nPeso_FinalBalanza) AS PENDIENTE_ENVIO,
														 1,
														 U.nCapacidad,
														 U.nTara,
														 U.id_marca,
														 L.balanza_observacion,
														 3 AS MODALIDAD_ENVIO,
														 U2.nCapacidad,
														 U2.nTara,
														 U2.id_marca
												FROM catalogolotes L
														 INNER JOIN controlingresovehiculo B ON L.id_controlIngresoVehiculo = B.id_controlIngresoVehiculo
														 LEFT JOIN tb_clientes C ON L.balanza_id_proveedorminero = C.Id
															 AND C.cod_clientecondicion = 1
														 LEFT JOIN transporte U ON B.placa = U.cplaca
														 LEFT JOIN transporte U2 ON B.placa2 = U2.cplaca
											 WHERE B.id_tipoingresounidad = 1
												 AND L.is_copiacomercializacion = 0
												 AND L.dFechaFinalBalanza IS NOT NULL
												 AND L.id_CatalogoLotes NOT IN (SELECT lote_id_lote
																													FROM despachos_primertramo_validaciondatos)";

	if ($res_insert = mysqli_query($enlace, $q_insert)) {
	}

	return $estado;
}

