													 D.cod_interno,
													 S.des_sucursal,
													 C.cliente_documento,
													 CL.razon_social,
													 CONCAT(CL.telefono1, CASE WHEN LENGTH(TRIM(IFNULL(CL.telefono2, ''))) > 0 THEN CONCAT(' - ', CL.telefono2) ELSE '' END) AS TELEFONOS_CLIENTE,
													 C.recibo_codigo,
													 C.facturador_comprobante,
													 C.is_instruccion,
													 C.is_temporal,
													 C.is_recepcioncanceled,
