													 C.is_recepcioncanceled,
													 TCL.Id AS COD_TIPOCLIENTE,
													 C.tiene_recojo,

													 CASE WHEN C.tiene_recojo = 1 THEN 'S/ 10.00' ELSE '' END AS RECOJO,

													 IFNULL(C.is_ampliacion_de, 0) AS IS_AMPLIACION,
