		);
		$cod_tipocliente = mysqli_real_escape_string(
			$enlace,
			$_POST["cod_tipocliente"]
		);
		$cod_tipo = mysqli_real_escape_string($enlace, $_POST["cod_tipo"]);
		$txt_tipo = mysqli_real_escape_string($enlace, $_POST["txt_tipo"]);
		$cod_cliente = mysqli_real_escape_string(
			$enlace,
			$_POST["cod_cliente"]
		);

		// Obtiene datos
		$q_clientes = "SELECT C.Id,
															C.cod_clientecondicion,
															TCC.descripcion AS CONDICION,
															C.cod_tipocliente,
															TC.descripcion AS TIPO_CLIENTE,
															C.cod_tipodocumento,
															TD.descripcion AS TIPO_DOCUMENTO,
															C.documento,
															C.razon_social,
															IFNULL(C.cod_cliente, '') AS cod_cliente,
															IFNULL(C.telefono1, '') AS telefono1,
															IFNULL(C.telefono2, '') AS telefono2,
															CONCAT(IFNULL(C.telefono1, ''), CASE WHEN LENGTH(IFNULL(C.telefono2, '')) > 0 THEN CONCAT(' - ', C.telefono2) ELSE '' END) AS TELEFONOS,
															IFNULL(C.correo, '') AS correo,
															IFNULL(C.direccion, '') AS direccion,
															IFNULL(C.proveedorminero_concesion, '') AS concesion,
															IFNULL(C.proveedorminero_codigounico, '') AS codigo_unico,
															IFNULL(C.proveedorminero_ubicacion, '') AS ubicacion,
															IFNULL(C.proveedorminero_representantelegal_dni, '') AS representantelegal_dni,
															IFNULL(C.proveedorminero_representantelegal_nombres, '') AS representantelegal_nombres,
															C.estado
												FROM tb_clientes C
															INNER JOIN tbconfig_tipocliente TC ON C.cod_tipocliente = TC.Id
															INNER JOIN tbconfig_tipodocumento TD ON C.cod_tipodocumento = TD.Id
															INNER JOIN tbconfig_clientecondicion TCC ON C.cod_clientecondicion = TCC.Id
											 WHERE C.estado <> 'X'";

		if (strlen($cod_condicion) > 0) {
			$q_clientes .= "   AND cod_clientecondicion = " . $cod_condicion;
		}

		if (strlen($cod_tipocliente) > 0) {
			$q_clientes .= "   AND cod_tipocliente = " . $cod_tipocliente;
		}

		if ($cod_tipo == 1 || $cod_tipo == 2) {
			if ($cod_tipo == 1) {
				$q_clientes .= "   AND documento LIKE '%" . $txt_tipo . "%'";
			} else {
				$q_clientes .= "   AND razon_social LIKE '%" . $txt_tipo . "%'";
			}
		}

		if (strlen($cod_cliente) > 0) {
			$q_clientes .= "   AND C.cod_cliente LIKE '%" . $cod_cliente . "%'";
		}

		$q_clientes .= " ORDER BY C.cod_cliente";

		if ($res_clientes = mysqli_query($enlace, $q_clientes)) {
			if (mysqli_num_rows($res_clientes) > 0) {
				$estado = 1;

				while ($row_clientes = mysqli_fetch_array($res_clientes)) {
					array_push($res, $row_clientes);
				}
			}
		}

		echo json_encode(["estado" => $estado, "res" => $res]);

		break;

