					if (
						$res_detallefactura = mysqli_query(
							$enlace,
							$q_detallefactura
						)
					) {
						if (mysqli_num_rows($res_detallefactura) > 0) {
							while (
								$row_detallefactura = mysqli_fetch_array(
									$res_detallefactura
								)
							) {
								$recojo = 10;

								// Inserta el resultado en la tabla de detalle de factura
								$q_ficticio =
									"INSERT INTO recepcion_ensayos_detallefactura (id_cabecera, item, descripcion, cantidad, precio, total, tiene_dscto, dscto, fechahora_registro, usuario_registro) VALUES(";
								$q_ficticio .= $id_recepcion . ", ";
								$q_ficticio .= $item . ", ";
								$q_ficticio .= "'RECOJO', ";
								$q_ficticio .= "1, ";
								$q_ficticio .= $recojo . ", ";
								$q_ficticio .= $recojo . ", ";
								$q_ficticio .=
									$row_detallefactura["cliente_tienedscto"] .
									", ";
								$q_ficticio .=
									(strlen(
										$row_detallefactura["dscto_porcentaje"]
									) == 0
										? "NULL"
										: $row_detallefactura[
											"dscto_porcentaje"
										]) . ", ";
								$q_ficticio .= "'" . $g_fecha . "', ";
								$q_ficticio .= "'" . $usuario_registro . "')";

								if (
									$res_ficticio = mysqli_query(
										$enlace,
										$q_ficticio
									)
								) {
								} else {
									$estado = 0;
								}

								$item++;
							}
						}
					}
				} else {
					$estado = 0;
				}
			}
		} else {
			$estado = 0;
		}

		// Genera el Comprobante Electrónico, excepto para clientes con crédito
		$num_comprobante = "";

		if ($is_porpagar == 1) {
			if ($estado == 1) {
				$res_comprobante = f_GenerarComprobanteElectronico(
					$id_recepcion,
					$is_factura
				);

				$res_comprobante = explode(",", $res_comprobante);
				$res_comprobante = explode(":", $res_comprobante[0])[1];

				if (!$res_comprobante) {
					$estado = 3;
				}

				// Obteniendo el N° de Comprobante
				$q_comprobante =
					"SELECT facturador_comprobante
																		FROM recepcion_ensayos_cabecera
																	 WHERE Id = " . $id_recepcion;

				if ($res_comprobante = mysqli_query($enlace, $q_comprobante)) {
					if (mysqli_num_rows($res_comprobante) > 0) {
						while (
							$row_comprobante = mysqli_fetch_array(
								$res_comprobante
							)
						) {
							$num_comprobante =
								$row_comprobante["facturador_comprobante"];
						}
					}
				}

				// // Genera los Códigos para Laboratorio
				// 	f_GetCodigosInternos_LQ($id_recepcion, $g_fecha, $g_anho, $g_mes, $g_dia, $usuario_registro);

				// Verifica si es una ampliación y si se realizó en el mismo día
				$fechahora_recepcion_amp = "";
				$fechahora_recepcion_org = "";

				$q_ampliacion =
					"SELECT fechahora_recepcion,
																				is_ampliacion_de
																	 FROM recepcion_ensayos_cabecera
																	WHERE Id = " . $id_recepcion;

				if ($res_ampliacion = mysqli_query($enlace, $q_ampliacion)) {
					if (mysqli_num_rows($res_ampliacion) > 0) {
						while (
							$row_ampliacion = mysqli_fetch_array(
								$res_ampliacion
							)
						) {
							$fechahora_recepcion_amp =
								$row_ampliacion["fechahora_recepcion"];

							if (
								strlen($row_ampliacion["is_ampliacion_de"]) == 0
							) {
								// Genera los Códigos para Laboratorio
								f_GetCodigosInternos_LQ(
									$id_recepcion,
									$g_fecha,
									$g_anho,
									$g_mes,
									$g_dia,
									$usuario_registro
								);
							} else {
								// Comprueba si la fecha de recepción de la ampliación y la original son iguales
								$q_fechaorigen =
									"SELECT fechahora_recepcion
																						 FROM recepcion_ensayos_cabecera
																						WHERE Id = " . $row_ampliacion["is_ampliacion_de"];

								if (
									$res_fechaorigen = mysqli_query(
										$enlace,
										$q_fechaorigen
									)
								) {
									if (mysqli_num_rows($res_fechaorigen) > 0) {
										while (
											$row_fechaorigen = mysqli_fetch_array(
												$res_fechaorigen
											)
										) {
											$fechahora_recepcion_org =
												$row_fechaorigen[
													"fechahora_recepcion"
												];
										}
									}
								}

								// Si las fecha son iguales coloca el mismo código de L.Q. a la muestra de ampliación, sino crea un nuevo código
								if (
									substr($fechahora_recepcion_amp, 0, 10) ==
									substr($fechahora_recepcion_org, 0, 10)
								) {
									// Obtiene la lista de muestras de la ampliación y actualiza los códigos interno con los originales
									$q_datos =
										"SELECT Id, is_ampliacion_de
																						FROM recepcion_ensayos_detalle
																					 WHERE id_cabecera = " . $id_recepcion;

									if (
										$res_datos = mysqli_query(
											$enlace,
											$q_datos
										)
									) {
										if (mysqli_num_rows($res_datos) > 0) {
											while (
												$row_datos = mysqli_fetch_array(
													$res_datos
												)
											) {
												$q_update =
													"UPDATE recepcion_ensayos_detalle
																										SET id_codinterno = (SELECT id_codinterno
																																					 FROM (SELECT D_x.id_codinterno
																																									 FROM recepcion_ensayos_detalle D_x
																																									 WHERE Id = " .
													$row_datos[
														"is_ampliacion_de"
													] .
													") AS DATOS),

																												cod_interno =  (SELECT cod_interno
																																							 FROM (SELECT D_x.cod_interno
																																									 FROM recepcion_ensayos_detalle D_x
																																									 WHERE Id = " .
													$row_datos[
														"is_ampliacion_de"
													] .
													") AS DATOS)
																									WHERE Id = " .
													$row_datos["Id"];

												if (
													$res_update = mysqli_query(
														$enlace,
														$q_update
													)
												) {
												}
											}
										}
									}
								} else {
									// Genera los Códigos para Laboratorio
									f_GetCodigosInternos_LQ(
										$id_recepcion,
										$g_fecha,
										$g_anho,
										$g_mes,
										$g_dia,
										$usuario_registro
									);
								}
							}
						}
					}
				}
			}
		}

		echo json_encode([
			"estado" => $estado,
			"num_comprobante" => $num_comprobante,
			"pagado_fechahoraregistro" => $g_fecha,
			"pagado_usuarioregistro" => $usuario_registro,
		]);

