	case "dash_TotalMuestras":
		$res = [];
		$estado = 0;
		$html = "";
		$d = 1;

		// Recuperando parámetros
		$fecha_inicio = mysqli_real_escape_string(
			$enlace,
			$_POST["fecha_inicio"]
		);
		$fecha_fin = mysqli_real_escape_string($enlace, $_POST["fecha_fin"]);
		// $filtro_cliente = mysqli_real_escape_string($enlace, $_POST["filtro_cliente"]);
		// $filtro_sucursal = mysqli_real_escape_string($enlace, $_POST["filtro_sucursal"]);
		// $filtro_mediospago = mysqli_real_escape_string($enlace, $_POST["filtro_mediospago"]);

		// Inicializando variables
		$total_muestras1 = 0;
		$total_muestras2 = 0;

		$num_ventas1 = 0;
		$num_ventas2 = 0;

		$total_ventas1 = 0;
		$total_ventas2 = 0;

		// Validando fechas
		if ($fecha_inicio <= "2023-01-31") {
			// Obtiene datos de la tabla de Backup (proveniente del sistema antiguo)
			$q_datosBk =
				"SELECT R.cod_sucursal,
																 COUNT(R.Id) AS _COUNT,

																 (SELECT COUNT(num_requerimiento)
																		FROM (SELECT cod_sucursal,
																								 num_requerimiento
																						FROM recepcion_ensayos_muestras_old
																					 WHERE fecha_recepcion BETWEEN '" .
				$fecha_inicio .
				"' AND '" .
				$fecha_fin .
				"'
																						 AND cod_sucursal = R.cod_sucursal
																					GROUP BY cod_sucursal, num_requerimiento) AS DATOS
																					GROUP BY cod_sucursal) AS _COUNT_VENTAS

														FROM recepcion_ensayos_muestras_old R
													 WHERE R.fecha_recepcion BETWEEN '" .
				$fecha_inicio .
				"' AND '" .
				$fecha_fin .
				"'
													GROUP BY R.cod_sucursal";

			if ($res_datosBk = mysqli_query($enlace, $q_datosBk)) {
				if (mysqli_num_rows($res_datosBk) > 0) {
					$estado = 1;

					while ($row_datosBk = mysqli_fetch_array($res_datosBk)) {
						if ($row_datosBk["cod_sucursal"] == 1) {
							$total_muestras1 += $row_datosBk["_COUNT"];
							$num_ventas1 += $row_datosBk["_COUNT_VENTAS"];
						}

						if ($row_datosBk["cod_sucursal"] == 2) {
							$total_muestras2 += $row_datosBk["_COUNT"];
							$num_ventas2 += $row_datosBk["_COUNT_VENTAS"];
						}
					}
				}
			}

			// Reasignando la fecha de inicio
			if ($fecha_fin <= "2023-02-01") {
				$fecha_inicio = "2023-02-01";
			}
		}

		// Obtiene datos
		$q_datos =
			"SELECT cod_sucursal,

													 (SELECT COUNT(D.Id) AS _COUNT
															FROM recepcion_ensayos_detalle D
																	 INNER JOIN recepcion_ensayos_cabecera C ON D.id_cabecera = C.Id
															WHERE C.is_temporal = 0
																AND C.is_recepcioncanceled = 0
																AND C.cod_sucursal = DATOS_x.cod_sucursal
																AND DATE(C.fechahora_recepcion) BETWEEN '" .
			$fecha_inicio .
			"' AND '" .
			$fecha_fin .
			"') AS _COUNT,

													 SUM(TOTAL) AS TOTAL_VENTAS,

													 (SELECT COUNT(C_.Id)
															FROM recepcion_ensayos_cabecera C_
														 WHERE C_.cod_sucursal = DATOS_x.cod_sucursal
															 AND C_.is_temporal = 0
															 AND C_.is_recepcioncanceled = 0
															 AND DATE(C_.fechahora_recepcion) BETWEEN '" .
			$fecha_inicio .
			"' AND '" .
			$fecha_fin .
			"') AS _COUNT_VENTAS

											FROM (SELECT Id,
																	 cod_sucursal,

																	 CASE WHEN cliente_tienedscto = 1
																		 THEN ROUND(TOTAL * ((100 - dscto_porcentaje) / 100), 2)
																	 ELSE TOTAL END AS TOTAL
															FROM (SELECT DISTINCT
																					 C.Id,
																					 C.cod_sucursal,

																					 (SELECT IFNULL(SUM(D_x.exceso), 0)
																							FROM recepcion_ensayos_detalle D_x
																						 WHERE D_x.id_cabecera = C.Id
																							 AND estado = 'A')
																										
																						+

																						CASE WHEN C.tiene_recojo = 1 THEN 10 ELSE 0 END
																								
																						+

																						(SELECT SUM(EA.total)
																							 FROM recepcion_ensayos_analisis EA
																							WHERE EA.id_detalle IN (SELECT D_x.Id
																																				FROM recepcion_ensayos_detalle D_x
																																			 WHERE D_x.id_cabecera = C.Id)) AS TOTAL,
																								
																						C.cliente_tienedscto,
																						C.dscto_porcentaje
																			 FROM recepcion_ensayos_cabecera C
																						INNER JOIN recepcion_ensayos_detalle D ON C.Id = D.id_cabecera
																			WHERE C.is_temporal = 0
																				AND C.is_recepcioncanceled = 0
																				AND DATE(C.fechahora_recepcion) BETWEEN '" .
			$fecha_inicio .
			"' AND '" .
			$fecha_fin .
			"') AS DATOS) AS DATOS_x
										GROUP BY cod_sucursal";

		if (strlen($filtro_sucursal) > 0) {
			$q_datos .= "   AND C.cod_sucursal = " . $filtro_sucursal;
		}

		if (strlen(trim($filtro_mediospago)) > 0) {
			$q_datos .=
				"   AND I.cod_mediopago LIKE '%" .
				trim($filtro_mediospago) .
				"%'";
		}

		if ($res_datos = mysqli_query($enlace, $q_datos)) {
			if (mysqli_num_rows($res_datos) > 0) {
				$estado = 1;

				while ($row_datos = mysqli_fetch_array($res_datos)) {
					if ($row_datos["cod_sucursal"] == 1) {
						$total_muestras1 += $row_datos["_COUNT"];
						$num_ventas1 += $row_datos["_COUNT_VENTAS"];
						$total_ventas1 += $row_datos["TOTAL_VENTAS"];
					}

					if ($row_datos["cod_sucursal"] == 2) {
						$total_muestras2 += $row_datos["_COUNT"];
						$num_ventas2 += $row_datos["_COUNT_VENTAS"];
						$total_ventas2 += $row_datos["TOTAL_VENTAS"];
					}
				}
			}
		}

		echo json_encode([
			"estado" => $estado,
			"total_muestras1" => $total_muestras1,
			"total_muestras2" => $total_muestras2,
			"total_ventas1" => number_format($total_ventas1, 2, ".", ","),
			"total_ventas2" => number_format($total_ventas2, 2, ".", ","),
			"total_ventas" => number_format(
				$total_ventas1 + $total_ventas2,
				2,
				".",
				","
			),
			"num_ventas1" => $num_ventas1,
			"num_ventas2" => $num_ventas2,
		]);

		break;

	case "update_TelefonoCliente":
