																												FROM recepcion_ensayos_detalle D_x
																											 WHERE D_x.id_cabecera = C.Id)) AS SUB_TOTAL,

														CASE WHEN C.tiene_recojo = 1 THEN 10 ELSE 0 END AS TIENE_RECOJO

											 FROM recepcion_ensayos_cabecera C
											WHERE C.cliente_documento = '" .
			$documento .
