	case "get_IdRecepcion_Ampliacion":
		$estado = 1;

		// Recupera parámetros
		$id_recepcion_origen = mysqli_real_escape_string(
			$enlace,
			$_POST["id_recepcion_origen"]
		);
		$arr_muestras = mysqli_real_escape_string(
			$enlace,
			$_POST["arr_muestras"]
		);
		$usuario_registro = $_SESSION["usu_usuario"];

		// Obtiene el nuevo código de Requerimiento
		$num_ampliacion = "";

		$q_requerimiento =
			"SELECT COUNT(Id) + 1 AS _COUNT
															FROM recepcion_ensayos_cabecera
														 WHERE is_ampliacion_de = " .
			$id_recepcion_origen .
			"
															 AND is_recepcioncanceled = 0";

		if ($res_requerimiento = mysqli_query($enlace, $q_requerimiento)) {
			if (mysqli_num_rows($res_requerimiento) > 0) {
				while (
					$row_requerimiento = mysqli_fetch_array($res_requerimiento)
				) {
					$num_ampliacion =
						"-" .
						str_pad(
							$row_requerimiento["_COUNT"],
							2,
							"0",
							STR_PAD_LEFT
						);
				}
			}
		}

		// Si es un registro nuevo hace copia del original
		$q_copia =
			"INSERT INTO recepcion_ensayos_cabecera(cod_interno_preliminar, fechahora_recepcion, cliente_documento,
																cliente_razonsocial, entregado_por, celular_areportar, cod_sucursal, cod_moneda, observacion,
																tiene_recojo, is_temporal, cod_recibocorrelativo, recibo_codigo, is_ampliacion_de,
																ampliacion_idmuestras, fechahora_registro, usuario_registro)

										SELECT CONCAT(cod_interno_preliminar, '" .
			$num_ampliacion .
			"') AS cod_interno_preliminar,
													 '" .
			$g_fecha .
			"' AS fechahora_recepcion,
													 cliente_documento,
													 cliente_razonsocial,
													 entregado_por,
													 celular_areportar,
													 cod_sucursal,
													 cod_moneda,
													 observacion,
													 tiene_recojo,
													 1 AS is_temporal,
													 cod_recibocorrelativo,
													 CONCAT(recibo_codigo, '" .
			$num_ampliacion .
			"') AS recibo_codigo,
													 " .
			$id_recepcion_origen .
			" AS is_ampliacion_de,
													 '" .
			str_replace("|", ", ", $arr_muestras) .
			"' AS ampliacion_idmuestras,
													 '" .
			$g_fecha .
			"' AS fechahora_registro,
													 '" .
			$usuario_registro .
			"' AS usuario_registro
											FROM recepcion_ensayos_cabecera
										 WHERE Id = " .
			$id_recepcion_origen;

		if ($res_copia = mysqli_query($enlace, $q_copia)) {
			$id_recepcion = mysqli_insert_id($enlace);
			$id_md5 = md5($id_recepcion);

			// Actualiza el campo de "tiene_ampliacion" en la Recepción Original
			$q_update =
				"UPDATE recepcion_ensayos_cabecera SET
																tiene_ampliacion = 1
													WHERE Id = " . $id_recepcion_origen;

			if ($res_update = mysqli_query($enlace, $q_update)) {
				$estado = 1;

				// Actualiza detalle
				$num_detalle = 1;
				$d = 0;
				$arr_muestras = explode("|", $arr_muestras);

				while ($d < count($arr_muestras)) {
					$q_detalle =
						"INSERT INTO recepcion_ensayos_detalle (id_cabecera, cod_interno_preliminar, nombre_muestra,
																						peso_muestra, cod_estadomuestra, cod_envasemuestra, cod_tipomuestra, cod_ensayomuestra,
																						fechahora_registro, usuario_registro, is_ampliacion_de)

																SELECT " .
						$id_recepcion .
						" AS id_cabecera,
																	
																			 (SELECT CONCAT(C.cod_interno_preliminar, '-', '" .
						str_pad($num_detalle, 3, "0", STR_PAD_LEFT) .
						"')
																					FROM recepcion_ensayos_cabecera C
																				 WHERE C.Id = $id_recepcion) AS cod_interno_preliminar,

																			 nombre_muestra,
																			 peso_muestra,
																			 cod_estadomuestra,
																			 cod_envasemuestra,
																			 cod_tipomuestra,
																			 cod_ensayomuestra,
																			 '" .
						$g_fecha .
						"',
																			 '" .
						$usuario_registro .
						"',
																			 " .
						$arr_muestras[$d] .
						" AS is_ampliacion_de
																	FROM recepcion_ensayos_detalle
																 WHERE Id = " .
						$arr_muestras[$d];

					if ($res_detalle = mysqli_query($enlace, $q_detalle)) {
						// Actualiza estado de registro original
						$q_update =
							"UPDATE recepcion_ensayos_detalle
																			SET tiene_ampliacion = 1
																		WHERE Id = " . $arr_muestras[$d];

						if ($res_update = mysqli_query($enlace, $q_update)) {
						} else {
							$estado = 0;
						}
					} else {
						$estado = 0;
					}

					$d++;
					$num_detalle++;
				}
			}
		} else {
			$estado = 0;
		}

		echo json_encode([
			"estado" => $estado,
			"id_recepcion" => $id_recepcion,
			"id_md5" => $id_md5,
		]);

		break;

	case "anular_Venta":
		$res = [];
		$estado = 0;

		$id_recepcion = mysqli_real_escape_string(
			$enlace,
			$_POST["id_recepcion"]
		);
		$usuario_registro = $_SESSION["usu_usuario"];

		// Elimina muestras
		$q_anular =
			"UPDATE recepcion_ensayos_cabecera
												SET is_recepcioncanceled = 1,
														facturador_estado = 'Venta Anulada',
														recepcioncanceled_fechahoraregistro = '" .
			$g_fecha .
			"',
														recepcioncanceled_usuarioregistro = '" .
			$usuario_registro .
			"'
											WHERE Id = " .
			$id_recepcion;

		if ($res_anular = mysqli_query($enlace, $q_anular)) {
			$estado = 1;
		}

		echo json_encode(["estado" => $estado]);

		break;

	case "editar_Venta":
		$res = [];
		$estado = 0;

		$id_recepcion = mysqli_real_escape_string(
			$enlace,
			$_POST["id_recepcion"]
		);
		$usuario_registro = $_SESSION["usu_usuario"];

		// Verificar que no haya un registro de venta en curso
		$tiene_venta = 0;

		$q_verify =
			"SELECT COUNT(Id) AS _COUNT
											 FROM recepcion_ensayos_cabecera
											WHERE usuario_registro = '" .
			$usuario_registro .
			"'
												AND is_temporal = 1";

		if ($res_verify = mysqli_query($enlace, $q_verify)) {
			if (mysqli_num_rows($res_verify) > 0) {
				while ($row_verify = mysqli_fetch_array($res_verify)) {
					if ($row_verify["_COUNT"] > 0) {
						$tiene_venta = 1;

						$estado = 2;

						echo json_encode(["estado" => $estado]);
						return;
					}
				}
			}
		}

		// Cambiar estado
		$q_editar =
			"UPDATE recepcion_ensayos_cabecera
												SET is_temporal = 1,
														usuario_registro = '" .
			$usuario_registro .
			"'
											WHERE Id = " .
			$id_recepcion;

		if ($res_editar = mysqli_query($enlace, $q_editar)) {
			$estado = 1;
		}

		echo json_encode(["estado" => $estado]);

		break;

	case "get_LQRecepcionMuestras":
		$res = [];
		$estado = 0;
		$html = "";
		$d = 1;

		// Recuperando parámetros
		$fecha_inicio = mysqli_real_escape_string(
			$enlace,
			$_POST["fecha_inicio"]
		);
		$fecha_fin = mysqli_real_escape_string($enlace, $_POST["fecha_fin"]);
		$filtro_CI = mysqli_real_escape_string($enlace, $_POST["filtro_CI"]);
		$filtro_opt1 = mysqli_real_escape_string(
			$enlace,
			$_POST["filtro_opt1"]
		);
		$filtro_opt2 = mysqli_real_escape_string(
			$enlace,
			$_POST["filtro_opt2"]
		);
		$filtro_opt3 = mysqli_real_escape_string(
			$enlace,
			$_POST["filtro_opt3"]
		);

		// Obtiene datos
		$q_datos = "SELECT L.ccod_Lote,
													 CONCAT(CIV.dFechaIngreso, ' ', CIV.dhoraingresoPlanta) AS FECHAHORA_INGRESO,
													 CIV.placa,
													 CIV.placa2,
													 TM.descripcion AS TIPO_MINERAL,
													 L.nPesoNetoBalanza,
													 L.humedad_pesohumedad,
													 L.preparacion_fechahoraregistro,
													 L.preparacion_usuarioregistro
											FROM catalogolotes L
													 LEFT JOIN controlingresovehiculo CIV ON L.id_controlIngresoVehiculo = CIV.id_controlIngresoVehiculo
													 LEFT JOIN tbconfig_tipomineral TM ON L.balanza_id_tipomineral = TM.Id
										 WHERE 1 = 1";

		if (strlen(trim($filtro_CI)) > 0) {
			$q_datos .= "   AND L.ccod_Lote LIKE '%" . trim($filtro_CI) . "%'";
		} else {
			$q_datos .=
				"   AND DATE(CIV.dFechaIngreso) BETWEEN '" .
				$fecha_inicio .
				"' AND '" .
				$fecha_fin .
				"'";
		}

		if ($filtro_opt3 == 0) {
			if ($filtro_opt1 == 1) {
				$q_datos .= "   AND L.preparacion_fechahoraregistro IS NULL";
			} else {
				$q_datos .=
					"   AND L.preparacion_fechahoraregistro IS NOT NULL";
			}
