		$total_muestras1 = 0;
		$total_muestras2 = 0;

		// Validando fechas y obteniendo datos
		if ($cod_anho == 2023 && $cod_mes == 1) {
			// Obtiene datos de la tabla de Backup (proveniente del sistema antiguo)
			$q_datosBk = "SELECT R.cod_sucursal,
																 COUNT(R.Id) AS _COUNT,

																 (SELECT COUNT(fecha_recepcion)
																		FROM (SELECT DISTINCT fecha_recepcion
																						FROM recepcion_ensayos_muestras_old
																					 WHERE YEAR(fecha_recepcion) = 2023
																						 AND MONTH(fecha_recepcion) = 1) AS DATOS) AS TOTAL_DIAS

														FROM recepcion_ensayos_muestras_old R
													 WHERE YEAR(R.fecha_recepcion) = 2023
														 AND MONTH(R.fecha_recepcion) = 1
													GROUP BY R.cod_sucursal";

			if ($res_datosBk = mysqli_query($enlace, $q_datosBk)) {
				if (mysqli_num_rows($res_datosBk) > 0) {
					$estado = 1;

