								$row_datosBk["TOTAL_DIAS"]
							);
						}

						if ($row_datosBk["cod_sucursal"] == 2) {
							$total_muestras2 += round(
								$row_datosBk["_COUNT"] /
								$row_datosBk["TOTAL_DIAS"]
							);
						}
					}
				}
