							($row_datos["is_temporal"] == 1
								? ""
								: ($row_datos["IS_PORPAGAR"] == 1
									? "background-color: #FF5F5D; color: #ffffff;"
									: ($row_datos["cod_mediopago"] == 3
										? "background-color: #89D99D; color: #ffffff;"
										: ($row_datos["cod_mediopago"] == 1
											? "background-color: #F2BE22; color: #ffffff;"
											: "")))) .
							'">';
						$html .=
							"   " .
							($row_datos["is_temporal"] == 1
								? ""
								: ($row_datos["IS_PORPAGAR"] == 1 &&
									$row_datos["is_ventacredito"] == 1
									? "CREDITO POR CONFIRMAR"
									: $row_datos["MEDIO_PAGO"]));

						if (
							$row_datos["IS_PORPAGAR"] == 1 &&
							$row_datos["IS_PAGADO"] == 1
						) {
							$html .=
								'   </br><label style="color: #212226;">* PAGADO *</label>';
						}
					} else {
						$html .=
							'  <td rowspan="' .
							$row_datos["_COUNT_MUESTRAS"] .
							'" style="border: solid; border-width: 1px; border-color: #D9D9D9; vertical-align: middle;">';
					}

					$html .= "  </td>";

					$html .=
						'  <td rowspan="' .
						$row_datos["_COUNT_MUESTRAS"] .
						'" style="border: solid; border-width: 1px; border-color: #D9D9D9; vertical-align: middle; text-align: center;">';

					if ($row_datos["is_recepcioncanceled"] == 0) {
						$total_efectivo_x =
							strlen($row_datos["efectivo_ingresado"]) == 0
							? ""
							: ($row_datos["efectivo_ingresado"] > $total_x
								? number_format($total_x, 2, ".", "")
								: number_format(
									$row_datos["efectivo_ingresado"],
