					$html .= "   " . number_format($total_x, 2, ".", ",");
					$html .= "  </td>";

					// Pintando Cabeceras de Medios de Pago
					$c = 0;
					$campo = "";

					while ($c < count($arr_cabecera)) {
						$campo = $arr_cabecera[$c]["COD_MEDIOPAGO"];

						if ($row_datos["COD_MEDIOPAGOCABECERA"] == $campo) {
