			if (mysqli_num_rows($res_validar) > 0) {
				while ($row_validar = mysqli_fetch_assoc($res_validar)) {
					// Verifica si la Muestra aun no ha sido recepcionada por LQ
					if (strlen($row_validar["fechahora_recepcionlq"]) == 0) {
						$estado = 4;

						echo json_encode(["estado" => $estado]);
						return;
					}
				}
			} else {
				// Muestra no existe en la BD
				$estado = 2;

				echo json_encode(["estado" => $estado]);
				return;
			}
		}

		// 1.1 Validar que la muestra tengo análisis de AAS
		$id_detalle_x = "";

		$q_validar =
			"SELECT Id,
															 fechahora_recepcionlq
													FROM recepcion_ensayos_detalle
												 WHERE cod_interno = '" .
			$cod_interno .
			"'";

		if ($res_validar = mysqli_query($enlace, $q_validar)) {
			if (mysqli_num_rows($res_validar) > 0) {
				while ($row_validar = mysqli_fetch_assoc($res_validar)) {
					$id_detalle_x .= $row_validar["Id"] . ", ";
				}
			}
		}

		if (strlen($id_detalle_x) > 0) {
			$id_detalle_x = substr($id_detalle_x, 0, -2);
		}

		// Verifica si la muestra tiene análisis de AAS
		if (f_ValidaTieneAAS($id_detalle_x) == 0) {
			$estado = 3;

			echo json_encode(["estado" => $estado]);
			return;
		}

		// 2. Verificando si la muestra existe en el mismo rack
		$q_validar =
			"SELECT Id
													FROM analisislq_aas_cabecera
												 WHERE cod_interno = '" .
			$cod_interno .
			"'
													 AND id_rack = " .
			$id_rack .
			"
													 AND is_reanalisis = 0";

		if ($res_validar = mysqli_query($enlace, $q_validar)) {
			if (mysqli_num_rows($res_validar) > 0) {
				while ($row_validar = mysqli_fetch_assoc($res_validar)) {
					$estado = 5;

					echo json_encode([
						"estado" => $estado,
						"id_cabecera" => $row_validar["Id"],
					]);
					return;
				}
			}
		}

		// 3. Verificando que la muestra no exista en otro rack, si existe verifica si tiene reanálisis
		$continua = 0;
		$is_reanalisis = 0;
		$id_reanalisisde = 0;

		$q_validar =
			"SELECT Id,
															 tiene_reanalisis,
															 reanalisis_enrack
													FROM analisislq_aas_cabecera
												 WHERE cod_interno = '" .
			$cod_interno .
			"'
													 AND id_rack <> " .
			$id_rack .
			"
													 AND is_reanalisis = 0";

		if ($res_validar = mysqli_query($enlace, $q_validar)) {
			if (mysqli_num_rows($res_validar) > 0) {
				while ($row_validar = mysqli_fetch_assoc($res_validar)) {
					// Si ya existe en otro rack y no tiene reanálisis
					if ($row_validar["tiene_reanalisis"] == 0) {
						$estado = 6;

