																		 D.nombre_muestra,
																		 TM.descripcion AS TIPO_MUESTRA,
																		 EM.descripcion AS ESTADO_MUESTRA
																FROM recepcion_ensayos_detalle D
																		 INNER JOIN tbconfig_tiposmuestra TM ON D.cod_tipomuestra = TM.Id
																		 INNER JOIN tbconfig_estadosmuestra EM ON D.cod_estadomuestra = EM.Id
															 WHERE D.cod_interno = '" .
					$cod_interno .
					"'";

				if ($res_datos = mysqli_query($enlace, $q_datos)) {
					if (mysqli_num_rows($res_datos) > 0) {
						while ($row_datos = mysqli_fetch_assoc($res_datos)) {
							$id_detalle = $row_datos["Id"];
							$nom_muestra = $row_datos["nombre_muestra"];
							$tipo_muestra = $row_datos["TIPO_MUESTRA"];
							$estado_muestra = $row_datos["ESTADO_MUESTRA"];

							// Obtiene los análisis de cada muestra
							$analisis = "";

							// 1. Obtiene análisis de Precios Generales
							$q_analisis =
								"SELECT CONCAT(EA.abv, CASE WHEN LENGTH(IFNULL(C.abv, '')) > 0 THEN CONCAT(' ', C.abv) ELSE '' END) AS abv,
																									REA.total
																						 FROM recepcion_ensayos_analisis REA
																									INNER JOIN tb_ensayos_analisisclasificaciones_detalle ACD ON REA.cod_analisis = ACD.Id
																									INNER JOIN tb_ensayos_analisisclasificaciones C ON ACD.cod_clasificacion = C.Id
																									INNER JOIN tb_ensayos_analisis EA ON ACD.cod_analisis = EA.Id
																						WHERE REA.id_detalle = " .
								$row_datos["Id"] .
								"
																							AND is_paquete = 0
																							AND is_paquetecliente = 0
																					 ORDER BY EA.orden";

							if (
								$res_analisis = mysqli_query(
									$enlace,
									$q_analisis
								)
							) {
								if (mysqli_num_rows($res_analisis) > 0) {
									while (
										$row_analisis = mysqli_fetch_array(
											$res_analisis
										)
									) {
										$analisis .=
											"            " .
											$row_analisis["abv"] .
											" - ";
									}
								}
							}

							// 2. Obtiene análisis de Paquetes Generales
							$q_paquetes =
								"SELECT C.abv,
																									C.descripcion AS CLASIFICACION,
																									REA.cod_analisis,
																									REA.total,
																									REA.is_paquete,
																									REA.is_paquetecliente
																						 FROM recepcion_ensayos_analisis REA
																									INNER JOIN tb_ensayos_analisisclasificaciones_paquetes P ON REA.cod_analisis = P.Id
																									INNER JOIN tb_ensayos_analisisclasificaciones C ON P.cod_clasificacion = C.Id
																						WHERE REA.id_detalle = " .
								$row_datos["Id"] .
								"
																							AND REA.is_paquete = 1";

							if (
								$res_paquetes = mysqli_query(
									$enlace,
									$q_paquetes
								)
							) {
								if (mysqli_num_rows($res_paquetes) > 0) {
									while (
										$row_paquetes = mysqli_fetch_array(
											$res_paquetes
										)
									) {
										// Armando la descripción de análisis por paquete
										$abv = "";
										$descripcion = "";

										$q_analisispaquete =
											"SELECT A.abv,
