		$fecha_inicio = mysqli_real_escape_string(
			$enlace,
			$_POST["fecha_inicio"]
		);
		$fecha_fin = mysqli_real_escape_string($enlace, $_POST["fecha_fin"]);
		$filtro_condicioningreso = mysqli_real_escape_string(
			$enlace,
			$_POST["filtro_condicioningreso"]
		);
		$filtro_transportista = mysqli_real_escape_string(
