																	CONCAT(L.cod_lote, '|', IFNULL(L.num_parte, '')) AS ccod_Lote,
																	'' AS MD5_LOTE,
																	'' AS FECHAHORA_CREACIONLOTE,
																	L.num_ticketbalanza AS nNro_ticketsBalanza,
																	'' AS item_ticketbalanza,
																	L.peso_tara AS nPeso_InicialBalanza,
