																	SUBSTRING(L.peso_tara_fechahoraregistro, 12, 5) AS tHoraInicialBalanza,
																	'' AS pesoinicial_observacion,
																	L.peso_tara_usuarioregistro AS USUARIO_INICIO,
																	L.peso_bruto AS nPeso_FinalBalanza,
