																	 IFNULL(V.unidad_capacidad, U.nCapacidad) AS unidad_capacidad,
																	 IFNULL(V.unidad_tara, U.nTara) AS unidad_tara,
																	 IFNULL(V.unidad_idmarca, U.id_marca) AS unidad_idmarca,
																	 IFNULL(V.balanza_id_tipovehiculo, U.id_tipovehiculo) AS unidad_idtipovehiculo,
																	 V.despacho_color,

