			mysqli_real_escape_string($enlace, $_POST["cod_modalidadenvio"])
		);

		// Obtiene datos
		$d = 1;
		$id_lote = 0;

		$q_datos =
			"SELECT V.Id,
													 V.lote_cod_lote,
													 V.lote_ticket_orden,
													 V.codigo_gel,
													 IFNULL(EM.nombres, '---') AS ENCARGADO_MUESTRA,
													 IFNULL(PM.razon_social, '---') AS PROVEEDOR_MINERO,
													 IFNULL(ME.descripcion, '---') AS MODALIDAD_ENVIO,
													 IFNULL(HC.cierre_prom, '') AS HUMEDAD,
													 SUM(V.lote_peso_neto) AS NETO_TMH
											FROM despachos_primertramo_validaciondatos V
													 LEFT JOIN tbconfig_encargadosmuestra EM ON V.lote_id_encargadomuestra = EM.Id
													 LEFT JOIN tb_clientes PM ON V.lote_id_proveedorminero = PM.Id
													 " .
			($id_planta == 16 ? "LEFT" : "INNER") .
			" JOIN tbconfig_modalidadenvio ME ON V.despacho_id_modalidadenvio = ME.Id
													 LEFT JOIN analisislq_humedad_cabecera HC ON V.lote_cod_lote = HC.cod_interno
															AND HC.is_cierre = 1
										 WHERE 1 = 1";

		// Si es Planta de MINERAL RETIRADO
		if ($id_planta == 16) {
			$q_datos .= "   AND V.despacho_id_estadolote = 5";
		} else {
			$q_datos .= "   AND V.despacho_id_estadolote = 4";
		}

		$q_datos .=
			"   AND despacho_id_destinoplanta = " .
			$id_planta .
			"
													AND V.Id NOT IN (SELECT id_validaciondatos
																						 FROM despachos_segundotramo_programacion_detalle)";

