		}

		if (strlen($cod_modalidadenvio) > 0) {
			$q_datos .=
				"   AND V.despacho_id_modalidadenvio = " . $cod_modalidadenvio;
		}

		$q_datos .=
			" GROUP BY V.Id, V.lote_cod_lote, V.lote_ticket_orden, V.codigo_gel";

