					$html .= "    " . $row_datos["lote_ticket_orden"];
					$html .= "  </td>";

					$html .=
						'  <td style="border: solid; border-width: 1px; border-color: #D9D9D9; vertical-align: middle; text-align: center; font-weight: bold; ">';
					$html .= "    " . $row_datos["codigo_gel"];
					$html .= "  </td>";

					$html .=
						'  <td style="border: solid; border-width: 1px; border-color: #D9D9D9; vertical-align: middle; text-align: center;">';
					$html .= "    " . $row_datos["ENCARGADO_MUESTRA"];
					$html .= "  </td>";

					$html .=
						'  <td style="border: solid; border-width: 1px; border-color: #D9D9D9; vertical-align: middle; text-align: center;">';
