	case "get_DespachosProgramacion_ListaProgramaciones":
		$res = [];
		$estado = 0;
		$d = 1;

		// Recuperando parámetros
		$id_planta = mysqli_real_escape_string($enlace, $_POST["id_planta"]);
		$fecha_inicio = mysqli_real_escape_string(
			$enlace,
			$_POST["fecha_inicio"]
		);
		$fecha_fin = mysqli_real_escape_string($enlace, $_POST["fecha_fin"]);
		$estado_cierre = mysqli_real_escape_string(
			$enlace,
			$_POST["estado_cierre"]
		);
		$filtro_codigodespacho = $_POST["filtro_codigodespacho"];
		$filtro_lote = $_POST["filtro_lote"];

		// Setea Filtro de Lotes
		$l = 0;
		$arr_lotes = "";

		if (isset($filtro_lote) && is_array($filtro_lote)) {
			while ($l < count($filtro_lote)) {
				$arr_lotes .= "'" . $filtro_lote[$l] . "', ";

				$l++;
			}

			if (strlen($arr_lotes) > 0) {
				$arr_lotes = substr($arr_lotes, 0, -2);
			}
		}

		// Setea Filtro de Despachos
		$l = 0;
		$arr_codigosdespacho = "";

		if (isset($filtro_codigodespacho) && is_array($filtro_codigodespacho)) {
			while ($l < count($filtro_codigodespacho)) {
				$arr_codigosdespacho .=
					"'" . $filtro_codigodespacho[$l] . "', ";

				$l++;
			}

			if (strlen($arr_codigosdespacho) > 0) {
				$arr_codigosdespacho = substr($arr_codigosdespacho, 0, -2);
			}
		}

		// Obtiene datos
		$x = 1;
		$d = 1;
		$p = 0;
		$id_prog = 0;
		$id_programacion = 0;
		$is_cerrado = 0;
		$html = "";

		$q_datos =
			"SELECT P.Id,
													 MD5(P.Id) AS ID_MD5,
													 PD.Id AS ID_DETALLE,
													 P.fechahora_registro,
													 P.usuario_registro,
													 /*PD.cod_lote,*/
													 VD.lote_cod_lote,
													 VD.lote_ticket_orden,
													 VD.codigo_gel,
													 PD.codigo_despacho,
													 PD.codigo_despacho_comercializacion,
													 IFNULL(PD.codigo_planta, '') AS CODIGO_PLANTA,
													 P.is_cerrado,
													 P.cerrado_fechahoraregistro,
													 P.cerrado_usuarioregistro,
													 P.fechaestimada_despacho,
														
													 (SELECT COUNT(PD_x.Id)
															FROM despachos_segundotramo_programacion_detalle PD_x
														 WHERE PD_x.id_programacion = P.Id) AS TOTAL_LOTES,

													(SELECT SUM(VD.lote_peso_neto)
															FROM despachos_primertramo_validaciondatos VD
														 WHERE VD.Id = PD.id_validaciondatos) AS TOTAL_TMH,

													 (SELECT AVG(HC.cierre_prom)
															FROM analisislq_humedad_cabecera HC
														 WHERE HC.cod_interno = PD.cod_lote) AS HUMEDAD,

													 (SELECT SUM(peso_distribuido)
															FROM despachos_segundotramo_distribucion_lotes DL
														 WHERE DL.id_validaciondatos = PD.id_validaciondatos) AS TOTAL_DISTRIBUIDO

											FROM despachos_segundotramo_programacion P
													 INNER JOIN despachos_segundotramo_programacion_detalle PD ON P.Id = PD.id_programacion
													 INNER JOIN despachos_primertramo_validaciondatos VD ON PD.id_validaciondatos = VD.Id
										 WHERE P.id_planta = " . $id_planta;

		if (strlen($arr_lotes) > 0 || strlen($arr_codigosdespacho) > 0) {
			if (strlen($arr_lotes) > 0) {
				$q_datos .=
					"   AND P.Id IN (SELECT PD_x.id_programacion
																						 FROM despachos_segundotramo_programacion_detalle PD_x
																						WHERE PD_x.Id IN (" .
					$arr_lotes .
					"))";
			}

			if (strlen($arr_codigosdespacho) > 0) {
				$q_datos .=
					"   AND PD.codigo_despacho IN (" .
					$arr_codigosdespacho .
					")";
			}
		} else {
			$q_datos .=
				"   AND DATE(P.fechahora_registro) BETWEEN '" .
				$fecha_inicio .
				"' AND '" .
				$fecha_fin .
				"'";

			if (strlen($estado_cierre) > 0) {
				$q_datos .= "   AND P.is_cerrado = " . $estado_cierre;
			}
		}

		$q_datos .= " ORDER BY P.fechahora_registro, VD.codigo_gel";

		if ($res_datos = mysqli_query($enlace, $q_datos)) {
			if (mysqli_num_rows($res_datos) > 0) {
				$estado = 1;

				while ($row_datos = mysqli_fetch_array($res_datos)) {
					$html .= '<tr style="font-size: 14px;">';

					if ($id_prog != $row_datos["Id"]) {
						$p++;

						$is_cerrado = $row_datos["is_cerrado"];

						if ($x == 1) {
							$id_programacion = $row_datos["Id"];
						}

						$html .=
							'  <td rowspan="' .
							$row_datos["TOTAL_LOTES"] .
							'" style="border: solid; border-width: 1px; border-color: #D9D9D9; vertical-align: middle; text-align: center; background-color: #ffffff;">';
						$html .= "    " . $x;
						$html .=
							'    <input id="id_prog_' .
							$x .
							'" type="hidden" value="' .
							$row_datos["Id"] .
							'">';
						$html .= "  </td>";

						$html .=
							'  <td rowspan="' .
							$row_datos["TOTAL_LOTES"] .
							'" style="border: solid; border-width: 1px; border-color: #D9D9D9; vertical-align: middle; text-align: center; background-color: #ffffff; font-size: 12px;">';

						$html .=
							'  	<div class="d-flex justify-content-center">';
						$html .=
							'  		<label class="is_programacerrado_' .
							$p .
							'" style="border: solid; border-width: 1px; border-color: #D9D9D9; border-radius: 7px; padding-left: 6px; padding-right: 6px; padding-bottom: 1px; background-color: #FF5F5D; color: #ffffff; font-weight: bold; cursor: pointer; ' .
							($is_cerrado == 1 ? "display: none;" : "") .
							'" onclick="f_EliminarProgramacion(' .
							$x .
							", " .
							$row_datos["Id"] .
							", '" .
							$row_datos["fechahora_registro"] .
							"', '" .
							$row_datos["usuario_registro"] .
							"'" .
							')">X</label>';

						$html .=
							'  		<label class="is_programacerrado_' .
							$p .
							'" style="border: solid; border-width: 1px; border-color: #D9D9D9; border-radius: 7px; padding-left: 6px; padding-right: 6px; padding-bottom: 1px; background-color: #0D6EFD; color: #ffffff; font-weight: bold; cursor: pointer; margin-left: 5px; ' .
							($is_cerrado == 1 ? "display: none;" : "") .
							'" onclick="f_AddProgramacion(' .
							"'E', " .
							$x .
							", " .
							$row_datos["Id"] .
							')">+ Lote</label>';
						$html .= "  	</div>";

						if ($id_planta != 16) {
							$html .=
								'  	<div class="d-flex justify-content-center" hidden>';
							// $html .= '  		<label class="is_programacerrado_'.$p.'" style="border: solid; border-width: 1px; border-color: #D9D9D9; border-radius: 7px; margin-top: 5px; padding: 3px; padding-left: 6px; padding-right: 6px; padding-bottom: 4px; background-color: #ffc107; font-weight: bold; cursor: pointer; '.(($is_cerrado == 1) ? 'display: none;' : '').'" onclick="f_AddLoteAUM('."'N', ".$row_datos["Id"].', '.$x.')">+ Lote AUM</label>';
							$html .= "  	</div>";
						}

						if ($is_cerrado == 1) {
							$html .=
								'  	<div class="d-flex justify-content-center">';
							$html .=
								'			<img src="' .
								$img_informe .
								'" style="width: 20px;"/>';
							$html .=
								'  		<a class="success" style="margin-left: 5px;" href="javascript: f_PrintDistribucionDespachos(' .
								"'" .
								$row_datos["ID_MD5"] .
								"'" .
								')"><u>Distribución </u></a>';
							$html .= "  	</div>";
						}

						$html .= "  </td>";

						$html .=
							'  <td id="td_prog_' .
							$x .
							'" rowspan="' .
							$row_datos["TOTAL_LOTES"] .
							'" style="border: solid; border-width: 1px; border-color: #D9D9D9; vertical-align: middle; text-align: center; cursor: pointer; ' .
							($x == 1 ? "background-color: #FFF587;" : "") .
							'" onclick="f_LoadItemProgramacion(' .
							$x .
							", " .
							$row_datos["Id"] .
							');">';
						$html .=
							"    " . $row_datos["fechahora_registro"] . "<br>";
						$html .=
							'    <label style="cursor: pointer;"><i>' .
							$row_datos["usuario_registro"] .
							"</i></label>";
						$html .= "  </td>";
					}

					$html .=
						'  <td style="border: solid; border-width: 1px; border-color: #D9D9D9; vertical-align: middle; text-align: center; background-color: #ffffff; font-weight: bold; font-size: 12px;">';

					$html .=
						'  	<label class="is_programacerrado_' .
						$p .
						'" style="border: solid; border-width: 1px; border-color: #D9D9D9; border-radius: 7px; padding-left: 6px; padding-right: 6px; padding-bottom: 1px; background-color: #FF5F5D; color: #ffffff; font-weight: bold; cursor: pointer; ' .
						($is_cerrado == 1 ? "display: none;" : "") .
						'" onclick="f_EliminarProgramacion_Lote(' .
						$x .
						", " .
						$row_datos["ID_DETALLE"] .
						", '" .
						(strlen($row_datos["codigo_gel"]) == 0
							? $row_datos["lote_cod_lote"] .
							(strlen($row_datos["lote_ticket_orden"]) == 0
								? ""
								: " - (" .
								$row_datos["lote_ticket_orden"] .
								")")
							: $row_datos["codigo_gel"]) .
