																					 ELSE PD.id_modalidadenvio END AS id_modalidadenvio,
																								
																					 CASE WHEN PD.id_planta = 3
																						 THEN ME_x.descripcion
																					 ELSE ME.descripcion END AS MODALIDAD_ENVIO,

																					 PD.codigo_despacho,
																					 PD.codigo_despacho_comercializacion,
																					 P.fechaestimada_despacho,
																					 U.id_unidad,
																					 IFNULL(DL.guias_placa1, UN.cplaca) AS guias_placa1,
																					 PD.cod_lote,
																					 /*0 AS ID_PROVEEDOR_MINERO,
																					 '---' AS PROVEEDOR_MINERO,*/
																					 V.lote_id_proveedorminero AS ID_PROVEEDOR_MINERO,
																					 CONCAT(PM.documento, ' - ', PM.razon_social) AS PROVEEDOR_MINERO,
																					 DL.guiaremitente_serie,
																					 DL.guiaremitente_numero,
																					 DL.guiatransportista_numero

																			FROM despachos_segundotramo_programacion_detalle PD
																					 INNER JOIN despachos_segundotramo_programacion P ON PD.id_programacion = P.Id
																					 INNER JOIN despachos_segundotramo_distribucion_unidades U ON P.Id = U.id_programacion
																					 INNER JOIN despachos_segundotramo_distribucion_lotes DL ON U.Id = DL.id_distribucionunidad
																						 AND PD.id_validaciondatos = DL.id_validaciondatos
																					 INNER JOIN transporte UN ON U.id_unidad = UN.id_transporte
																					 INNER JOIN tbconfig_plantas PL ON PD.id_planta = PL.Id
																					 LEFT JOIN tbconfig_modalidadenvio ME ON PD.id_modalidadenvio = ME.Id
																					 LEFT JOIN despachos_primertramo_validaciondatos V ON PD.cod_lote = V.lote_cod_lote
																					 LEFT JOIN tbconfig_modalidadenvio ME_x ON V.despacho_id_modalidadenvio = ME_x.Id
																					 LEFT JOIN tb_clientes PM ON V.lote_id_proveedorminero = PM.Id
