																			 AND (CASE WHEN PD.id_planta = 3
																						 THEN V.despacho_id_modalidadenvio
																					 ELSE PD.id_modalidadenvio END IN (3, 4, 5))

																		 UNION

																		 SELECT DISTINCT
																					 U.Id AS ID_DISTRIBUCIONUNIDAD,
																					 PD.id_planta,
																					 PL.nombre_comercial AS PLANTA_DESTINO,

																					 CASE WHEN PD.id_planta = 3
																						 THEN V.despacho_id_modalidadenvio
