	case "grabar_SegundoTramo_Resumen_EditLlegadaPlanta":
		$estado = 0;

		// Recupera variables
		$item = $_POST["item"];
		$id_registro = $_POST["id_registro"];
		$valor = $_POST["valor"];
		$usuario_registro = $_SESSION["usu_usuario"];

		// Seteando campos
		$valor = strlen(trim($valor)) == 0 ? "NULL" : "'" . trim($valor) . "'";

		if ($item == 1) {
			$campo = "llegadaplanta_codigoplanta";
		}

		if ($item == 2) {
			$campo = "llegadaplanta_fechaingreso";
		}

		if ($item == 3) {
			$campo = "llegadaplanta_codigopesaje";
		}

		if ($item == 4) {
			$campo = "llegadaplanta_pesonetoplanta";
		}

		if ($item == 5) {
			$campo = "llegadaplanta_humedadplanta";
		}

		if ($item == 6) {
			$campo = "llegadaplanta_pesoseco";
		}

		if ($item == 7) {
			$campo = "llegadaplanta_pesobrutoplanta";
		}

		if ($item == 8) {
			$campo = "llegadaplanta_pesotaraplanta";
		}

		// Guarda datos
		$q_save = "UPDATE despachos_segundotramo_distribucion_lotes SET ";
		$q_save .= $campo . " = " . $valor . ", ";
		$q_save .= $campo . "_fechahoraregistro = '" . $g_fecha . "', ";
		$q_save .= $campo . "_usuarioregistro = '" . $usuario_registro . "'";
		$q_save .= " WHERE Id = " . $id_registro;

		if ($res_save = mysqli_query($enlace, $q_save)) {
			$estado = 1;

			// Actualizando Peso Neto
			if ($item == 7 || $item == 8) {
				$q_update =
					"UPDATE despachos_segundotramo_distribucion_lotes SET";
				$q_update .=
					"  llegadaplanta_pesonetoplanta = llegadaplanta_pesobrutoplanta - llegadaplanta_pesotaraplanta";
				$q_update .= " WHERE Id = " . $id_registro;

				if ($res_update = mysqli_query($enlace, $q_update)) {
					if ($valor != "NULL") {
						// Actualiza el Peso Seco
						$valor = 0;

						$q_humedad =
							"SELECT llegadaplanta_humedadplanta
																		FROM despachos_segundotramo_distribucion_lotes
																	 WHERE Id = " . $id_registro;

						if ($res_humedad = mysqli_query($enlace, $q_humedad)) {
							if (mysqli_num_rows($res_humedad) > 0) {
								while (
									$row_humedad = mysqli_fetch_array(
										$res_humedad
									)
								) {
									$valor =
										$row_humedad[
											"llegadaplanta_humedadplanta"
										];

									if (strlen($valor) > 0) {
										$item = 5;
									}
								}
							}
						}
