															 AND (YEAR(L.tFechaInicialBalanza) >= 2024
																OR V.lote_cod_lote IN ('AUM-2587', 'AUM-3000', 'AUM-2337', 'AUM-2585', 'AUM-2907', 'AUM-2980'))";

		if (strlen($fecha_inicio) > 0) {
