					$html .= "  </td>";

					// Seteo de columnas de Cierre
					$html .=
						'  <td id="td_cierre_1_' .
						$d .
						'" style="border: solid; border-width: 1px; border-color: #D9D9D9; 	vertical-align: middle; text-align: center;">';

					if ($row_datos["is_cerradolote"] == 0) {
						$html .=
							'		<input id="chk_cierre_' .
							$d .
							'" class="form-check-input chk_cierre" type="checkbox" style="transform: scale(1.5);">';
					} else {
						$html .=
							'		<label style="font-style: italic; color: #F23030; cursor: pointer;" onclick="f_Reabrir(' .
							$d .
							", " .
							$row_datos["Id"] .
							')"><u> Reabrir </u></label>';
					}

					$html .= "  </td>";

					$html .=
						'  <td id="td_cierre_2_' .
						$d .
						'" style="border: solid; border-width: 1px; border-color: #D9D9D9; vertical-align: middle; text-align: center;">';

					if ($row_datos["is_cerradolote"] == 1) {
						$html .=
							"		" . $row_datos["cerradolote_fechahoraregistro"];
					}

					$html .= "  </td>";

					$html .=
						'  <td id="td_cierre_3_' .
						$d .
						'" style="border: solid; border-width: 1px; border-color: #D9D9D9; vertical-align: middle; text-align: center;">';

					if ($row_datos["is_cerradolote"] == 1) {
						$html .= "		" . $row_datos["cerradolote_usuarioregistro"];
					}

					$html .= "  </td>";

					$html .= "</tr>";

					$d++;
				}
			}
		}

		echo json_encode(["estado" => $estado, "html" => $html]);

		break;

	case "cierre_SegundoTramo_CierreLotes":
		$estado = 0;
		$arr_tickets = [];

		// Recupera parámetros
		$arr_idlotes = trim($_POST["arr_idlotes"]);
		$usuario_registro = $_SESSION["usu_usuario"];

		// Grabando cierre
		$q_update = "UPDATE despachos_segundotramo_distribucion_lotes";
		$q_update .= "  SET is_cerradolote = 1, ";
		$q_update .= "			cerradolote_fechahoraregistro = '" . $g_fecha . "', ";
		$q_update .=
			"			cerradolote_usuarioregistro = '" . $usuario_registro . "'";
		$q_update .= " WHERE Id IN (" . $arr_idlotes . ")";

		if ($res_update = mysqli_query($enlace, $q_update)) {
			$estado = 1;

			// Migrando Lotes cerrados a la tabla de datos Consolidados
			f_MigrarLotes_CierreContable(
				$enlace,
				2,
				$arr_idlotes,
				$g_fecha,
				$usuario_registro
			);

			// Devuelve los números de ticket para ser actualizados
			$q_tickets =
				"SELECT id_registro,
																 num_ticketbalanza
														FROM consolidado_lotes_cierrecontable
													 WHERE id_registro IN (" .
				$arr_idlotes .
				")
														 AND id_tipoingreso = 2";

			if ($res_tickets = mysqli_query($enlace, $q_tickets)) {
				if (mysqli_num_rows($res_tickets) > 0) {
					while ($row_tickets = mysqli_fetch_array($res_tickets)) {
						array_push($arr_tickets, $row_tickets);
					}
				}
			}
		}

		echo json_encode([
			"estado" => $estado,
			"cerrado_fechahoraregistro" => $g_fecha,
			"cerrado_usuarioregistro" => $usuario_registro,
			"arr_tickets" => $arr_tickets,
		]);

