			$q_delete = "DELETE FROM consolidado_lotes_cierrecontable";
			$q_delete .= " WHERE id_tipoingreso = 2";
			$q_delete .= "   AND id_registro = " . $id_registro;

			if ($res_delete = mysqli_query($enlace, $q_delete)) {
			}
		}

		echo json_encode(["estado" => $estado]);

		break;

