	case "get_ConfiguracionVehicular":
		$estado = 0;
		$res = [];

		// Recupera parámetros
		$id_distribucionunidad = $_POST["id_distribucionunidad"];
		$remitente_ruc = $_POST["remitente_ruc"];

		// Obtiene datos
		$q_datos =
			"SELECT CV.Id,
													 CONCAT(DU.id_configuracionvehicular, '|', CV.pesobruto_maximopermitido, '|', CV.tiene_ingresomanual) AS ID_CONFIGURACIONVEHICULAR,
													 DU.configuracionvehicular_pesobrutomaximo,
													 DU.configuracionvehicular_pesobrutomaximo2,
													 DU.configuracionvehicular_pesobrutototaltransportado
											FROM despachos_segundotramo_distribucion_unidades DU
													 LEFT JOIN tbconfig_configuracionvehicular CV ON DU.id_configuracionvehicular = CV.Id
										WHERE DU.Id = " . $id_distribucionunidad;

		if ($res_datos = mysqli_query($enlace, $q_datos)) {
			if (mysqli_num_rows($res_datos) > 0) {
				$estado = 1;

				while ($row_datos = mysqli_fetch_array($res_datos)) {
					array_push($res, $row_datos);
				}
			}
		}

		// Obtiene Toneladas Distribuídas
		$q_toneladas =
			"SELECT DL.peso_bruto
													FROM despachos_segundotramo_programacion_detalle PD
															 INNER JOIN despachos_segundotramo_programacion P ON PD.id_programacion = P.Id
															 INNER JOIN despachos_segundotramo_distribucion_unidades U ON P.Id = U.id_programacion
															 INNER JOIN despachos_segundotramo_distribucion_lotes DL ON U.Id = DL.id_distribucionunidad
																 AND PD.cod_lote = DL.cod_lote
															 INNER JOIN tbconfig_remitentessegundotramo RE ON DL.guias_iddestino = RE.id_destino
																 AND DL.guias_idmodalidadenvio = RE.id_modalidadenvio
												 WHERE U.Id = '" .
			$id_distribucionunidad .
			"'
													 AND RE.ruc = '" .
			$remitente_ruc .
			"'
													 AND DL.guiaremitente_serie IS NOT NULL
											 ORDER BY DL.peso_bruto DESC LIMIT 1";

		if ($res_toneladas = mysqli_query($enlace, $q_toneladas)) {
			if (mysqli_num_rows($res_toneladas) > 0) {
				while ($row_toneladas = mysqli_fetch_array($res_toneladas)) {
					$peso_distribuido = $row_toneladas["peso_bruto"] * 1000;
				}
			}
		}

		echo json_encode([
			"estado" => $estado,
			"res" => $res,
			"peso_distribuido" => $peso_distribuido,
		]);

		break;

	case "grabar_ConfiguracionVehicular_PesosyMedidas":
