			"   configuracionvehicular_usuarioregistro = '" .
			$usuario_registro .
			"'";
		$q_save .= " WHERE Id = " . $id_distribucionunidad;

		if ($res_save = mysqli_query($enlace, $q_save)) {
			$estado = 1;

			// Obtiene el/los remitentes por Unidad
			$q_remitentes =
				"SELECT DISTINCT
																		RE.ruc,
																		RE.razon_social
															 FROM despachos_segundotramo_programacion_detalle PD
																		INNER JOIN despachos_segundotramo_programacion P ON PD.id_programacion = P.Id
																		INNER JOIN despachos_segundotramo_distribucion_unidades U ON P.Id = U.id_programacion
																		INNER JOIN despachos_segundotramo_distribucion_lotes DL ON U.Id = DL.id_distribucionunidad
																			AND PD.cod_lote = DL.cod_lote
																		LEFT JOIN tbconfig_remitentessegundotramo RE ON DL.guias_iddestino = RE.id_destino
																			AND DL.guias_idmodalidadenvio = RE.id_modalidadenvio
															WHERE U.Id = " . $id_distribucionunidad;

			if ($res_remitentes = mysqli_query($enlace, $q_remitentes)) {
				if (mysqli_num_rows($res_remitentes) > 0) {
					$estado = 1;

					while (
						$row_remitentes = mysqli_fetch_array($res_remitentes)
					) {
						array_push($res, $row_remitentes);
					}
				}
			}
		}

		echo json_encode(["estado" => $estado, "res" => $res]);

		break;

	case "get_GestionTransporte_ListaUnidades":
		$res = [];
		$estado = 0;
		$d = 1;

		// Recuperando parámetros
		$id_planta = mysqli_real_escape_string($enlace, $_POST["id_planta"]);
		$fecha_inicio = mysqli_real_escape_string(
			$enlace,
			$_POST["fecha_inicio"]
		);
		$fecha_fin = mysqli_real_escape_string($enlace, $_POST["fecha_fin"]);
		$estado_cierre = mysqli_real_escape_string(
			$enlace,
			$_POST["estado_cierre"]
		);
		$filtro_codigodespacho = $_POST["filtro_codigodespacho"];
		$filtro_lote = $_POST["filtro_lote"];

		// Setea Filtro de Lotes
		$l = 0;
		$arr_lotes = "";

		if (isset($filtro_lote) && is_array($filtro_lote)) {
			while ($l < count($filtro_lote)) {
				$arr_lotes .= "'" . $filtro_lote[$l] . "', ";

				$l++;
			}

			if (strlen($arr_lotes) > 0) {
				$arr_lotes = substr($arr_lotes, 0, -2);
			}
		}

		// Setea Filtro de Despachos
		$l = 0;
		$arr_codigosdespacho = "";

		if (isset($filtro_codigodespacho) && is_array($filtro_codigodespacho)) {
			while ($l < count($filtro_codigodespacho)) {
				$arr_codigosdespacho .=
					"'" . $filtro_codigodespacho[$l] . "', ";

				$l++;
			}

			if (strlen($arr_codigosdespacho) > 0) {
				$arr_codigosdespacho = substr($arr_codigosdespacho, 0, -2);
			}
		}

		// Obtiene datos
		$d = 1;
		$html = "";

		$q_datos =
			"SELECT DATOS.ID_UNIDAD,
													 DATOS.codigo_despacho,
													 DATOS.codigo_despacho_comercializacion,
													 DATOS.guias_idmodalidadenvio AS ID_MODALIDAD_ENVIO,
													 DATOS.MODALIDAD_ENVIO,
													 DATOS.FECHAHORA_SALIDA,
													 /*DATOS.FECHA_LLEGADAPLANTA,*/
													 DATOS.TIPO_VEHICULO,
													 DATOS.PLACA1,
													 DATOS.PLACA2,
													 DATOS.TRANSPORTISTA_RUC,
													 DATOS.TRANSPORTISTA_RAZONSOCIAL,
													 MO.abv AS MONEDA_ABV,
													 IFNULL(LC.tarifa, TT.tarifa_sin_igv) AS tarifa_sin_igv,
													 COORDINADOR_TRANSPORTE,
													 guias_remitenteruc,
													 LC.Id AS ID_CIERRE,
													 MD5(LC.Id) AS ID_CIERRE_MD5,
													 LC.fechahora_registro AS FECHAHORA_CERRE,
													 LC.usuario_registro AS USUARIO_CIERRE,

													 SUM(llegadaplanta_pesonetoplanta) AS TMH_TOTAL

											FROM (SELECT DISTINCT
																	 U.Id AS ID_UNIDAD,
																	 PD.codigo_despacho,
																	 PD.codigo_despacho_comercializacion,

																	 DL.guias_idmodalidadenvio,
																	 ME.descripcion AS MODALIDAD_ENVIO,
				 
																	 (SELECT CI.fechahora_salida
																			FROM controlingresovehiculo CI
																		 WHERE CI.placa = UN.cplaca
																			 AND CI.dFechaIngreso BETWEEN U.fecha_ingresoplanta AND P.fechaestimada_despacho
																		ORDER BY CI.fechahora_salida DESC
																		LIMIT 1) AS FECHAHORA_SALIDA,
																		
																	 DATE(DL.llegadaplanta_fechaingreso) AS FECHA_LLEGADAPLANTA,
																	 TV.descripcion AS TIPO_VEHICULO,
																	 UN.cplaca AS PLACA1,
																	 UN2.cplaca AS PLACA2,
																	 TR.documento AS TRANSPORTISTA_RUC,
																	 TR.razon_social AS TRANSPORTISTA_RAZONSOCIAL,
																	 DL.llegadaplanta_pesonetoplanta,
																	 PD.id_planta,
																	 U.id_coordinadortransporte,
																	 CT.nombres AS COORDINADOR_TRANSPORTE,
																	 DL.guias_remitenteruc
															FROM despachos_segundotramo_programacion_detalle PD
																	 INNER JOIN despachos_segundotramo_programacion P ON PD.id_programacion = P.Id
																	 INNER JOIN despachos_segundotramo_distribucion_unidades U ON P.Id = U.id_programacion
																	 INNER JOIN despachos_segundotramo_distribucion_lotes DL ON U.Id = DL.id_distribucionunidad
																		 AND PD.cod_lote = DL.cod_lote
																	 INNER JOIN transporte UN ON U.id_unidad = UN.id_transporte
																	 LEFT JOIN transporte UN2 ON U.id_unidad2 = UN2.id_transporte
																	 INNER JOIN tb_clientes TR ON UN.id_Transportista = TR.Id
																	 INNER JOIN tbconfig_plantas PL ON PD.id_planta = PL.Id
																	 LEFT JOIN tbconfig_modalidadenvio ME ON DL.guias_idmodalidadenvio = ME.Id
																	 INNER JOIN tbconfig_tipovehiculo TV ON UN.id_tipovehiculo = TV.Id
																	 LEFT JOIN tbconfig_coordinadorestransporte CT ON U.id_coordinadortransporte = CT.Id
														 WHERE DL.is_complemento = 0
															 AND DL.guias_fecha IS NOT NULL
															 AND P.id_planta = " . $id_planta;

		if (strlen($arr_lotes) > 0 || strlen($arr_codigosdespacho) > 0) {
			if (strlen($arr_lotes) > 0) {
				$q_datos .=
					"   AND P.Id IN (SELECT PD_x.id_programacion
																					 FROM despachos_segundotramo_programacion_detalle PD_x
																					WHERE PD_x.cod_lote IN (" .
					$arr_lotes .
					"))";
			}

			if (strlen($arr_codigosdespacho) > 0) {
				$q_datos .=
					"   AND PD.codigo_despacho IN (" .
					$arr_codigosdespacho .
					")";
			}
		} else {
			$q_datos .=
				"   AND DATE(P.fechaestimada_despacho) BETWEEN '" .
				$fecha_inicio .
				"' AND '" .
				$fecha_fin .
				"'";

			// if (strlen($estado_cierre) > 0){
			// 	$q_datos .= "   AND P.is_cerrado = ".$estado_cierre;
			// }
		}

		$q_datos .= ") AS DATOS
										 LEFT JOIN tbconfig_tarifatransporte TT ON DATOS.id_coordinadortransporte = TT.id_coordinadortransporte
											 AND DATOS.id_planta = TT.id_planta
										 LEFT JOIN tbconfig_monedas MO ON TT.id_moneda = MO.Id
										 LEFT JOIN liquidaciones_transporte LC ON DATOS.codigo_despacho = LC.codigo_despacho
											 AND DATOS.guias_remitenteruc = LC.remitente_ruc
											 AND DATOS.PLACA1 = LC.placa
										 GROUP BY DATOS.ID_UNIDAD, DATOS.codigo_despacho, DATOS.codigo_despacho_comercializacion, DATOS.guias_idmodalidadenvio, DATOS.FECHAHORA_SALIDA, /*DATOS.FECHA_LLEGADAPLANTA,*/ DATOS.TIPO_VEHICULO, DATOS.PLACA1, DATOS.PLACA2, DATOS.TRANSPORTISTA_RUC, DATOS.TRANSPORTISTA_RAZONSOCIAL, MO.abv, TT.tarifa_sin_igv, COORDINADOR_TRANSPORTE, guias_remitenteruc
										 ORDER BY codigo_despacho";

		if ($res_datos = mysqli_query($enlace, $q_datos)) {
			if (mysqli_num_rows($res_datos) > 0) {
				$estado = 1;

				while ($row_datos = mysqli_fetch_array($res_datos)) {
					if ($d == 1) {
						$cod_despacho = $row_datos["codigo_despacho"];
						$id_unidad = $row_datos["ID_UNIDAD"];
						$id_modalidadenvio = $row_datos["ID_MODALIDAD_ENVIO"];
					}

					$is_cerrado = 0;

					if (strlen($row_datos["FECHAHORA_CERRE"]) > 0) {
						$is_cerrado = 1;
					}

					$html .=
						'<tr id="tr_detalle_' .
						$d .
						'" class="bg_selected bg_selected_' .
						$d .
						'" style="font-size: 14px; cursor: pointer; background-color: ' .
						($d == 1 ? "#FFF587" : "#ffffff") .
						';" onclick="f_LoadItemInformacionLotes(' .
						$d .
						", '" .
						$row_datos["codigo_despacho"] .
						"', " .
						$row_datos["ID_UNIDAD"] .
						", " .
						$row_datos["ID_MODALIDAD_ENVIO"] .
						')">';

					$html .=
						'  <td style="border: solid; border-width: 1px; border-color: #D9D9D9; vertical-align: middle; text-align: center;">';
					$html .= "    " . $d;
					$html .= "  </td>";

					$html .=
						'  <td style="border: solid; border-width: 1px; border-color: #D9D9D9; vertical-align: middle; text-align: center; font-weight: bold;">';
					$html .= "    " . $row_datos["codigo_despacho"];

					if (
						$row_datos["ID_MODALIDAD_ENVIO"] == 3 ||
						$row_datos["ID_MODALIDAD_ENVIO"] == 4 ||
						$row_datos["ID_MODALIDAD_ENVIO"] == 5
					) {
						$html .=
							" / " .
							$row_datos["codigo_despacho_comercializacion"];
					}

					$html .= "  </td>";

					$html .=
						'  <td style="border: solid; border-width: 1px; border-color: #D9D9D9; vertical-align: middle; text-align: center;">';
					$html .= "    " . $row_datos["MODALIDAD_ENVIO"];
					$html .= "  </td>";

					$html .=
						'  <td style="border: solid; border-width: 1px; border-color: #D9D9D9; vertical-align: middle; text-align: center;">';
					$html .=
						"    " . substr($row_datos["FECHAHORA_SALIDA"], 0, 10);
					$html .= "  </td>";

					$html .=
						'  <td style="border: solid; border-width: 1px; border-color: #D9D9D9; vertical-align: middle; text-align: center;">';
					$html .=
						"    " .
						substr($row_datos["llegadaplanta_fechaingreso"], 0, 10);
					$html .= "  </td>";

