																	 PD.id_planta,
																	 U.id_coordinadortransporte,
																	 CT.nombres AS COORDINADOR_TRANSPORTE,
																	 DL.guias_remitenteruc
															FROM despachos_segundotramo_programacion_detalle PD
																	 INNER JOIN despachos_segundotramo_programacion P ON PD.id_programacion = P.Id
																	 INNER JOIN despachos_segundotramo_distribucion_unidades U ON P.Id = U.id_programacion
																	 INNER JOIN despachos_segundotramo_distribucion_lotes DL ON U.Id = DL.id_distribucionunidad
																		 AND PD.cod_lote = DL.cod_lote
																	 INNER JOIN transporte UN ON U.id_unidad = UN.id_transporte
																	 LEFT JOIN transporte UN2 ON U.id_unidad2 = UN2.id_transporte
																	 INNER JOIN tb_clientes TR ON UN.id_Transportista = TR.Id
																	 INNER JOIN tbconfig_plantas PL ON PD.id_planta = PL.Id
																	 LEFT JOIN tbconfig_modalidadenvio ME ON DL.guias_idmodalidadenvio = ME.Id
																	 INNER JOIN tbconfig_tipovehiculo TV ON UN.id_tipovehiculo = TV.Id
																	 LEFT JOIN tbconfig_coordinadorestransporte CT ON U.id_coordinadortransporte = CT.Id
														 WHERE DL.is_complemento = 0
															 AND DL.guias_fecha IS NOT NULL";

		if (strlen($arr_lotes) > 0 || strlen($arr_codigosdespacho) > 0) {
			if (strlen($arr_lotes) > 0) {
				$q_datos .=
					"   AND P.Id IN (SELECT PD_x.id_programacion
																					 FROM despachos_segundotramo_programacion_detalle PD_x
																					WHERE PD_x.cod_lote IN (" .
					$arr_lotes .
					"))";
			}

			if (strlen($arr_codigosdespacho) > 0) {
				$q_datos .=
					"   AND PD.codigo_despacho IN (" .
					$arr_codigosdespacho .
					")";
			}
		} else {
			$q_datos .=
				"   AND DATE(P.fechaestimada_despacho) BETWEEN '" .
				$fecha_inicio .
				"' AND '" .
				$fecha_fin .
				"'";

			// if (strlen($estado_cierre) > 0){
			// 	$q_datos .= "   AND P.is_cerrado = ".$estado_cierre;
			// }
		}

		$q_datos .= ") AS DATOS
										 LEFT JOIN tbconfig_tarifatransporte TT ON DATOS.id_coordinadortransporte = TT.id_coordinadortransporte
											 AND DATOS.id_planta = TT.id_planta
										 LEFT JOIN tbconfig_monedas MO ON TT.id_moneda = MO.Id
										 LEFT JOIN liquidaciones_transporte LC ON DATOS.codigo_despacho = LC.codigo_despacho
											 AND DATOS.guias_remitenteruc = LC.remitente_ruc
											 AND DATOS.PLACA1 = LC.placa
										 LEFT JOIN tbconfig_tipopagocomprobante TPC ON LC.id_tipopagocomprobante = TPC.Id
										 GROUP BY DATOS.PLANTA, DATOS.ID_UNIDAD, DATOS.codigo_despacho, DATOS.codigo_despacho_comercializacion, DATOS.guias_idmodalidadenvio, DATOS.FECHAHORA_SALIDA, DATOS.FECHA_LLEGADAPLANTA, DATOS.TIPO_VEHICULO, DATOS.PLACA1, DATOS.PLACA2, DATOS.TRANSPORTISTA_RUC, DATOS.TRANSPORTISTA_RAZONSOCIAL, MO.abv, TT.tarifa_sin_igv, COORDINADOR_TRANSPORTE, guias_remitenteruc
										 ORDER BY DATOS.PLANTA, codigo_despacho";

		if ($res_datos = mysqli_query($enlace, $q_datos)) {
