	case "update_SegundoTramo_CierreLote":
		$estado = 0;

		// Recupera parámetros
		$id = trim($_POST["Id"]);
		$orden_campo = trim($_POST["orden_campo"]);
		$valor = trim($_POST["valor"]);
		$complemento_pesodistribuido = trim(
			$_POST["complemento_pesodistribuido"]
		);
		$usuario_registro = $_SESSION["usu_usuario"];

		// Seteando campo
		$campo = "";

		if ($orden_campo == 1) {
			$campo = "peso_bruto_fechahoraregistro";
		}

		if ($orden_campo == 2) {
			$campo = "observacion";
		}

		if ($orden_campo == 3) {
			$campo = "cierrelote_complementotara";
		}

		// Seteando query
		$q_save = "UPDATE despachos_segundotramo_distribucion_lotes";
		$q_save .=
			"  SET " .
			$campo .
			" = " .
			(strlen($valor) > 0 ? "'" . $valor . "'" : "NULL");

		// Campos de auditoría
		if ($orden_campo == 3) {
			$q_save .=
				", " .
				$campo .
				"_fechahoraregistro = " .
				(strlen($valor) > 0 ? "'" . $g_fecha . "'" : "NULL");
			$q_save .=
				", " .
				$campo .
				"_usuarioregistro = " .
				(strlen($valor) > 0 ? "'" . $usuario_registro . "'" : "NULL");
		}

		$q_save .= " WHERE Id = " . $id;

		if ($res_save = mysqli_query($enlace, $q_save)) {
			$estado = 1;

			// Actualiza el Peso Bruto
			if ($orden_campo == 3) {
				$peso_bruto = 0;

				$update =
					"UPDATE despachos_segundotramo_distribucion_lotes SET";
				$update .=
					"  peso_bruto = (cierrelote_complementotara / 1000) + " .
					$complemento_pesodistribuido;
				$update .= " WHERE Id = " . $id;

				if ($res_save = mysqli_query($enlace, $update)) {
					$q_pesobruto =
						"SELECT peso_bruto
																	FROM despachos_segundotramo_distribucion_lotes
																 WHERE Id = " . $id;

					if ($res_pesobruto = mysqli_query($enlace, $q_pesobruto)) {
						if (mysqli_num_rows($res_pesobruto) > 0) {
							while (
								$row_pesobruto = mysqli_fetch_array(
									$res_pesobruto
								)
							) {
								$peso_bruto =
									$row_pesobruto["peso_bruto"] * 1000;
							}
						}
					}
				}
			}
		}

		echo json_encode([
			"estado" => $estado,
			"peso_bruto" => number_format($peso_bruto, 0, ".", ","),
		]);

		break;

