								TEMP1.id_gestiondocumentaria_tipo_dato,
								D.cod_tipo_cliente,
								TEMP1.is_principal,

								(SELECT COUNT(TD_x.Id)
									 FROM tb_controlinterno_procesos_detalle_tipo_dato TD_x
									WHERE TD_x.cod_controlinterno_proceso_detalle = D.Id
										AND TD_x.cod_tipo_dato = 1) AS TIENE_ARCHIVO

					FROM tb_controlinterno_procesos_detalle_tipo_dato TD
					LEFT JOIN
					(
							SELECT TD.Id,
										GDTD.input_value,
										GDTD.Id as id_gestiondocumentaria_tipo_dato,
										GDTD.is_principal
							FROM tb_controlinterno_procesos_detalle_tipo_dato TD
							LEFT JOIN controlinterno_gestiondocumentaria_procesos_detalle_tipo_dato GDTD ON (GDTD.cod_controlinterno_proceso_detalle_tipo_dato = TD.Id)
