					INNER JOIN tb_controlinterno_procesos_detalle D ON (D.Id = TD.cod_controlinterno_proceso_detalle)
					WHERE TD.estado = 'A'
						AND TD.Id IN ($array_id_tipo_dato)
					ORDER BY D.Id, CTD.orden
				";

