	case "import_CierreResultados_Leyes_ExcelToBD":
		$estado = 0;

		$id_importacion = $_POST["id_importacion"];
		$id_leyes_grupo = $_POST["id_leyes_grupo"];
		$usuario_registro = $_SESSION["usu_usuario"];
		$g_fecha = date("Y-m-d H:i:s");

		// Archivo
		$nombre_file = $_FILES["file"]["name"];
		$tmp_file = $_FILES["file"]["tmp_name"];
		$ext_file = substr($nombre_file, strrpos($nombre_file, ".") + 1);
		$nombre_file_destino = "file_" . $id_importacion . "." . $ext_file;
		$destino_file = "../files/leyes/" . $nombre_file_destino;

		if (strlen($nombre_file) > 0) {
			if (!move_uploaded_file($tmp_file, $destino_file)) {
				echo 0;
			} else {
				$inputFileType = \PhpOffice\PhpSpreadsheet\IOFactory::identify(
					$destino_file
				);
				$reader = \PhpOffice\PhpSpreadsheet\IOFactory::createReader(
					$inputFileType
				);
				$spreadsheet = $reader->load($destino_file);
				$sheet = $spreadsheet->getActiveSheet();
				$rows = $sheet->toArray();

				$highestColumn = $sheet->getHighestColumn();
				$highestColumnIndex = \PhpOffice\PhpSpreadsheet\Cell\Coordinate::columnIndexFromString(
					$highestColumn
				);
				$num_cols = $highestColumnIndex;

				$r = 0;
				$cabecera = [];

				foreach ($rows as $row) {
					if (strlen(trim($row[0])) == 0) {
						break;
					}

					if ($r == 0) {
						// Cabecera
						$cabecera = $row;

						for ($c = 1; $c < $num_cols; $c++) {
							$analito = strtolower(trim($row[$c]));
							$campo = "porc_" . $analito;

							// Validar existencia del campo
							$q_exists = "SELECT COUNT(COLUMN_NAME) AS _COUNT
														FROM INFORMATION_SCHEMA.COLUMNS
														WHERE TABLE_SCHEMA = 'bdGelSac'
															AND TABLE_NAME = 'import_resultadosleyes_detalle'
															AND COLUMN_NAME = '$campo'";
							$res_exists = mysqli_query($enlace, $q_exists);
							$row_exists = mysqli_fetch_array($res_exists);
							if ($row_exists["_COUNT"] == 0) {
								mysqli_query(
									$enlace,
									"DELETE FROM import_resultadosleyes WHERE Id = $id_importacion"
								);
								echo json_encode([
									"estado" => 0,
									"columna" => $analito,
								]);
								return;
							}
						}
					} else {
						$cod_interno = trim($row[0]);
						if ($cod_interno == "") {
							continue;
						}

						// Validar cierre
						$q_cierre = "SELECT COUNT(Id) AS _COUNT
													FROM import_resultadosleyes_detalle
													WHERE is_cerrado = 1
														AND cod_interno = '$cod_interno'";
						$res_cierre = mysqli_query($enlace, $q_cierre);
						$row_cierre = mysqli_fetch_array($res_cierre);

						if ($row_cierre["_COUNT"] == 0) {
							// Construir columnas y valores para insert individual
							$campos =
								"id_importacion, id_ensayosdetalle, cod_interno, nombre_lote";
							$valores = "$id_importacion, $r, '$cod_interno', '$cod_interno'";

							for ($c_x = 1; $c_x < $num_cols; $c_x++) {
								$valor = trim($row[$c_x]);
								$analito = strtolower(trim($cabecera[$c_x]));

								$campos .= ", porc_$analito, porc_{$analito}_fechahoraregistro, porc_{$analito}_usuarioregistro";
								$valores .=
									", '$valor', " .
									(strlen($valor) == 0
										? "NULL"
										: "'$g_fecha'") .
									", " .
									(strlen($valor) == 0
										? "NULL"
										: "'$usuario_registro'");
							}

							$campos .= ", fechahora_registro, usuario_registro";
							$valores .= ", '$g_fecha', '$usuario_registro'";

							$q_individual = "INSERT INTO import_resultadosleyes_detalle ($campos) VALUES ($valores)";
							if (mysqli_query($enlace, $q_individual)) {
								// Registro exitoso
								$estado = 1;

								$last_id_detalle = mysqli_insert_id($enlace); // <--- CAPTURA EL ID INSERTADO

								// Insertar en tb_leyes_analisis_valor
								for ($c_x = 1; $c_x < $num_cols; $c_x++) {
									$valor = trim($row[$c_x]);
									$abv_elemento = strtolower(
										trim($cabecera[$c_x])
									);
									if ($valor != "") {
										$posicion = $last_id_detalle;
										$q_val = "INSERT INTO tb_leyes_analisis_valor 
												(cod_lote, id_grupo, abv_elemento, valor, posicion, fechahora_registro, usuario_registro, is_select)
												VALUES ('$cod_interno', '$id_leyes_grupo', '$abv_elemento', '$valor', $posicion, '$g_fecha', '$usuario_registro', 0)";
										mysqli_query($enlace, $q_val);
									}
								}
							} else {
								echo "Error al insertar: $q_individual\n";
							}
						}
					}

					$r++;
				}
			}
		}

		echo json_encode(["estado" => $estado]);

		break;

