		$q_save .= ", guias_motivotraslado = '" . $guia_motivotraslado . "'";
		$q_save .= ", balanza_id_transportista = '" . intval($guia_empresatransporte) . "'";
		$q_save .= ", balanza_placa = '" . $guia_placa_numero . "'";

