			$enlace,
			$_POST["numguia_serie"]
		);
		$numguia_numero = mysqli_real_escape_string(
			$enlace,
			$_POST["numguia_numero"]
		);

		$q_lotes = "SELECT V.Id as id_validaciondatos, 
														V.lote_id_lote,
														V.lote_cod_lote,
														DATE(V.lote_pesoinicial_fechahoraregistro) AS FECHA_INGRESO_PLANTA
												FROM despachos_primertramo_validaciondatos  V
											WHERE V.guiaremitente_serie = '$numguia_serie'
												AND V.guiaremitente_numero = '$numguia_numero'
												AND V.codigo_gel is not null
												-- AND V.is_cerradolote = 1
											ORDER BY guias_posicion ASC";

		if ($res_lotes = mysqli_query($enlace, $q_lotes)) {
			if (mysqli_num_rows($res_lotes) > 0) {
				while ($row_lotes = mysqli_fetch_array($res_lotes)) {
					$id_validaciondatos = $row_lotes["id_validaciondatos"];
					$fecha_llegadaplanta_validaciondatos =
						$row_lotes["FECHA_INGRESO_PLANTA"];

					//Actualizar el estado del correlativo GEL
					$q_update = "UPDATE correlativo_codigosgel SET ";
					$q_update .= "   estado = 'X'";
					$q_update .=
