												 WHERE serie_comprobante = '$comprobante_serie'
													 AND numero_comprobante = '$comprobante_numero'
													 AND id_proveedor = $id_proveedor
													 AND estado <> 'X'";

				$r_check = mysqli_query($enlace, $q_check);
				$row_check = mysqli_fetch_assoc($r_check);

				if ($row_check["existe"] > 0) {
					throw new Exception(
						"El comprobante con esa serie y número ya existe."
					);
				}

				// Insertar
				$q_insert =
					"INSERT INTO comprobante_pago (id_proveedor, id_valorizacion, id_moneda, fecha_emision_comprobante, serie_comprobante, numero_comprobante, sub_total, igv, total_comprobante, porc_detraccion, total_detraccion, total_detraccion_soles, total_sin_detraccion, tipo_cambio, fechahora_registro, usuario_registro, estado) VALUES (";
				$q_insert .= "$id_proveedor, ";
				$q_insert .= "'$id_valorizacion', ";
				$q_insert .= "$id_moneda, ";
				$q_insert .= "'$fecha_emision', ";
				$q_insert .= "'$comprobante_serie', ";
				$q_insert .= "'$comprobante_numero', ";
				$q_insert .= "$sub_total, ";
				$q_insert .= "$igv, ";
				$q_insert .= "$comprobante_total, ";
				$q_insert .= "$comprobante_porc_detraccion, ";
				$q_insert .= "$total_detraccion, ";
				$q_insert .= round($total_detraccion * $tc_venta, 0) . ", ";
				$q_insert .= "$total_sin_detraccion, ";
				$q_insert .= "$tc_venta, ";
				$q_insert .= "'$fechahora_actual', ";
				$q_insert .= "'$usuario_registro',";
				$q_insert .= "'P')";

				if (!mysqli_query($enlace, $q_insert)) {
					throw new Exception("Error al insertar el comprobante." . mysqli_error($enlace));
				}

