																 INNER JOIN tb_ensayos_analisis E ON VD.id_elemento = E.Id
																 LEFT JOIN valorizacion_compramineral V ON VD.id_valorizacion = V.Id
																 LEFT JOIN tb_clientes P ON V.id_proveedor = P.Id
														WHERE VD.estado <> 'X'";

		if (strlen($arr_lotes) > 0) {
