						"";
					$html .= "  </td>";

					$html .=
						'  <td style="border: solid; border-width: 1px; border-color: #D9D9D9; vertical-align: middle; text-align: center; background-color: #ffffff;">';
					$html .=
						'    <input type="checkbox" ' .
						($row_validacion["val"] == 1 ? "checked" : "") .
