	case "eliminar_ComprobantePago":
		$estado = 0;

		// Recupera parámetros
		$id = mysqli_real_escape_string($enlace, $_POST["id"]);

		$q = "UPDATE comprobante_pago SET estado = 'X' WHERE Id = $id";

		if ($res_save = mysqli_query($enlace, $q)) {
			$estado = 1;
		}

		echo json_encode(["estado" => $estado]);
		break;

	case "anular_ComprobantePago":
		$estado = 0;
		$msg = "";
		$id_comprobante = intval($_POST["id_comprobante"]);
		$fechahora_actual = date("Y-m-d H:i:s");
		$usuario_registro = $_SESSION["usu_usuario"];

		mysqli_begin_transaction($enlace);
		try {
			// Obtener info del comprobante
			$q_comp = "SELECT id_valorizacion FROM comprobante_pago WHERE Id = $id_comprobante";
			$res_comp = mysqli_query($enlace, $q_comp);
			$row_comp = mysqli_fetch_assoc($res_comp);
			$id_valorizacion = $row_comp['id_valorizacion'];

			// Actualizar estado de comprobante
			$q_upd_comp = "UPDATE comprobante_pago SET estado = 'X' WHERE Id = $id_comprobante";
			if (!mysqli_query($enlace, $q_upd_comp)) {
				throw new Exception("Error al anular el comprobante.");
			}

			// Actualizar valorización (is_aprobado = 0, y si estaba inactivo 'I' u otra cosa, quizas 'A')
			// liberandola
			$q_upd_val = "UPDATE valorizacion_compramineral SET is_aprobado = 0, is_aprobado_fechahoraregistro = NULL, is_aprobado_usuarioregistro = NULL WHERE Id = $id_valorizacion";
			mysqli_query($enlace, $q_upd_val);

			$q_update2 = "UPDATE import_resultadosleyes_detalle SET 
									is_valorizado = 0,
									is_valorizado_fechahoraregistro = NULL,
									is_valorizado_usuarioregistro = NULL
									WHERE cod_interno IN (SELECT cod_lote FROM valorizacion_compramineral_detalle WHERE id_valorizacion = $id_valorizacion)";
			mysqli_query($enlace, $q_update2);

			$q_update3 = "UPDATE despachos_primertramo_validaciondatos SET 
									codigogel_valorizado = 0,
									codigogel_valorizado_fechahoraregistro = NULL,
									codigogel_valorizado_usuarioregistro = NULL
									WHERE lote_cod_lote IN (SELECT cod_lote FROM valorizacion_compramineral_detalle WHERE id_valorizacion = $id_valorizacion)";
			mysqli_query($enlace, $q_update3);

			// Verificar si la valorización usa anticipos
			$q_val_info = "SELECT usa_anticipo FROM valorizacion_compramineral WHERE Id = $id_valorizacion";
			$res_val_info = mysqli_query($enlace, $q_val_info);
			$row_val_info = mysqli_fetch_assoc($res_val_info);

			if ($row_val_info['usa_anticipo'] == 1) {
				// Buscar transacciones asociadas que esten Aplicadas ('A') o Por confirmar ('B')
				$q_trans = "SELECT id, id_proveedor_anticipo, monto_retirado, estado FROM proveedor_anticipo_transaccion WHERE id_valorizacion_compramineral = $id_valorizacion AND estado IN ('A', 'B')";
				$res_trans = mysqli_query($enlace, $q_trans);
				while ($row_trans = mysqli_fetch_assoc($res_trans)) {
					$id_trans = $row_trans['id'];
					$id_anticipo = $row_trans['id_proveedor_anticipo'];
					$monto_retirado = $row_trans['monto_retirado'];
					$estado_trans = $row_trans['estado'];

					if ($estado_trans == 'A') {
						// Si estaba confirmada, devolver saldo al anticipo
						$q_upd_ant = "UPDATE proveedor_anticipo SET saldo_actual = saldo_actual + $monto_retirado, cantidad_transacciones = cantidad_transacciones - 1, estado = 'A', updated_at = '$fechahora_actual' WHERE id = $id_anticipo";
						mysqli_query($enlace, $q_upd_ant);
					}

					// Revertir la transacción al estado Por confirmar ('B') 
					$q_upd_trans = "UPDATE proveedor_anticipo_transaccion SET estado = 'B', updated_at = '$fechahora_actual' WHERE id = $id_trans";
					mysqli_query($enlace, $q_upd_trans);
				}
			}

			mysqli_commit($enlace);
			$estado = 1;
		} catch (Exception $e) {
			mysqli_rollback($enlace);
			$msg = $e->getMessage();
		}

		echo json_encode(["estado" => $estado, "msg" => $msg]);
		break;

	case "update_ContabilidadPagos_Datos":
		$out["estado"] = 0;

		$item = intval($_POST["item"]);
		$id_registro = intval($_POST["id_registro"]);
		$valor = trim(mysqli_real_escape_string($enlace, $_POST["valor"]));
		$usuario_registro = $_SESSION["usu_usuario"];

		// Seteando campo
		$campo = "";

		if ($item == 1) {
			$campo = "serie_comprobante";
		}

		if ($item == 2) {
			$campo = "numero_comprobante";
		}

		if ($item == 3) {
			$campo = "observaciones";
		}

		// Actualiza fecha y tipo de cambio en el comprobante
		$q_update = "UPDATE comprobante_pago SET ";
		$q_update .=
			"  " .
			$campo .
			" = " .
			(strlen($valor) == 0 ? "NULL" : "'" . $valor . "'");
		$q_update .=
			", " .
			$campo .
			"_fechahoraregistro = " .
			(strlen($valor) == 0 ? "NULL" : "'" . $g_fecha . "'");
		$q_update .=
			", " .
			$campo .
			"_usuarioregistro = " .
			(strlen($valor) == 0 ? "NULL" : "'" . $usuario_registro . "'");
		$q_update .= " WHERE Id = $id_registro";

		if (mysqli_query($enlace, $q_update)) {
			$out["estado"] = 1;
		}

		echo json_encode($out);
		break;

	case "actualizar_CampoTexto_ComprobantePago":
		$id = intval($_POST["id"]);
		$campo = $_POST["campo"];
		$valor = mysqli_real_escape_string($enlace, $_POST["valor"]);
		$fechahora_actual_raw = date("Y-m-d H:i:s");
		$usuario_registro_raw = $_SESSION["usu_usuario"];

		$campos_permitidos = [
			"observaciones",
			"aprobo_contabilidad",
			"aprobo_comercial",
			"aprobo_documentaria",
			"djvm",
			"val",
		];

		if (!in_array($campo, $campos_permitidos)) {
			echo json_encode(["estado" => 0, "msg" => "Campo no permitido"]);
			break;
		}

		if ($valor == 0) {
			if ($campo == "aprobo_contabilidad") {
				// Validacion: si Comercial o Documentaria ya aprobaron, contabilidad no puede quitar su check
				$q_check = "SELECT aprobo_comercial, aprobo_documentaria FROM comprobante_pago WHERE Id = $id";
				$res_check = mysqli_query($enlace, $q_check);
				if ($row_check = mysqli_fetch_assoc($res_check)) {
					if ($row_check['aprobo_comercial'] == 1 || $row_check['aprobo_documentaria'] == 1) {
						echo json_encode(["estado" => 0, "msg" => "No se puede quitar la aprobación de Contabilidad porque ya fue aprobado por Comercial o Documentaria."]);
						exit;
					}
				}
			}

			$fechahora_actual = "NULL";
			$usuario_registro = "NULL";
		} else {
			$fechahora_actual = "'" . $fechahora_actual_raw . "'";
			$usuario_registro = "'" . $usuario_registro_raw . "'";
		}

		mysqli_begin_transaction($enlace);

		try {
			// 1. Actualizar el campo solicitado
			$q = "UPDATE comprobante_pago SET
								$campo = '$valor',
								{$campo}_fechahora_registro = $fechahora_actual,
								{$campo}_usuario_registro = $usuario_registro
							WHERE Id = $id";

			if (!mysqli_query($enlace, $q)) {
				throw new Exception("Error al actualizar el campo");
			}


			mysqli_commit($enlace);

			// 2. Verificar si corresponde marcar como pagado (Logica Centralizada)
			f_UpdateComprobanteStatus($enlace, $id);

			echo json_encode([
				"estado" => 1,
				"id_comprobante" => $id,
				"fechahora_registro" =>
					$fechahora_actual == "NULL"
					? ""
					: $fechahora_actual_raw,
				"usuario_registro" =>
					$usuario_registro == "NULL"
					? ""
					: $usuario_registro_raw,
			]);
		} catch (Exception $e) {
			mysqli_rollback($enlace);
			echo json_encode(["estado" => 0, "msg" => $e->getMessage()]);
		}

		break;

	case "get_CuentasBancariasPorBanco":
		$id_banco = intval($_POST["id_banco"]);
		$id_moneda = isset($_POST["id_moneda"])
			? intval($_POST["id_moneda"])
			: 0;
		$estado = 0;
		$cuentas = [];

		if ($id_banco == 3) {
			$id_moneda = 1;
		}

		$q = "SELECT BC.*, M.abv as moneda_abv, M.abv as simbolo_moneda 
						FROM tb_bancos_cuentas BC
						LEFT JOIN 	tbconfig_monedas M ON (M.Id = BC.id_moneda)
						WHERE BC.id_banco = $id_banco 
							AND BC.estado = 'A'
						";

		if ($id_moneda > 0) {
			$q .= " AND BC.id_moneda = $id_moneda";
		}

		$q .= " ORDER BY BC.num_cuenta";

		if ($res = mysqli_query($enlace, $q)) {
			while ($row = mysqli_fetch_assoc($res)) {
				$cuentas[] = [
					"id" => $row["id"],
					"num_cuenta" => $row["num_cuenta"],
					"is_detraccion" => $row["is_detraccion"],
					"id_moneda" => $row["id_moneda"],
					"moneda_abv" => $row["moneda_abv"],
					"simbolo_moneda" => $row["simbolo_moneda"],
				];
			}

			$estado = 1;
		}

		echo json_encode(["estado" => $estado, "cuentas" => $cuentas]);
		break;

	case "grabar_ComprobantePago_RegistroPago":
		$res = [];
		$res["estado"] = 0;

		$modo = $_POST["modo"];
		$id = intval($_POST["id"]);
		$fecha = mysqli_real_escape_string($enlace, $_POST["fecha"]);
		$id_comprobante_pago = intval($_POST["id_comprobante_pago"]);
		$pago_monto = floatval($_POST["pago_monto"]);
		$cambio =
			isset($_POST["tipocambio"]) && is_numeric($_POST["tipocambio"])
			? floatval($_POST["tipocambio"])
			: null;
		$id_mediopago = intval($_POST["id_mediopago"]);
		$id_cuenta_1 = intval($_POST["id_cuenta_1"]);
		$id_cuenta_2 = intval($_POST["id_cuenta_2"]);
		$id_cuenta_moneda_1 = intval($_POST["id_cuenta_moneda_1"]);
		$id_cuenta_moneda_2 = intval($_POST["id_cuenta_moneda_2"]);
		$num_operacion = mysqli_real_escape_string(
			$enlace,
			$_POST["num_operacion"]
		);
		$pago_observacion = mysqli_real_escape_string(
			$enlace,
			$_POST["pago_observacion"]
		);
		$is_detraccion = mysqli_real_escape_string(
			$enlace,
			$_POST["is_detraccion"]
		);
		$fechahora_actual = date("Y-m-d H:i:s");
		$usuario_registro = $_SESSION["usu_usuario"];
		$pago_adjunto = mysqli_real_escape_string(
			$enlace,
			(isset($_POST["pago_adjunto"])) ? $_POST["pago_adjunto"] : ''
		);

		if ($modo == "N") {
			$q_save = "INSERT INTO comprobante_pago_pagos (";
			$q_save .=
				"id_comprobante_pago, fecha, id_mediopago, monto_pago, id_moneda_origen, id_moneda_destino, cambio, id_entidadbancaria, id_cliente_banco, num_operacion, observacion, documento_adjunto, fechahora_registro, usuario_registro";
			$q_save .= ") VALUES (";
			$q_save .= $id_comprobante_pago . ", ";
			$q_save .= "'" . $fecha . "', ";
			$q_save .= $id_mediopago . ", ";
			$q_save .= $pago_monto . ", ";
			$q_save .= $id_cuenta_moneda_1 . ", ";
			$q_save .= $id_cuenta_moneda_2 . ", ";
			$q_save .= $cambio . ", ";
			$q_save .= $id_cuenta_1 . ", ";
			$q_save .= $id_cuenta_2 . ", ";
			$q_save .= "'" . $num_operacion . "', ";
			$q_save .=
				(strlen($pago_observacion) == 0
					? "NULL"
					: "'" . $pago_observacion . "'") . ", ";
			$q_save .=
				(strlen($pago_adjunto) == 0 ? "NULL" : "'$pago_adjunto'") .
				", ";
			$q_save .= "'" . $fechahora_actual . "', ";
			$q_save .= "'" . $usuario_registro . "')";
		} else {
			$q_save = "UPDATE comprobante_pago_pagos SET ";
			$q_save .= "id_mediopago = " . $id_mediopago . ", ";
			$q_save .= "fecha = '" . $fecha . "', ";
			$q_save .= "monto_pago = " . $pago_monto . ", ";
			$q_save .= "id_moneda_origen = " . $id_cuenta_moneda_1 . ", ";
			$q_save .= "id_moneda_destino = " . $id_cuenta_moneda_2 . ", ";
			$q_save .= "cambio = " . $cambio . ", ";
			$q_save .= "id_entidadbancaria = " . $id_cuenta_1 . ", ";
			$q_save .= "id_cliente_banco = " . $id_cuenta_2 . ", ";
			$q_save .= "num_operacion = '" . $num_operacion . "', ";
			$q_save .= "fechahora_actual = '" . $fechahora_actual . "', ";
			$q_save .= "usuario_registro = '" . $usuario_registro . "', ";
			$q_save .=
				"observacion = " .
				(strlen($pago_observacion) == 0
					? "NULL"
					: "'" . $pago_observacion . "'");
			$q_save .=
				"adjunto = " .
				(strlen($pago_adjunto) == 0 ? "NULL" : "'$pago_adjunto'") .
				", ";
			$q_save .= " WHERE Id = " . $id;
		}

		if (mysqli_query($enlace, $q_save)) {
			// Si es detracción, actualizar campo en tabla padre
			if ($modo == "N") {
				if ($is_detraccion == 1) {
					$q_update_comprobante = "UPDATE comprobante_pago 
																		SET pago_detraccion = pago_detraccion + $pago_monto
																		WHERE Id = $id_comprobante_pago";
					mysqli_query($enlace, $q_update_comprobante);
				} else {
					$q_update_comprobante = "UPDATE comprobante_pago 
																		SET pago_sin_detraccion = pago_sin_detraccion + ($pago_monto) 
																		WHERE Id = $id_comprobante_pago";
					mysqli_query($enlace, $q_update_comprobante);
				}
			}

			//Obtener totales actualizados
			$q_totales = "SELECT 
												ROUND(pago_detraccion, 0) AS pago_detraccion, 
												tipo_cambio, 
												ROUND(pago_sin_detraccion, 2) AS pago_sin_detraccion, 
												ROUND(total_comprobante, 2) AS total_comprobante, 
												ROUND(total_detraccion_soles, 0) AS total_detraccion_soles,
												ROUND(total_sin_detraccion, 2) AS total_sin_detraccion  
											FROM comprobante_pago 
											WHERE Id = $id_comprobante_pago";

			$r_totales = mysqli_query($enlace, $q_totales);
			if ($r_totales && mysqli_num_rows($r_totales) > 0) {
				$row_totales = mysqli_fetch_assoc($r_totales);

				// Si la detracción ya fue completada, registrar fecha y usuario solo si aún no se han registrado
				if (
					$row_totales["total_detraccion_soles"] ==
					$row_totales["pago_detraccion"]
				) {
					$q_registro_detraccion = "UPDATE comprobante_pago 
																			SET pago_detraccion_fechahora_registro = '$fechahora_actual',
																					pago_detraccion_usuario_registro = '$usuario_registro'
																			WHERE Id = $id_comprobante_pago 
																				AND (pago_detraccion_fechahora_registro IS NULL OR pago_detraccion_usuario_registro IS NULL)";
					mysqli_query($enlace, $q_registro_detraccion);
				}

				// Si el pago sin detracción ya fue completado, registrar fecha y usuario solo si aún no se han registrado
				if (
					$row_totales["total_sin_detraccion"] ==
					$row_totales["pago_sin_detraccion"]
				) {
					$q_update_detraccion_registro = "UPDATE comprobante_pago 
																						SET pago_sin_detraccion_fechahora_registro = '$fechahora_actual', 
																								pago_sin_detraccion_usuario_registro = '$usuario_registro'
																						WHERE Id = $id_comprobante_pago 
																							AND (pago_sin_detraccion_fechahora_registro IS NULL OR pago_sin_detraccion_usuario_registro IS NULL)";
					mysqli_query($enlace, $q_update_detraccion_registro);
				}

				$res["pago_detraccion"] = $row_totales["pago_detraccion"];
				$res["tipo_cambio"] = $row_totales["tipo_cambio"];
				$res["pago_sin_detraccion"] =
					$row_totales["pago_sin_detraccion"];
				$res["total_comprobante"] = $row_totales["total_comprobante"];
				$res["total_detraccion_soles"] =
					$row_totales["total_detraccion_soles"];
				$res["total_sin_detraccion"] =
					$row_totales["total_sin_detraccion"];
			}

			// Verificar si corresponde marcar como pagado (Logica Centralizada)
			f_UpdateComprobanteStatus($enlace, $id_comprobante_pago);

			$res["estado"] = 1;
		} else {
			$res["estado"] = 0;
			$res["msg"] = "Error SQL: " . mysqli_error($enlace);
		}

		echo json_encode($res);
		break;

	case "get_ComprobantePago_RegistroPagos":
		$res = [];
		$res["estado"] = 0;
		$res["html"] = "";
		$res["total_pagos"] = 0;

