		f_UpdateComprobanteStatus($enlace, $id_comprobante_pago);

		$q = "SELECT P.Id,
									DATE_FORMAT(P.fechahora_registro, '%d/%m/%Y %H:%i') AS fecha_registro,
									P.usuario_registro,
									MP.descripcion AS medio_pago,
									P.monto_pago,
									IFNULL(P.cambio, '') AS cambio,
									P.num_operacion,
									P.observacion,
									B1.Id AS ID_BANCO,
									B1.cod_banco AS BANCO_ORIGEN,
									B2.cod_banco AS BANCO_DESTINO,
									C1.num_cuenta as c1_nro_cuenta,
									C2.nro_cuenta as c2_nro_cuenta,
									C2.cci AS CCI_DESTINO,
									M1.descripcion AS MONEDA_ORIGEN,
									M2.descripcion AS MONEDA_DESTINO,
									C2.is_detraccion as c2_is_detraccion,
									P.fecha,
									P.documento_adjunto
							FROM comprobante_pago_pagos P
							LEFT JOIN tbconfig_mediospago MP ON MP.Id = P.id_mediopago
							LEFT JOIN tb_bancos_cuentas C1 ON C1.id = P.id_entidadbancaria
							LEFT JOIN tb_bancos B1 ON C1.id_banco = B1.Id
							LEFT JOIN tbconfig_monedas M1 ON C1.id_moneda = M1.Id
							LEFT JOIN tb_clientes_bancos C2 ON C2.id = P.id_cliente_banco
							LEFT JOIN tb_bancos B2 ON C2.id_banco = B2.Id
							LEFT JOIN tbconfig_monedas M2 ON C2.id_moneda = M2.Id
							WHERE P.id_comprobante_pago = $id_comprobante_pago AND P.estado = 'A'
							ORDER BY P.fecha DESC";

		if ($res_q = mysqli_query($enlace, $q)) {
			$cont = 0;
			$total = 0;
