				$res["estado"] = 1;

				$cont++;
				$total += floatval($row["monto_pago"]);

				$res["html"] .=
					'
						<tr style="font-size: 12px;">
							<td style="text-align: center; vertical-align: middle;">' .
					$cont .
					'</td>
							<td style="text-align: center; vertical-align: middle;">';

				if ($_SESSION["is_compramineral_pagodetracciones"] == 1) {
					if ($row["ID_BANCO"] == 3) {
						$res["html"] .=
							'	<button class="btn btn-sm btn-danger me-1" title="Eliminar" onclick="f_Eliminar_ComprobantePagoDetalle(' .
							$row["Id"] .
							');">
																			<i class="bi bi-trash"></i>
																		</button>';
					}
				}

				if ($_SESSION["is_compramineral_pagoneto"] == 1) {
					if ($row["ID_BANCO"] != 3) {
						$res["html"] .=
							'	<button class="btn btn-sm btn-danger me-1" title="Eliminar" onclick="f_Eliminar_ComprobantePagoDetalle(' .
							$row["Id"] .
							');">
																			<i class="bi bi-trash"></i>
																		</button>';
					}
				}

				$res["html"] .=
					'
							</td>
							<td style="text-align: center; vertical-align: middle;">' .
					$row["fecha_registro"] .
					"<br>" .
					$row["usuario_registro"] .
					'</td>
							<td style="text-align: center; vertical-align: middle;">' .
					$row["fecha"] .
					'</td>
							<td style="text-align: center; vertical-align: middle;">' .
					$row["medio_pago"] .
					'</td>
							<td style="vertical-align: middle;"><label style="font-weight: bold;">' .
					$row["BANCO_ORIGEN"] .
					" - (" .
					$row["MONEDA_ORIGEN"] .
					")</label><br>N° Cuenta: " .
					$row["c1_nro_cuenta"] .
					// (strlen($row["CCI_ORIGEN"]) == 0
					//     ? ""
					//     : "<br>CCI: " . $row["CCI_ORIGEN"]) .
					'</td>
							<td style="vertical-align: middle;"><label style="font-weight: bold;">' .
					$row["BANCO_DESTINO"] .
					" - (" .
					$row["MONEDA_DESTINO"] .
					")</label><br>N° Cuenta: " .
					$row["c2_nro_cuenta"] .
					(strlen($row["CCI_DESTINO"]) == 0
						? ""
						: "<br>CCI: " . $row["CCI_DESTINO"]) .
					'</td>
							<td style="text-align: right; vertical-align: middle;">' .
					($row["c2_is_detraccion"] == 1 ? "S/ " : "$ ") .
					number_format($row["monto_pago"], 2) .
					'</td>
							<td style="text-align: center; vertical-align: middle;">' .
					(strlen($row["cambio"])
						? number_format($row["cambio"], 3)
						: "") .
					'</td>
							<td style="text-align: center; vertical-align: middle;">' .
					$row["num_operacion"] .
					'</td>
							<td style="text-align: center; vertical-align: middle;">' .
					mb_strtoupper($row["observacion"] ?? '') .
					'</td>
							<td style="text-align: center; vertical-align: middle;">';

				//Mostrar documento adjunto si existe
				if (!empty($row["documento_adjunto"])) {
					$ruta_archivo =
						"files/comprobantes/" . $row["documento_adjunto"];
					$ext = pathinfo(
						$row["documento_adjunto"],
						PATHINFO_EXTENSION
					);

					// Icono según extensión
					switch (strtolower($ext)) {
						case "pdf":
							$icono =
								'<i class="bi bi-file-earmark-pdf" style="color: red;"></i>';
							break;
						case "jpg":
						case "jpeg":
						case "png":
							$icono =
								'<i class="bi bi-file-earmark-image" style="color: #0d6efd;"></i>';
							break;
						case "doc":
						case "docx":
							$icono =
								'<i class="bi bi-file-earmark-word" style="color: #2b579a;"></i>';
							break;
						default:
							$icono =
								'<i class="bi bi-file-earmark" style="color: gray;"></i>';
							break;
					}

					$res["html"] .=
						'
							<a href="' .
						$ruta_archivo .
						'" target="_blank" class="btn btn-default btn-sm mb-1" style="width: 100%; font-size: 12px;">
								' .
						$icono .
						' Ver Archivo
							</a><br>';
				}

				// Botón para subir o reemplazar archivo

				if ($_SESSION["is_compramineral_pagodetracciones"] == 1) {
					if ($row["ID_BANCO"] == 3) {
						$res["html"] .=
