		$fecha = mysqli_real_escape_string($enlace, $_POST["fecha"]); // 'YYYY-MM-DD'

		// Busca el TC de la fecha o el más cercano anterior
		$sql = "SELECT tc_venta 
						FROM tb_tipocambio 
					WHERE estado='A' 
						AND fecha <= '$fecha'
					ORDER BY fecha DESC 
					LIMIT 1";

		if ($q = mysqli_query($enlace, $sql)) {
			if ($row = mysqli_fetch_assoc($q)) {
				$res["estado"] = 1;
				$res["tc_venta"] = floatval($row["tc_venta"]);
			} else {
				$res["msg"] =
					"No hay tipo de cambio registrado para la fecha indicada ni fechas previas.";
			}
