	case "eliminar_ComprobantePago_RegistroPago":
		$id_pago = intval($_POST["id"]);
		$id_comprobante = intval($_POST["id_comprobante_pago"]);
		$usuario_actual = $_SESSION["usu_usuario"];

		$out = ["estado" => 0, "msg" => ""];

		// 1) Borrado lógico del pago
		$ok = mysqli_query(
			$enlace,
			"UPDATE comprobante_pago_pagos SET estado='X' WHERE Id=$id_pago LIMIT 1"
		);

		if ($ok) {
			// 2) Recalcular sumas de pagos activos (estado = 'A')
			$qSum = "SELECT 
									COALESCE(SUM(CASE WHEN C2.is_detraccion = 1  THEN P.monto_pago ELSE 0 END),0) AS pago_detraccion,
									COALESCE(SUM(CASE WHEN C2.is_detraccion <> 1 THEN P.monto_pago ELSE 0 END),0) AS pago_sin_detraccion
								FROM comprobante_pago_pagos P
									LEFT JOIN tb_clientes_bancos C2 ON C2.id = P.id_cliente_banco
								WHERE P.estado = 'A' AND P.id_comprobante_pago = $id_comprobante";
			$rsSum = mysqli_query($enlace, $qSum);
			$sumas = mysqli_fetch_assoc($rsSum);

			// 3) Actualizar los montos en comprobante_pago
			mysqli_query(
				$enlace,
				"
					UPDATE comprobante_pago SET 
						pago_detraccion = " .
				(float) $sumas["pago_detraccion"] .
				",
						pago_sin_detraccion = " .
				(float) $sumas["pago_sin_detraccion"] .
				"
					WHERE Id = $id_comprobante
					LIMIT 1
				"
			);

			// 4) Determinar tipo de pago eliminado
			$qTipo = "SELECT C2.is_detraccion
									FROM comprobante_pago_pagos P
									LEFT JOIN tb_clientes_bancos C2 ON C2.id = P.id_cliente_banco
									WHERE P.Id = $id_pago
									LIMIT 1";
			$rsTipo = mysqli_query($enlace, $qTipo);
			$rowTipo = mysqli_fetch_assoc($rsTipo);
			$is_detraccion = intval($rowTipo["is_detraccion"]);

			// 5) Actualizar campos de auditoría correspondientes
			if ($is_detraccion == 1) {
				$qUpd = "UPDATE comprobante_pago SET 
										pago_detraccion_fechahora_registro = NULL,
										pago_detraccion_usuario_registro = NULL
									WHERE Id = $id_comprobante
									LIMIT 1";
			} else {
				$qUpd = "UPDATE comprobante_pago SET 
										pago_sin_detraccion_fechahora_registro = NULL,
										pago_sin_detraccion_usuario_registro = NULL
									WHERE Id = $id_comprobante
									LIMIT 1";
			}
			mysqli_query($enlace, $qUpd);

			// 6) Traer totales actualizados del comprobante
			$qComp = "SELECT 
										total_comprobante,
										total_detraccion_soles,
										total_sin_detraccion,
										tipo_cambio
									FROM comprobante_pago
									WHERE Id = $id_comprobante
									LIMIT 1";
			$rsComp = mysqli_query($enlace, $qComp);
			$comp = mysqli_fetch_assoc($rsComp);

			// 7) Retornar respuesta
			$out["estado"] = 1;
			$out["pago_detraccion"] = (float) $sumas["pago_detraccion"];
			$out["pago_sin_detraccion"] = (float) $sumas["pago_sin_detraccion"];
			$out["total_comprobante"] = (float) $comp["total_comprobante"];
			$out["total_detraccion_soles"] =
				(float) $comp["total_detraccion_soles"];
			$out["total_sin_detraccion"] =
				(float) $comp["total_sin_detraccion"];
			$out["tipo_cambio"] = (float) $comp["tipo_cambio"];
		} else {
			$out["msg"] = "No se pudo eliminar el pago.";
		}

		echo json_encode($out);
		break;

	case "grabar_ComprobantePago_RegistroPago_Documento":
