		if ($res_check && mysqli_num_rows($res_check) > 0) {
			$row_check = mysqli_fetch_assoc($res_check);
			$usa_anticipo = $row_check['usa_anticipo'];
		}

		// Copiando datos de cabecera
		$q_insert = "
										INSERT INTO valorizacion_compramineral(
												id_proveedor,
