				// Si falla la copia del detalle, eliminar la cabecera creada
				mysqli_query($enlace, "DELETE FROM valorizacion_compramineral WHERE Id = $id_valorizacion");
				$mensaje = "Error al copiar el detalle de la valorización.";
			}
