	case "grabar_ValorizacionCompra_Aprobacion":
		$estado = 0;
		$msg = "";

		$id_registro = mysqli_real_escape_string($enlace, $_POST["id_registro"]);
		$num_valorizacion = mysqli_real_escape_string($enlace, $_POST["num_valorizacion"]);
		$version = mysqli_real_escape_string($enlace, $_POST["version"]);
		$is_aprobado = mysqli_real_escape_string($enlace, $_POST["is_aprobado"]);
		$usuario_registro = $_SESSION["usu_usuario"];

		mysqli_begin_transaction($enlace);

		try {
			// Primero, verificar si la valorización usa anticipos
			$q_check_anticipo = "SELECT usa_anticipo FROM valorizacion_compramineral WHERE Id = $id_registro";
			$res_check = mysqli_query($enlace, $q_check_anticipo);
			$row_check = mysqli_fetch_assoc($res_check);
			$usa_anticipo = $row_check['usa_anticipo'] == 1;

			if ($is_aprobado == 1 && $usa_anticipo) {
				// Verificar transacciones pendientes
				$q_transacciones = "SELECT 
										trans.id,
										trans.id_proveedor_anticipo,
										trans.monto_retirado,
										ant.saldo_actual as saldo_disponible
								FROM proveedor_anticipo_transaccion trans
								INNER JOIN proveedor_anticipo ant ON ant.id = trans.id_proveedor_anticipo
								WHERE trans.id_valorizacion_compramineral = $id_registro 
								AND trans.estado = 'B'";

				$res_trans = mysqli_query($enlace, $q_transacciones);
				$transacciones = [];

				while ($row = mysqli_fetch_assoc($res_trans)) {
					$transacciones[] = $row;
				}

				if (count($transacciones) <= 0) {
					throw new Exception("La valorizacion ya no tiene anticipos.");
				}

				// Verificar que cada anticipo tenga saldo suficiente
				foreach ($transacciones as $trans) {
					if ($trans['monto_retirado'] > $trans['saldo_disponible']) {
						throw new Exception("El anticipo {$trans['id_proveedor_anticipo']} no tiene saldo suficiente. Saldo disponible: {$trans['saldo_disponible']}, Monto a retirar: {$trans['monto_retirado']}");
					}
				}

				// Actualizar saldos de anticipos y confirmar transacciones
				foreach ($transacciones as $trans) {
					$id_anticipo = $trans['id_proveedor_anticipo'];
					$monto_retirado = $trans['monto_retirado'];
					$saldo_actual = $trans['saldo_disponible'];
					$saldo_restante = $saldo_actual - $monto_retirado;

					// Actualizar transacción
					$q_update_trans = "UPDATE proveedor_anticipo_transaccion 
																		SET saldo_actual = $saldo_actual,
																				saldo_restante = $saldo_restante,
																				estado = 'A',
																				updated_at = '$g_fecha'
																		WHERE id = {$trans['id']}";
					mysqli_query($enlace, $q_update_trans);

					// Actualizar anticipo
					$q_update_anticipo = "UPDATE proveedor_anticipo 
																				SET saldo_actual = $saldo_restante,
																						cantidad_transacciones = cantidad_transacciones + 1,
																						updated_at = '$g_fecha'
																				WHERE id = $id_anticipo";
					mysqli_query($enlace, $q_update_anticipo);

					// Si el saldo llega a 0, cambiar estado a 'B' (Sin saldo)
					if ($saldo_restante <= 0) {
						$q_update_estado = "UPDATE proveedor_anticipo 
																				SET estado = 'B', updated_at = '$g_fecha'
																				WHERE id = $id_anticipo AND saldo_actual <= 0";
						mysqli_query($enlace, $q_update_estado);
					}
				}
			} elseif ($is_aprobado == 0 && $usa_anticipo) {
				// Si se desaprueba, revertir transacciones confirmadas
				$q_revertir = "SELECT 
										trans.id,
										trans.id_proveedor_anticipo,
										trans.monto_retirado,
										trans.saldo_actual,
										trans.saldo_restante
								FROM proveedor_anticipo_transaccion trans
								WHERE trans.id_valorizacion_compramineral = $id_registro 
								AND trans.estado = 'A'";

				$res_revertir = mysqli_query($enlace, $q_revertir);

				while ($row = mysqli_fetch_assoc($res_revertir)) {
					$id_anticipo = $row['id_proveedor_anticipo'];
					$monto_retirado = $row['monto_retirado'];
					$saldo_actual = $row['saldo_actual'];

					// Restaurar saldo del anticipo
					$saldo_nuevo = $saldo_actual + $monto_retirado;
					$q_restaurar = "UPDATE proveedor_anticipo 
																SET saldo_actual = $saldo_nuevo,
																		cantidad_transacciones = cantidad_transacciones - 1,
																		estado = 'A', -- Volver a estado con saldo
																		updated_at = '$g_fecha'
																WHERE id = $id_anticipo";
					mysqli_query($enlace, $q_restaurar);

					// Cambiar estado de transacción a 'B' (Por confirmar)
					$q_update_trans = "UPDATE proveedor_anticipo_transaccion 
																		SET estado = 'B',
																				updated_at = '$g_fecha'
																		WHERE id = {$row['id']}";
					mysqli_query($enlace, $q_update_trans);
				}
			}

			// Actualizar la valorización
			$q_update = "UPDATE valorizacion_compramineral SET 
								is_aprobado = $is_aprobado,
								is_aprobado_fechahoraregistro = " . ($is_aprobado == 1 ? "'$g_fecha'" : "NULL") . ",
								is_aprobado_usuarioregistro = " . ($is_aprobado == 1 ? "'$usuario_registro'" : "NULL") . "
						WHERE Id = $id_registro";

			if (mysqli_query($enlace, $q_update)) {
				$estado = 1;

				// Actualiza tablas adicionales (código existente)
				$q_update2 = "UPDATE import_resultadosleyes_detalle SET 
										is_valorizado = $is_aprobado,
										is_valorizado_fechahoraregistro = " . ($is_aprobado == 1 ? "'$g_fecha'" : "NULL") . ",
										is_valorizado_usuarioregistro = " . ($is_aprobado == 1 ? "'$usuario_registro'" : "NULL") . "
										WHERE cod_interno IN (SELECT cod_lote FROM valorizacion_compramineral_detalle WHERE id_valorizacion = $id_registro)";

				mysqli_query($enlace, $q_update2);

				$q_update3 = "UPDATE despachos_primertramo_validaciondatos SET 
										codigogel_valorizado = $is_aprobado,
										codigogel_valorizado_fechahoraregistro = " . ($is_aprobado == 1 ? "'$g_fecha'" : "NULL") . ",
										codigogel_valorizado_usuarioregistro = " . ($is_aprobado == 1 ? "'$usuario_registro'" : "NULL") . "
										WHERE lote_cod_lote IN (SELECT cod_lote FROM valorizacion_compramineral_detalle WHERE id_valorizacion = $id_registro)";

				mysqli_query($enlace, $q_update3);
			}

			mysqli_commit($enlace);
		} catch (Exception $e) {
			mysqli_rollback($enlace);
			$msg = $e->getMessage();
			$estado = 0;
		}

		echo json_encode(["estado" => $estado, "msg" => $msg]);
		break;

	case "get_config_tiposcambio":
		$res = [];
		$res["estado"] = 0;
		$res["html"] = "";

		$fecha_inicio = mysqli_real_escape_string(
			$enlace,
			$_POST["fecha_inicio"]
		);
		$fecha_fin = mysqli_real_escape_string($enlace, $_POST["fecha_fin"]);

		$q_datos = "SELECT TC.id, 
												 TC.id_moneda_base, M.descripcion AS moneda,
												 TC.fecha, TC.tc_compra, TC.tc_venta, TC.estado,
												 TC.fechahora_registro,
												 TC.usuario_registro
										FROM tb_tipocambio TC
												 LEFT JOIN tbconfig_monedas M ON M.id = TC.id_moneda_base
									 WHERE TC.estado <> 'X'
										 AND TC.fecha BETWEEN '$fecha_inicio' AND '$fecha_fin'
									ORDER BY TC.fecha DESC";

		$rs = mysqli_query($enlace, $q_datos);
		$i = 1;

		while ($row = mysqli_fetch_assoc($rs)) {
			$estado_txt = $row["estado"] == "A" ? "Activo" : "Inactivo";
			$color = $row["estado"] == "A" ? "#2E8B57" : "#e0a800";

			$res["html"] .= '<tr style="font-size: 13px;">';
			$res["html"] .=
				'<td class="text-center" style="vertical-align: middle;">' .
				$i .
				"</td>";
			$res["html"] .=
				'<td class="text-center" style="vertical-align: middle;">' .
				$row["fecha"] .
				"</td>";
			$res["html"] .=
				'<td class="text-center" style="vertical-align: middle;">' .
				htmlspecialchars($row["moneda"]) .
				"</td>";
			$res["html"] .=
				'<td class="text-center" style="vertical-align: middle;">' .
				number_format($row["tc_compra"], 4) .
				"</td>";
			$res["html"] .=
				'<td class="text-center" style="vertical-align: middle;">' .
				number_format($row["tc_venta"], 4) .
				"</td>";
			$res["html"] .=
				'<td class="text-center" style="vertical-align: middle;">' .
				$row["fechahora_registro"] .
				"<br>" .
				$row["usuario_registro"] .
				"</td>";
			$res["html"] .=
				'<td class="text-center" style="vertical-align: middle; background-color:' .
				$color .
				'; color:white;">' .
				$estado_txt .
				"</td>";
			$res["html"] .=
				'<td class="text-center" style="vertical-align: middle;">';
			$res["html"] .=
				'<button class="btn btn-sm btn-primary me-1" title="Editar" onclick="f_AdminTipoCambio(' .
				$row["id"] .
				', \'' .
				$row["fecha"] .
				'\', ' .
				$row["tc_compra"] .
				", " .
				$row["tc_venta"] .
				", " .
				$row["id_moneda_base"] .
				');">' .
				'<i class="bi bi-pencil-square"></i></button>';

			if ($row["estado"] == "A") {
				$res["html"] .=
					'<button class="btn btn-sm btn-warning me-1" title="Inactivar" onclick="f_CambiarEstadoTipoCambio(' .
					$row["id"] .
					', \'I\');"><i class="bi bi-x-circle"></i></button>';
			} else {
				$res["html"] .=
					'<button class="btn btn-sm btn-success me-1" title="Activar" onclick="f_CambiarEstadoTipoCambio(' .
					$row["id"] .
					', \'A\');"><i class="bi bi-check-circle"></i></button>';
			}

			$res["html"] .=
				'<button class="btn btn-sm btn-danger" title="Eliminar" onclick="f_EliminarTipoCambio(' .
				$row["id"] .
				');"><i class="bi bi-trash"></i></button>';
			$res["html"] .= "</td>";
			$res["html"] .= "</tr>";
			$i++;
		}

		$res["estado"] = 1;

		echo json_encode($res);

		break;

	case "grabar_config_tipocambio":
		$res = [];
		$res["estado"] = 0;

		$modo = $_POST["modo"];
		$id = intval($_POST["id"]);
		$fecha = mysqli_real_escape_string($enlace, $_POST["fecha"]);
		$compra = floatval($_POST["compra"]);
		$venta = floatval($_POST["venta"]);
		$id_moneda = intval($_POST["id_moneda_base"]);
		$usuario = $_SESSION["usu_usuario"];
		$f_registro = date("Y-m-d H:i:s");

		if ($modo == "N") {
			$q_valida = "SELECT COUNT(id) AS total
											FROM tb_tipocambio
											WHERE fecha = '$fecha' AND estado <> 'X'";
			$r_valida = mysqli_query($enlace, $q_valida);
			$valida = mysqli_fetch_assoc($r_valida);

			if ($valida["total"] > 0) {
				$res["estado"] = 2; // duplicado
			} else {
				$q = "INSERT INTO tb_tipocambio (id_moneda_base, tc_compra, tc_venta, fecha, estado, fechahora_registro, usuario_registro)
								VALUES ($id_moneda, $compra, $venta, '$fecha', 'A', '$f_registro', '$usuario')";
				if (mysqli_query($enlace, $q)) {
					$res["estado"] = 1;
				}
			}
		} else {
			$q = "UPDATE tb_tipocambio
								SET 
										fecha = '$fecha',
										tc_compra = $compra,
										tc_venta = $venta,
										id_moneda_base = $id_moneda
							WHERE id = $id";

			if (mysqli_query($enlace, $q)) {
				$res["estado"] = 1;
			}
		}

		echo json_encode($res);

		break;

	case "cambiar_estado_config_tipocambio":
		$res = [];
		$res["estado"] = 0;

		$id = intval($_POST["id"]);
		$modo = mysqli_real_escape_string($enlace, $_POST["modo"]);

		$q = "UPDATE tb_tipocambio SET estado = '$modo' WHERE id = $id";

		if (mysqli_query($enlace, $q)) {
			$res["estado"] = 1;
		}

		echo json_encode($res);

		break;

	case "eliminar_config_tipocambio":
		$res = [];
		$res["estado"] = 0;

		$id = intval($_POST["id"]);

		$q = "UPDATE tb_tipocambio SET estado = 'X' WHERE id = $id";

		if (mysqli_query($enlace, $q)) {
			$res["estado"] = 1;
		}

		echo json_encode($res);

		break;

	case "get_TipoCambio":
		$res = ["estado" => 0, "data" => []];

		$fecha = mysqli_real_escape_string($enlace, $_POST["fecha"]);

		$q_datos = "SELECT Id,
												 tc_compra,
												 tc_venta
										FROM tb_tipocambio
									 WHERE estado = 'A'
										 AND fecha = '$fecha'";

		if ($res_datos = mysqli_query($enlace, $q_datos)) {
			if (mysqli_num_rows($res_datos) > 0) {
				$res["estado"] = 1;

				while ($row_datos = mysqli_fetch_assoc($res_datos)) {
					$res["data"][] = [
						"id_registro" => $row_datos["Id"],
						"tc_compra" => $row_datos["tc_compra"],
						"tc_venta" => $row_datos["tc_venta"],
					];
				}
			}
		}

		echo json_encode($res);
		break;

	case "getAnticiposAndProviders":
		$response = [
			"cantidad_anticipos" => 0,
			"anticipos_con_saldo" => 0,
			"anticipos_sin_saldo" => 0,
			"proveedores" => [],
			"proveedores_con_anticipos" => [],
		];

		// 1. Obtener la lista de proveedores APTOs para Select2 (cod_clientecondicion = 1)
		$sql_aptos = "
						SELECT
								pr.Id as id_proveedor,
								pr.documento,
								pr.razon_social
						FROM
								tb_clientes pr
						WHERE pr.cod_clientecondicion = 1
			ORDER BY pr.razon_social ASC;
				";
		$res_aptos = mysqli_query($enlace, $sql_aptos);
		while ($p = mysqli_fetch_assoc($res_aptos)) {
			$response["proveedores"][] = $p;
		}

		// 2. Obtener TODAS las transacciones para mapearlas fácilmente (Query 3)
		$sql_transacciones = "
						SELECT
								tr.id AS id_transaccion,
								tr.id_proveedor_anticipo AS id_anticipo,
								tr.saldo_actual,
								tr.monto_retirado,
								tr.saldo_restante,
								val.correlativo as codigo_unico,
								val.procedencia,
								val.concesion,
								tr.created_at AS fecha_registro
						FROM
								proveedor_anticipo_transaccion AS tr
						INNER JOIN valorizacion_compramineral AS val
						ON
								tr.id_valorizacion_compramineral = val.Id
						WHERE tr.estado = 'A'
						ORDER BY fecha_registro DESC;
				";
		$res_transacciones = mysqli_query($enlace, $sql_transacciones);
		$transacciones_map = [];
		while ($t = mysqli_fetch_assoc($res_transacciones)) {
			$transacciones_map[$t["id_anticipo"]][] = $t;
		}
		// Liberar el resultado
		mysqli_free_result($res_transacciones);

		// 3. Obtener TODOS los anticipos (Query 2)
		$sql_anticipos = "
						SELECT
								ant.id as id_anticipo,
								ant.id_proveedor,
								ant.serie_factura,
								ant.numero_factura,
								ant.saldo_inicial,
								ant.saldo_actual,
								ant.cantidad_transacciones,
								DATE_FORMAT(ant.created_at, '%d/%m/%Y') as fecha_registro_formateada,
								ant.estado
						FROM
								proveedor_anticipo ant
						WHERE ant.estado != 'X';
				";
		$res_anticipos = mysqli_query($enlace, $sql_anticipos);
		$anticipos_raw = [];
		while ($a = mysqli_fetch_assoc($res_anticipos)) {
			$anticipos_raw[] = $a;
		}
		// Liberar el resultado
		mysqli_free_result($res_anticipos);

		// 4. Obtener proveedores con anticipos (Query 1)
		$sql_proveedores_con_anticipos = "
						SELECT DISTINCT
								pr.Id AS id_proveedor,
								pr.documento,
								pr.razon_social
						FROM
								tb_clientes pr
						INNER JOIN proveedor_anticipo ant ON ant.id_proveedor = pr.Id;
				";
		$res_proveedores_con_anticipos = mysqli_query(
			$enlace,
			$sql_proveedores_con_anticipos
		);
		$proveedores_con_anticipos_map = [];

		// Inicializar el mapa de proveedores con anticipos
		while ($p = mysqli_fetch_assoc($res_proveedores_con_anticipos)) {
			$proveedores_con_anticipos_map[$p["id_proveedor"]] = [
				"id_proveedor" => $p["id_proveedor"],
				"documento" => $p["documento"],
				"razon_social" => $p["razon_social"],
				"cantidad_anticipos" => 0,
				"anticipos_con_saldo" => 0,
				"anticipos_sin_saldo" => 0,
				"anticipos" => [],
			];
		}
		// Liberar el resultado
		mysqli_free_result($res_proveedores_con_anticipos);

		// 5. Mapear anticipos a proveedores y sumar totales
		foreach ($anticipos_raw as $ant) {
			$id_proveedor = $ant["id_proveedor"];
			$id_anticipo = $ant["id_anticipo"];

			// Asignar transacciones al anticipo
			$ant["transacciones"] = $transacciones_map[$id_anticipo] ?? [];
			$ant["fecha_registro"] = $ant["fecha_registro_formateada"]; // Usar el campo con formato DD/MM/YYYY
			unset($ant["fecha_registro_formateada"]); // Limpieza

			if (isset($proveedores_con_anticipos_map[$id_proveedor])) {
				$proveedores_con_anticipos_map[$id_proveedor]["anticipos"][] = $ant;
				$proveedores_con_anticipos_map[$id_proveedor]["cantidad_anticipos"]++;
				$response["cantidad_anticipos"]++;

				if ($ant["estado"] === "A") {
					// Asumo 'A' para CON SALDO
					$proveedores_con_anticipos_map[$id_proveedor]["anticipos_con_saldo"]++;
					$response["anticipos_con_saldo"]++;
				} else {
					// Asumo 'B' para SALDO AGOTADO / SIN SALDO
					$proveedores_con_anticipos_map[$id_proveedor]["anticipos_sin_saldo"]++;
					$response["anticipos_sin_saldo"]++;
				}
			}
		}

		// Convertir el mapa de proveedores a una lista para el JSON final
		$response["proveedores_con_anticipos"] = array_values(
			$proveedores_con_anticipos_map
		);

		// Ordenar la lista de proveedores por Razon Social
		usort($response["proveedores_con_anticipos"], function ($a, $b) {
			return strcmp($a["razon_social"], $b["razon_social"]);
		});

		// Retornar la respuesta
		header("Content-Type: application/json");
		echo json_encode(["estado" => 1, "data" => $response]);
		break;
	case "registerNewAnticipo":
		// Validaciones (simples)
		$id_proveedor = intval($_POST["id_proveedor"] ?? 0);
		$serie = trim($_POST["serie_factura"] ?? "");
		$numero = trim($_POST["numero_factura"] ?? "");
		$saldo_inicial = floatval($_POST["saldo_inicial"] ?? 0);

		if (
			!$id_proveedor ||
			empty($serie) ||
			empty($numero) ||
			$saldo_inicial <= 0
		) {
			header("Content-Type: application/json");
			echo json_encode([
				"estado" => 0,
				"msg" =>
					"Faltan datos requeridos (Proveedor, Factura o Saldo inicial válido).",
			]);
			exit();
		}

		// Asumo id_moneda = 2 para Dólares
		$id_moneda = 2;
		$estado = "A"; // Estado inicial: CON SALDO

		// La fecha de registro se establecerá automáticamente en la DB,
		// pero la incluimos por si la tabla no lo hace (aunque no es estrictamente necesario)
		$f_registro = date("Y-m-d H:i:s");

		// Lógica de inserción con Prepared Statement (seguridad mejorada)
		$sql = "INSERT INTO proveedor_anticipo (id_proveedor, id_moneda, serie_factura, numero_factura, saldo_inicial, saldo_actual, estado, created_at) 
			VALUES (?, ?, ?, ?, ?, ?, ?, ?)";

		$stmt = mysqli_prepare($enlace, $sql);

		if ($stmt) {
			/* * Bind Parameters:
			 * 'isssddss' -> i: integer, s: string, d: double (float)
			 * (i) id_proveedor, (i) id_moneda, (s) serie, (s) numero,
			 * (d) saldo_inicial, (d) saldo_actual, (s) estado, (s) created_at
			 */
			mysqli_stmt_bind_param(
				$stmt,
				"iisssdss",
				$id_proveedor,
				$id_moneda,
				$serie,
				$numero,
				$saldo_inicial,
				$saldo_inicial,
				$estado,
				$f_registro
			);
			if (mysqli_stmt_execute($stmt)) {
				$new_id = mysqli_insert_id($enlace); // Obtiene el ID generado
				mysqli_stmt_close($stmt);
				// Prepara la data del nuevo anticipo para el front
				$new_anticipo_data = [
					"id_anticipo" => (int) $new_id,
					"id_proveedor" => (int) $id_proveedor,
					"serie_factura" => $serie,
					"numero_factura" => $numero,
					"saldo_inicial" => number_format(
						$saldo_inicial,
						2,
						".",
						""
					),
					"saldo_actual" => number_format($saldo_inicial, 2, ".", ""),
					"cantidad_transacciones" => 0,
					"fecha_registro" => date("d/m/Y"),
					"estado" => $estado,
					"transacciones" => [],
				];

				header("Content-Type: application/json");
				echo json_encode([
					"estado" => 1,
					"msg" => "Anticipo registrado con éxito.",
					"id_anticipo" => $new_id,
					"new_data" => $new_anticipo_data,
				]);
			} else {
				mysqli_stmt_close($stmt);
				header("Content-Type: application/json");
				echo json_encode([
					"estado" => 0,
					"msg" =>
						"Error al ejecutar la consulta de inserción: " .
						mysqli_error($enlace),
				]);
			}
		} else {
			header("Content-Type: application/json");
			echo json_encode([
				"estado" => 0,
				"msg" =>
					"Error al preparar la consulta: " . mysqli_error($enlace),
			]);
		}
		break;

	case "getAnticiposByProveedor":
		$id_proveedor = intval($_POST["id_proveedor"] ?? 0);

		if ($id_proveedor == 0) {
			header("Content-Type: application/json");
			echo json_encode([
				"estado" => 0,
				"msg" => "ID de proveedor inválido.",
				"data" => [],
			]);
			exit();
		}

		// Obtener la lista de anticipos por proveedor
		$sql_query = "
										SELECT
												ant.id AS id_anticipo,
												CONCAT(
														ant.serie_factura,
														'-',
														ant.numero_factura
												) AS factura,
												ant.saldo_actual,
												ant.saldo_inicial,
												ant.created_at AS fecha_registro
										FROM
												proveedor_anticipo ant
										WHERE
												ant.id_proveedor = '$id_proveedor' AND ant.estado = 'A' AND ant.saldo_actual > 0
										ORDER BY
												ant.created_at ASC;
								";
		$response_query = mysqli_query($enlace, $sql_query);

		$anticipos = [];
		while ($row = mysqli_fetch_assoc($response_query)) {
			$row["saldo_actual"] = floatval($row["saldo_actual"]);
			$anticipos[] = $row;
		}

		// Liberar el resultado
		mysqli_free_result($response_query);

		// Retornar la respuesta
		header("Content-Type: application/json");
		echo json_encode(["estado" => 1, "data" => $anticipos]);
		break;

	case "getAnticiposByValorizacion":
		$id_valorizacion = intval($_POST["id_valorizacion"] ?? 0);

		if ($id_valorizacion == 0) {
			header("Content-Type: application/json");
			echo json_encode(["estado" => 0, "msg" => "ID de valorización inválido.", "data" => []]);
			exit();
		}

		$sql_query = "
						SELECT 
								trans.id,
								trans.id_proveedor_anticipo,
								trans.monto_retirado,
								trans.saldo_actual,
								trans.saldo_restante,
								trans.estado,
								trans.created_at,
								ant.serie_factura,
								ant.numero_factura,
								CONCAT(ant.serie_factura, '-', ant.numero_factura) AS factura
						FROM proveedor_anticipo_transaccion trans
						INNER JOIN proveedor_anticipo ant ON ant.id = trans.id_proveedor_anticipo
						WHERE trans.id_valorizacion_compramineral = '$id_valorizacion'
						AND(
								trans.estado = 'A' OR trans.estado = 'B'
						)
						ORDER BY trans.created_at ASC;
				";

		$response_query = mysqli_query($enlace, $sql_query);

		$transacciones = [];
		while ($row = mysqli_fetch_assoc($response_query)) {
			$row['monto_retirado'] = floatval($row['monto_retirado']);
			$row['saldo_actual'] = floatval($row['saldo_actual']);
			$row['saldo_restante'] = floatval($row['saldo_restante']);
			$transacciones[] = $row;
		}

		mysqli_free_result($response_query);

		header("Content-Type: application/json");
		echo json_encode(["estado" => 1, "data" => $transacciones]);
		break;

	case "eliminarAnticipo":
		$id_anticipo = intval($_POST["id_anticipo"] ?? 0);

		if (!$id_anticipo) {
			header("Content-Type: application/json");
			echo json_encode([
				"estado" => 0,
				"msg" => "Anticipo inválido."
			]);
			exit();
		}

		// Verificar si el anticipo existe y obtener sus datos
		$sql_check = "SELECT * FROM proveedor_anticipo WHERE id = ?";
		$stmt_check = mysqli_prepare($enlace, $sql_check);
		mysqli_stmt_bind_param($stmt_check, "i", $id_anticipo);
		mysqli_stmt_execute($stmt_check);
		$result_check = mysqli_stmt_get_result($stmt_check);
		$anticipo_data = mysqli_fetch_assoc($result_check);
		mysqli_stmt_close($stmt_check);

		if (!$anticipo_data) {
			header("Content-Type: application/json");
			echo json_encode([
				"estado" => 0,
				"msg" => "Anticipo no encontrado."
			]);
			exit();
		}

		// Verificar si tiene transacciones CONFIRMADAS (estado 'A')
		$sql_transacciones_aprobadas = "
				SELECT COUNT(*) as count 
				FROM proveedor_anticipo_transaccion 
				WHERE id_proveedor_anticipo = ? 
				AND estado = 'A'
		";
		$stmt_aprobadas = mysqli_prepare($enlace, $sql_transacciones_aprobadas);
		mysqli_stmt_bind_param($stmt_aprobadas, "i", $id_anticipo);
		mysqli_stmt_execute($stmt_aprobadas);
		$result_aprobadas = mysqli_stmt_get_result($stmt_aprobadas);
		$row_aprobadas = mysqli_fetch_assoc($result_aprobadas);
		mysqli_stmt_close($stmt_aprobadas);

		if ($row_aprobadas['count'] > 0) {
			header("Content-Type: application/json");
			echo json_encode([
				"estado" => 0,
				"msg" => "No se puede eliminar el anticipo porque tiene valorizaciones CONFIRMADAS asociadas."
			]);
			exit();
		}

		// Contadores para respuesta
		$transacciones_eliminadas = 0;
		$valorizaciones_anuladas = 0;

		// Iniciar transacción
		mysqli_begin_transaction($enlace);

		try {
			// 1. Obtener todas las transacciones POR CONFIRMAR (estado 'B')
			$sql_get_transacciones = "
						SELECT id, id_valorizacion_compramineral 
						FROM proveedor_anticipo_transaccion 
						WHERE id_proveedor_anticipo = ? 
						AND estado = 'B'
				";
			$stmt_get = mysqli_prepare($enlace, $sql_get_transacciones);
			mysqli_stmt_bind_param($stmt_get, "i", $id_anticipo);
			mysqli_stmt_execute($stmt_get);
			$result_get = mysqli_stmt_get_result($stmt_get);
			$transacciones_por_confirmar = [];

			while ($row = mysqli_fetch_assoc($result_get)) {
				$transacciones_por_confirmar[] = $row;
			}
			mysqli_stmt_close($stmt_get);

			// 2. Para cada transacción por confirmar:
			//    a. Cambiar estado a 'C' (Cancelada)
			//    b. Cambiar estado de la valorización a 'R' (Anulado por eliminación de anticipo)
			foreach ($transacciones_por_confirmar as $transaccion) {
				// Actualizar estado de transacción a 'C'
				$sql_update_trans = "
								DELETE FROM proveedor_anticipo_transaccion 
								WHERE id = ?
						";
				$stmt_upd_trans = mysqli_prepare($enlace, $sql_update_trans);
				mysqli_stmt_bind_param($stmt_upd_trans, "i", $transaccion['id']);
				mysqli_stmt_execute($stmt_upd_trans);
				mysqli_stmt_close($stmt_upd_trans);
				$transacciones_eliminadas++;

				// Actualizar estado de la valorización a 'R'
				$sql_update_val = "
								UPDATE valorizacion_compramineral 
								SET estado = 'R' 
								WHERE Id = ?
						";
				$stmt_upd_val = mysqli_prepare($enlace, $sql_update_val);
				mysqli_stmt_bind_param($stmt_upd_val, "i", $transaccion['id_valorizacion_compramineral']);
				mysqli_stmt_execute($stmt_upd_val);
				mysqli_stmt_close($stmt_upd_val);
				$valorizaciones_anuladas++;
			}

			// eliminar anticipo
			$sql_update_anticipo = "
						DELETE FROM proveedor_anticipo 
						WHERE id = ?
				";
			$stmt_upd_anticipo = mysqli_prepare($enlace, $sql_update_anticipo);
			mysqli_stmt_bind_param($stmt_upd_anticipo, "i", $id_anticipo);
			mysqli_stmt_execute($stmt_upd_anticipo);
			mysqli_stmt_close($stmt_upd_anticipo);

			// Confirmar transacción
			mysqli_commit($enlace);

			header("Content-Type: application/json");
			echo json_encode([
				"estado" => 1,
				"msg" => "Anticipo eliminado exitosamente.",
				"transacciones_eliminadas" => $transacciones_eliminadas,
				"valorizaciones_anuladas" => $valorizaciones_anuladas,
				"id_anticipo" => $id_anticipo
			]);

		} catch (Exception $e) {
			// Revertir transacción en caso de error
			mysqli_rollback($enlace);

			header("Content-Type: application/json");
			echo json_encode([
				"estado" => 0,
				"msg" => "Error al eliminar anticipo: " . $e->getMessage()
			]);
		}
		break;

	case "reabrir_Valorizacion":
		$estado = 0;
		$msg = "";

		$id_valorizacion = intval($_POST["id_valorizacion"]);
		$usuario_registro = $_SESSION["usu_usuario"];

		if ($id_valorizacion == 0) {
			echo json_encode(["estado" => 0, "msg" => "ID de valorización inválido."]);
			exit();
		}

		mysqli_begin_transaction($enlace);

		try {
			// Verificar si la valorización existe y está aprobada
			$q_check = "SELECT 
								V.Id,
								V.is_aprobado,
								V.usa_anticipo
						FROM valorizacion_compramineral V
						WHERE V.Id = $id_valorizacion
						AND V.estado = 'A'
						AND V.is_aprobado = 1";

			$res_check = mysqli_query($enlace, $q_check);

			if (mysqli_num_rows($res_check) == 0) {
				throw new Exception("La valorización no existe, no está activa o no está aprobada.");
			}

			$row_val = mysqli_fetch_assoc($res_check);
			$usa_anticipo = $row_val['usa_anticipo'] == 1;

			// Validar si existe comprobante asociado
			$q_check_comprobante = "SELECT 
								cp.Id as id_comprobante
						FROM
								comprobante_pago cp
						WHERE
								cp.id_valorizacion = $id_valorizacion and cp.estado != 'X'
						LIMIT 1";

			$res_check_comprobante = mysqli_query($enlace, $q_check_comprobante);

			if (mysqli_num_rows($res_check_comprobante) > 0) {
				throw new Exception("La valorización ya tiene un comprobante asociado, no se puede reabrir.");
			}

			// Revertir aprobación
			$q_update = "UPDATE valorizacion_compramineral 
												SET is_aprobado = 0,
														is_aprobado_fechahoraregistro = NULL,
														is_aprobado_usuarioregistro = NULL
												WHERE Id = $id_valorizacion";

			if (!mysqli_query($enlace, $q_update)) {
				throw new Exception("Error al actualizar la valorización.");
			}

			// Revertir transacciones de anticipos si corresponde
			if ($usa_anticipo) {
				// Obtener transacciones confirmadas para revertir
				$q_transacciones = "
										SELECT
												trans.id,
												trans.id_proveedor_anticipo,
												trans.monto_retirado,
												pa.saldo_actual
										FROM
												proveedor_anticipo_transaccion trans
										INNER JOIN proveedor_anticipo pa on pa.id = trans.id_proveedor_anticipo
										WHERE
												trans.id_valorizacion_compramineral = $id_valorizacion AND trans.estado = 'A';
										";

				$res_trans = mysqli_query($enlace, $q_transacciones);

				while ($row = mysqli_fetch_assoc($res_trans)) {
					$id_anticipo = $row['id_proveedor_anticipo'];
					$monto_retirado = floatval($row['monto_retirado']);
					$saldo_actual = floatval($row['saldo_actual']);

					// Restaurar saldo del anticipo
					$saldo_nuevo = $saldo_actual + $monto_retirado;

					// Actualizar el anticipo
					$q_actualizar_anticipo = "UPDATE proveedor_anticipo 
																		SET saldo_actual = $saldo_nuevo,
																				cantidad_transacciones = GREATEST(0, cantidad_transacciones - 1),
																				estado = 'A', -- Volver a estado con saldo
																				updated_at = '$g_fecha'
																		WHERE id = $id_anticipo";

					mysqli_query($enlace, $q_actualizar_anticipo);

					// Cambiar estado de transacción a 'B' (Por confirmar)
					$q_update_trans = "UPDATE proveedor_anticipo_transaccion 
																		SET estado = 'B',
																				updated_at = '$g_fecha'
																		WHERE id = {$row['id']}";

					mysqli_query($enlace, $q_update_trans);
				}
			}

			// Actualizar tablas relacionadas
			$q_update_leyes = "UPDATE import_resultadosleyes_detalle 
														SET is_valorizado = 0,
																is_valorizado_fechahoraregistro = NULL,
																is_valorizado_usuarioregistro = NULL
														WHERE cod_interno IN (
																SELECT cod_lote 
																FROM valorizacion_compramineral_detalle 
																WHERE id_valorizacion = $id_valorizacion
														)";

			mysqli_query($enlace, $q_update_leyes);

			$q_update_validacion = "UPDATE despachos_primertramo_validaciondatos 
																SET codigogel_valorizado = 0,
																		codigogel_valorizado_fechahoraregistro = NULL,
																		codigogel_valorizado_usuarioregistro = NULL
																WHERE lote_cod_lote IN (
																		SELECT cod_lote 
																		FROM valorizacion_compramineral_detalle 
																		WHERE id_valorizacion = $id_valorizacion
																)";

			mysqli_query($enlace, $q_update_validacion);

			mysqli_commit($enlace);
			$estado = 1;
			$msg = "Valorización reabierta correctamente. Las transacciones han sido revertidas a estado 'Por confirmar'.";
		} catch (Exception $e) {
			mysqli_rollback($enlace);
			$msg = $e->getMessage();
		}

		echo json_encode(["estado" => $estado, "msg" => $msg]);
		break;
	case "get_info_cuenta_banco_valorizacion":
		$estado = 0;
		$data = []; // Usaremos 'data' en lugar de 'msg' para los resultados

		// Obtener y validar el ID del Comprobante de Pago
		$id_comprobante = isset($_POST["id_comprobante_pago"]) ? intval($_POST["id_comprobante_pago"]) : 0;

		if ($id_comprobante == 0) {
			// Devolver error si el ID no es válido
			echo json_encode(["estado" => 0, "msg" => "ID de Comprobante de Pago inválido."]);
			exit();
		}

		// La consulta SQL solicitada
		$q_data_pago = "
						SELECT
								ban.id AS id_banco,
								cli.Id as id_proveedor,
								ban.descripcion AS nombre_banco,
								vc.id_cuentabancaria,
								clb.nro_cuenta,
								clb.cci,
								mon.Id AS id_moneda,
								clb.is_detraccion,
								mon.abv AS simbolo_moneda
						FROM
								comprobante_pago cp
						LEFT JOIN valorizacion_compramineral vc ON
								vc.Id = cp.id_valorizacion
						LEFT JOIN tb_clientes cli ON
								cli.Id = vc.id_proveedor
						LEFT JOIN tb_clientes_bancos clb ON
								clb.id_cliente = cli.Id AND clb.cci = vc.infopago_cci
						LEFT JOIN tbconfig_monedas mon ON
								clb.id_moneda = mon.Id
						LEFT JOIN tb_bancos ban ON
								ban.id = clb.id_banco
						WHERE
								cp.Id = $id_comprobante;
				"; // Se agrega LIMIT 1 ya que se espera una cuenta bancaria única por comprobante

		$res_data_pago = mysqli_query($enlace, $q_data_pago);

		if ($res_data_pago === false) {
			// Manejo de error de consulta SQL
			$msg = "Error al ejecutar la consulta: " . mysqli_error($enlace);
			echo json_encode(["estado" => 0, "msg" => $msg]);
			exit();
		}

		if (mysqli_num_rows($res_data_pago) > 0) {
			// Si se encuentra información, se lee la primera fila
			$row = mysqli_fetch_assoc($res_data_pago);
			$data = $row; // La información se almacena en el array $data
			$estado = 1;
			$msg = "Datos de pago obtenidos correctamente.";
		} else {
			// Si no se encuentra información
			$msg = "No se encontraron datos bancarios asociados al Comprobante de Pago ID $id_comprobante.";
		}
		echo json_encode([
			"estado" => $estado,
			"msg" => $msg ?? "", // Asegura que 'msg' exista
			"data" => $data
		]);
		break;

	case "get_monto_total_valorizacion":
		$estado = 0;
		$data = [];

		// Obtener y validar el ID de la Valorización
		$id_valorizacion = isset($_POST["id_valorizacion"]) ? intval($_POST["id_valorizacion"]) : 0;

		if ($id_valorizacion == 0) {
			echo json_encode(["estado" => 0, "msg" => "ID de Valorizacion inválida."]);
			exit();
		}

		// 1. Consulta para obtener el monto total de la valorización
		$q_monto_total_valorizacion = "
						SELECT
								COALESCE(SUM(vcd.total), 0) AS monto_total_valorizacion
						FROM
								valorizacion_compramineral vc
						INNER JOIN valorizacion_compramineral_detalle vcd ON
								vcd.id_valorizacion = vc.Id
						WHERE
								vc.Id = $id_valorizacion AND vc.estado = 'A';
				";

		$res_monto_total = mysqli_query($enlace, $q_monto_total_valorizacion);

		if ($res_monto_total === false) {
			$msg = "Error al ejecutar la consulta del monto total: " . mysqli_error($enlace);
			echo json_encode(["estado" => 0, "msg" => $msg]);
			exit();
		}

		// 2. Consulta para obtener el monto usado de anticipos
		$q_monto_anticipos = "
						SELECT
								COALESCE(SUM(pat.monto_retirado), 0) AS monto_total_anticipos
						FROM
								valorizacion_compramineral vc
						INNER JOIN proveedor_anticipo_transaccion pat ON
								pat.id_valorizacion_compramineral = vc.Id
						WHERE
								vc.Id = $id_valorizacion 
								AND vc.estado = 'A' 
								AND pat.estado = 'A';
				";

		$res_monto_anticipos = mysqli_query($enlace, $q_monto_anticipos);

		if ($res_monto_anticipos === false) {
			$msg = "Error al ejecutar la consulta de anticipos: " . mysqli_error($enlace);
			echo json_encode(["estado" => 0, "msg" => $msg]);
			exit();
		}

		// Obtener resultados
		$row_monto_total = mysqli_fetch_assoc($res_monto_total);
		$row_monto_anticipos = mysqli_fetch_assoc($res_monto_anticipos);

		if ($row_monto_total) {
			$monto_total_valorizacion = floatval($row_monto_total['monto_total_valorizacion']);
			$monto_total_anticipos = floatval($row_monto_anticipos['monto_total_anticipos']);

			// Calcular saldo por transferencia
			$saldo_transferencia = $monto_total_valorizacion - $monto_total_anticipos;

			// Asegurarse de que no sea negativo (por si acaso)
			if ($saldo_transferencia < 0) {
				$saldo_transferencia = 0;
			}

			// Preparar los datos para la respuesta
			$data = [
				"monto_total_valorizacion" => $monto_total_valorizacion,
				"monto_total_anticipos" => $monto_total_anticipos,
				"saldo_transferencia" => $saldo_transferencia
			];

			$estado = 1;
			$msg = "Montos obtenidos correctamente.";
		} else {
			$msg = "No se encontraron datos para la valorización ID $id_valorizacion.";
		}

		echo json_encode([
			"estado" => $estado,
			"msg" => $msg ?? "",
			"data" => $data
		]);
		break;

	case "getReporteAnticiposTransacciones":
		$id_proveedor = intval($_POST["id_proveedor"] ?? 0);
		$fecha_desde = $_POST["fecha_desde"] ?? null;
		$fecha_hasta = $_POST["fecha_hasta"] ?? null;

		if ($id_proveedor == 0) {
			header("Content-Type: application/json");
			echo json_encode(["estado" => 0, "msg" => "ID de proveedor inválido."]);
			exit();
		}

		$data_final = getDataReporte($enlace, $id_proveedor, $fecha_desde, $fecha_hasta);

		header("Content-Type: application/json");
		echo json_encode(["estado" => 1, "data" => $data_final]);
		break;

	case "verificar_pagototal_comprobante":
		$id = intval($_POST["id"]);

		try {
			$query = "
								SELECT
										cp.aprobo_contabilidad,
										cp.aprobo_comercial,
										cp.aprobo_documentaria,
										cp.total_sin_detraccion,
										cp.total_detraccion_soles,
										cp.pago_sin_detraccion,
										cp.pago_detraccion,
										CASE WHEN vc.id_cuentabancaria = NULL AND vc.usa_anticipo THEN 1 ELSE 0
								END AS solo_anticipo
								FROM
										comprobante_pago cp
								INNER JOIN valorizacion_compramineral vc ON
										vc.Id = cp.id_valorizacion
								WHERE
										cp.Id = $id
						";

			$result = mysqli_query($enlace, $query);
			$cp = mysqli_fetch_assoc($result);

			if (!$cp)
				throw new Exception("Comprobante no encontrado.");

			$solo_anticipo = $cp["solo_anticipo"];
			$aprobado = ($cp["aprobo_contabilidad"] == 1 &&
				$cp["aprobo_comercial"] == 1 &&
				$cp["aprobo_documentaria"] == 1);

			// verificamos si lo pagado cubre el total
			// aplicamos cierta tolerancia para evitar errores de precision
			$total_deuda = floatval($cp["total_sin_detraccion"]) + floatval($cp["total_detraccion_soles"]);
			$total_pagado = floatval($cp["pago_sin_detraccion"]) + floatval($cp["pago_detraccion"]);

			$pagado_completamente = ($total_pagado >= ($total_deuda - 0.01));

			mysqli_commit($enlace);

			echo json_encode([
				"estado" => 1,
				"totalmente_pagado" => ($aprobado && $pagado_completamente),
				"solo_anticipo" => $solo_anticipo
			]);

		} catch (Exception $e) {
			mysqli_rollback($enlace);
			echo json_encode(["estado" => 0, "msg" => $e->getMessage()]);
		}
		break;
	case "exportExcelResumenTransacciones":
		// 0. Limpiar buffers y suprimir errores al inicio absoluto
		error_reporting(0);
		ini_set('display_errors', 0);
		while (ob_get_level())
			ob_end_clean();

		$id_proveedor = intval($_POST["id_proveedor"] ?? 0);
		$fecha_desde = $_POST["fecha_desde"] ?? null;
		$fecha_hasta = $_POST["fecha_hasta"] ?? null;

