		// O: N VAlorizacion (ROWSPAN 2)
		$sheet->mergeCells('O2:O3');
		$sheet->setCellValue('O2', 'N° VALORIZACIÓN');
		$sheet->getStyle('O2:O3')->applyFromArray($stylePrimary);

