		$sheet->getStyle('F3')->applyFromArray($styleSuccess);

		// Venta
		$sheet->setCellValue('G3', 'N° Factura Amortiza');
		$sheet->getStyle('G3')->applyFromArray($styleSecondary);
		$sheet->setCellValue('H3', 'Fecha');
		$sheet->getStyle('H3')->applyFromArray($styleSecondary);
		$sheet->setCellValue('I3', 'Importe Factura USD $');
		$sheet->getStyle('I3')->applyFromArray($styleSecondary);
		$sheet->setCellValue('J3', 'Importe Amortiza Adelanto USD $');
		$sheet->getStyle('J3')->applyFromArray($styleSecondary);

		// Saldo
		$sheet->setCellValue('K3', 'Saldo Factura Amortiza');
		$sheet->getStyle('K3')->applyFromArray($styleWarning);

		// Dsct
		$sheet->setCellValue('L3', 'Saldo Neto Factura Amortiza');
		$sheet->getStyle('L3')->applyFromArray($styleInfo);

		// Saldo Deuda
		$sheet->setCellValue('M3', 'Importe USD $');
		$sheet->getStyle('M3')->applyFromArray($styleDanger);

		// Anchos de columna
		$sheet->getColumnDimension('A')->setWidth(15);
		$sheet->getColumnDimension('B')->setWidth(12);
		$sheet->getColumnDimension('C')->setWidth(18);
		$sheet->getColumnDimension('D')->setWidth(12);
		$sheet->getColumnDimension('E')->setWidth(18);
		$sheet->getColumnDimension('F')->setWidth(15);
		$sheet->getColumnDimension('G')->setWidth(15);
		$sheet->getColumnDimension('H')->setWidth(12);
		$sheet->getColumnDimension('I')->setWidth(15);
		$sheet->getColumnDimension('J')->setWidth(18);
		$sheet->getColumnDimension('K')->setWidth(15);
		$sheet->getColumnDimension('L')->setWidth(15);
		$sheet->getColumnDimension('M')->setWidth(15);
		$sheet->getColumnDimension('N')->setWidth(12);
		$sheet->getColumnDimension('O')->setWidth(12);

		$row = 4;

		foreach ($data_final as $group) {
			$ant = $group['anticipo_info'];

			// Fila de encabezado de Anticipo
			$sheet->setCellValue('A' . $row, $ant['factura']);
			$sheet->setCellValue('B' . $row, $ant['fecha']); // Assuming d/m/Y or similar
			$sheet->setCellValue('C' . $row, $ant['importe_inicial']);
			$sheet->getStyle('C' . $row)->getNumberFormat()->setFormatCode('"US$ "#,##0.00');

			// Aplicar estilo gris a toda la fila
			$sheet->getStyle('A' . $row . ':O' . $row)->applyFromArray($styleAnticipoRow);
			$sheet->getStyle('A' . $row . ':O' . $row)->applyFromArray($styleCellBorder);

			$row++;

			foreach ($group['transacciones'] as $tr) {
				// D: Aplicado %
				$sheet->setCellValue('D' . $row, $tr['porcentaje_aplicado']);
				// E: Monto Aplicado
				$sheet->setCellValue('E' . $row, $tr['monto_aplicado']);
				$sheet->getStyle('E' . $row)->getNumberFormat()->setFormatCode('"US$ "#,##0.00');

				// F: Lote
				$sheet->setCellValue('F' . $row, $tr['lotes']);

				// G: Factura Amortiza
				$sheet->setCellValue('G' . $row, $tr['factura_amortiza_serie']);

				// H: Fecha Factura
				$sheet->setCellValue('H' . $row, formatDateShort($tr['fecha_factura']));

				// I: Importe Factura USD
				$sheet->setCellValue('I' . $row, $tr['importe_factura_usd']);
				$sheet->getStyle('I' . $row)->getNumberFormat()->setFormatCode('"US$ "#,##0.00');

				// J: Importe Amortiza Adelanto USD
				$sheet->setCellValue('J' . $row, $tr['importe_amortiza_adelanto_usd']);
				// Highlight yellow
				$sheet->getStyle('J' . $row)->applyFromArray(['fill' => ['fillType' => \PhpOffice\PhpSpreadsheet\Style\Fill::FILL_SOLID, 'startColor' => ['argb' => 'FFFFFF00']]]);
				$sheet->getStyle('J' . $row)->getNumberFormat()->setFormatCode('"US$ "#,##0.00');

				// K: Saldo Factura Amortiza
				$sheet->setCellValue('K' . $row, $tr['saldo_factura_amortiza']);
				$sheet->getStyle('K' . $row)->getNumberFormat()->setFormatCode('"US$ "#,##0.00');

				// L: Saldo Neto Factura
				$sheet->setCellValue('L' . $row, $tr['saldo_neto_factura_amortiza']);
				$sheet->getStyle('L' . $row)->getNumberFormat()->setFormatCode('"US$ "#,##0.00');

				// M: Saldo Deuda
				$sheet->setCellValue('M' . $row, $tr['saldo_deuda_usd']);
				$sheet->getStyle('M' . $row)->getNumberFormat()->setFormatCode('"US$ "#,##0.00');

				// N: Estado
				$sheet->setCellValue('N' . $row, $tr['estado_comprobante']);

				// O: Valorizacion
				$sheet->setCellValue('O' . $row, $tr['nro_valorizacion']);

				$sheet->getStyle('A' . $row . ':O' . $row)->applyFromArray($styleCellBorder);

				$row++;
			}
		}

		// Descargar
		$filename = 'Transacciones_Anticipos_' . date('Ymd_His') . '.xlsx';

		// Limpiar cualquier salida previa (espacios en blanco, notices, etc)
		while (ob_get_level())
			ob_end_clean();

		header('Content-Type: application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');
		header('Content-Disposition: attachment;filename="' . $filename . '"');
		header('Cache-Control: max-age=0');
		// If you're serving to IE 9, then the following may be needed
		header('Cache-Control: max-age=1');

		// If you're serving to IE over SSL, then the following may be needed
		header('Expires: Mon, 26 Jul 1997 05:00:00 GMT'); // Date in the past
		header('Last-Modified: ' . gmdate('D, d M Y H:i:s') . ' GMT'); // always modified
		header('Cache-Control: cache, must-revalidate'); // HTTP/1.1
		header('Pragma: public'); // HTTP/1.0

		$writer = new \PhpOffice\PhpSpreadsheet\Writer\Xlsx($spreadsheet);
		$writer->save('php://output');
		break;

	case "getTipoPagoValorizacion":
		$estado = 0;
		$tipo_pago = "";
		$mensaje = "Error desconocido.";

		// Sanitizar el parámetro 'id'
		if (!isset($_POST["id_valorizacion"])) {
			$mensaje = "Parámetro 'id_valorizacion' no recibido.";
		} else {
			$id_valorizacion = mysqli_real_escape_string($enlace, $_POST["id_valorizacion"]);

			$q_tipo_pago = "
								SELECT
										vc.usa_anticipo,
										vc.id_cuentabancaria
								FROM
										valorizacion_compramineral vc
								WHERE
										vc.id = $id_valorizacion;
						";

			$res_tipo_pago = mysqli_query($enlace, $q_tipo_pago);

			if ($res_tipo_pago && mysqli_num_rows($res_tipo_pago) > 0) {
				$row = mysqli_fetch_assoc($res_tipo_pago);

				$usa_anticipo = (int) $row['usa_anticipo'];
				$id_cuentabancaria = $row['id_cuentabancaria'];
				$usa_cuenta_bancaria = !empty($id_cuentabancaria);

				if ($usa_anticipo === 1 && $usa_cuenta_bancaria) {
					$tipo_pago = "mixto";
				} elseif ($usa_anticipo === 1 && !$usa_cuenta_bancaria) {
					$tipo_pago = "anticipo";
				} elseif ($usa_anticipo === 0 && $usa_cuenta_bancaria) {
					$tipo_pago = "banco";
				} else {
					// no habra posibilidad de que usa_anticipo y id_cuentabancaria sean nulos, pero por si acaso xd
					$tipo_pago = "pago no definido/invalido";
					$mensaje = "Combinación de pago inválida (No anticipo y No cuenta bancaria).";
					goto end_response;
				}

				$estado = 1;
				$mensaje = "Tipo de pago obtenido correctamente.";
			} else if ($res_tipo_pago && mysqli_num_rows($res_tipo_pago) === 0) {
				$mensaje = "No se encontró registro para el ID proporcionado.";
			} else {
				$mensaje = "Error en la consulta a la base de datos: " . mysqli_error($enlace);
			}
		}

		end_response:

		echo json_encode([
			"estado" => $estado,
			"msg" => $mensaje,
			"tipo_pago" => $tipo_pago,
			"id_valorizacion" => $id_valorizacion ?? null
		]);
		break;

	case "get_montos_valorizacion":
		$estado = 0;
		$mensaje = "Error desconocido.";
		$monto_total = 0.00; // Usar float para montos
		$monto_anticipo = 0.00;
		$monto_banco = 0.00;

		// 1. Validar y Sanitizar la Entrada
		if (!isset($_POST["id_valorizacion"])) {
			$mensaje = "Parámetro 'id_valorizacion' no recibido.";
			break;
		}

		$id_valorizacion = $_POST["id_valorizacion"];

		if (!is_numeric($id_valorizacion) || $id_valorizacion <= 0) {
			$mensaje = "ID de valorización inválido.";
			break;
		}

		$id_valorizacion = (int) $id_valorizacion;

		// Consulta del monto total de la valorización
		$q_monto_total = "
						SELECT
								IFNULL(SUM(vcd.total), 0.00) AS monto_total
						FROM
								valorizacion_compramineral_detalle vcd
						WHERE
								vcd.id_valorizacion = {$id_valorizacion};
				";

		// Consulta del monto de anticipo usado
		$q_uso_anticipo = "
						SELECT
								IFNULL(SUM(pat.monto_retirado), 0.00) AS monto_anticipo
						FROM
								proveedor_anticipo_transaccion pat
						WHERE
								pat.id_valorizacion_compramineral = {$id_valorizacion}
								AND pat.estado <> 'C';
				";

		$res_monto_total = mysqli_query($enlace, $q_monto_total);
		$res_uso_anticipo = mysqli_query($enlace, $q_uso_anticipo);

		if (!$res_monto_total || !$res_uso_anticipo) {
			$mensaje = "Error en la consulta a la base de datos: " . mysqli_error($enlace);
		} else {
			if ($row_monto = mysqli_fetch_assoc($res_monto_total)) {
				$monto_total = (float) $row_monto['monto_total'];
			}

			if ($row_anticipo = mysqli_fetch_assoc($res_uso_anticipo)) {
				$monto_anticipo = (float) $row_anticipo['monto_anticipo'];
			}

			$monto_banco = $monto_total - $monto_anticipo;
			$monto_banco = max(0.00, $monto_banco);

			$estado = 1;
			$mensaje = "Montos de valorización obtenidos correctamente.";
		}

		echo json_encode([
			"estado" => $estado,
			"msg" => $mensaje,
			"monto_total" => $monto_total,
			"monto_anticipo" => $monto_anticipo,
			"monto_banco" => $monto_banco,
		]);
		break;

	case "get_proveedores_to_blending":
		$q = "
		SELECT
			prov.Id as id_proveedor,
			prov.documento,
			prov.razon_social
		FROM tb_clientes prov
		WHERE 
			prov.cod_clientecondicion = 1 AND
			prov.estado = 'A'
		";

		$result = mysqli_query($enlace, $q);
		$proveedores = [];

		if ($result) {
			while ($p = mysqli_fetch_assoc($result)) {
				$proveedores[] = $p;
			}
		}

		echo json_encode([
			"estado" => 1,
			"data" => ["proveedores" => $proveedores]
		]);
		break;

	case "get_lotes_to_blending_by_proveedor":
		$id_proveedor = intval($_POST["id_proveedor"] ?? 0);

		$where_clause = "";
		if ($id_proveedor > 0) {
			$where_clause = "AND vc.id_proveedor = $id_proveedor";
		}

		$q = "
		SELECT DISTINCT
			lot.id_CatalogoLotes AS id_lote,
			lot.ccod_Lote AS codigo_lote,
			vcd.cod_gel AS codigo_gel,
			prov.razon_social as proveedor_nombre,
			prov.documento as proveedor_doc,
			lot.peso_actual as peso_humedo,
			vcd.porc_h20 as porcentaje_humedad,
			ROUND(lot.peso_actual / (1 + (vcd.porc_h20 / 100)),2) as peso_seco,
            (
                SELECT
                    ROUND(COALESCE(AVG(anl.valor),0),2) AS promedio
                FROM
                    tb_leyes_analisis_valor anl
                WHERE
                    -- codigo del lote del primer tramo
                    anl.cod_lote = lot.ccod_Lote AND 
                    -- el grupo: 1: Lotes, 2: Sacos, 3: Consolidadas (las que importan)
                    anl.id_grupo = 3 AND 
                    -- elementos quimico: newau|newag
                    anl.abv_elemento = 'newau' AND 
                    -- que haya sido una ley seleccionada
                    anl.is_select = 1
            ) as ley_oro,
            (
                SELECT
                    ROUND(COALESCE(AVG(anl.valor),0),2) AS promedio
                FROM
                    tb_leyes_analisis_valor anl
                WHERE
                    -- codigo del lote del primer tramo
                    anl.cod_lote = lot.ccod_Lote AND 
                    -- el grupo: 1: Lotes, 2: Sacos, 3: Consolidadas (las que importan)
                    anl.id_grupo = 3 AND 
                    -- elementos quimico: newau|newag
                    anl.abv_elemento = 'newag' AND 
                    -- que haya sido una ley seleccionada
                    anl.is_select = 1
            ) as ley_plata
		FROM
			catalogolotes lot
		INNER JOIN valorizacion_compramineral_detalle vcd ON
			vcd.cod_lote = lot.ccod_Lote
		INNER JOIN valorizacion_compramineral vc on vc.Id = vcd.id_valorizacion
		INNER JOIN comprobante_pago cp on cp.id_valorizacion = vc.Id
		INNER JOIN tb_clientes prov ON prov.Id = vc.id_proveedor
		WHERE 
			-- estados de PAGADO: mixto, banco, anticipos
			cp.estado IN ('A','B','C') AND
			-- que aun tenga saldo
			ROUND(lot.peso_actual, 2) > 0 
			$where_clause
		ORDER BY prov.razon_social, vcd.cod_gel;
		";

		$result = mysqli_query($enlace, $q);
		$lotes = [];

		if ($result) {
			while ($p = mysqli_fetch_assoc($result)) {
				$lotes[] = $p;
			}
		}

		echo json_encode([
			"estado" => 1,
			"data" => ["lotes" => $lotes]
		]);
		break;

	case "crear_blending":
		$lotes = $_POST["lotes"]; // { "id_lote" : "", "peso_tomado": ""}

		// calcular el nuevo correlativo
		$nuevo_numero_correlativo = getNuevoNumeroCorrelativoBlending($enlace);
		$year_short = date('y');
		$numero_con_ceros = str_pad($nuevo_numero_correlativo, 5, "0", STR_PAD_LEFT);
		$nuevo_correlativo = "BLEND-" . $year_short . "-" . $numero_con_ceros;
		//

		$peso_total_tomado = 0;

		// verificar stock y calcular peso total
		foreach ($lotes as $lot) {
			$id_lote = $lot['id_lote'];
			$peso_solicitado = $lot['peso_tomado'];

			$res_stock = mysqli_query($enlace, "
			SELECT 
				peso_actual, 
				ccod_Lote as codigo_lote 
			FROM catalogolotes 
			WHERE id_CatalogoLotes = $id_lote
			");
			$row_stock = mysqli_fetch_assoc($res_stock);

			if (!$row_stock || $row_stock['peso_actual'] < $peso_solicitado) {
				$codigo_lote = $row_stock['codigo_lote'];
				echo json_encode(["estado" => 0, "mensaje" => "El lote $codigo_lote no tiene peso suficiente."]);
				exit;
			}
			$peso_total_tomado += $peso_solicitado;
		}

		// INSERTAR CABECERA
		$q_cabecera = "
		INSERT INTO blending (
			correlativo, 
			numero_correlativo, 
			peso_inicial, 
			peso_actual, 
			estado
		) 
		VALUES (
			'$nuevo_correlativo', 
			$nuevo_numero_correlativo, 
			$peso_total_tomado, 
			$peso_total_tomado, 
			'A'
		)";

		if (mysqli_query($enlace, $q_cabecera)) {
			$nuevo_id_blending = mysqli_insert_id($enlace); // el ID generado

			// Insertar detalles y actualizar stock
			foreach ($lotes as $lot) {
				$id_lote = $lot['id_lote'];
				$peso = $lot['peso_tomado'];

				// Obtener peso actual para log
				$res_log = mysqli_query($enlace, "
				SELECT 
					peso_actual 
				FROM catalogolotes 
				WHERE id_CatalogoLotes = $id_lote");
				$row_log = mysqli_fetch_assoc($res_log);
				$peso_actual_log = $row_log['peso_actual'];

				// Insertar detalle
				$q_det = "
				INSERT INTO blending_detalle (
					id_blending, 
					id_lote, 
					peso_tomado, 
					peso_actual_log
				) 
				VALUES (
					$nuevo_id_blending, 
					$id_lote, 
					$peso, 
					$peso_actual_log
				)";
				mysqli_query($enlace, $q_det);

				// Actualizar peso en catálogo
				$q_upd = "
				UPDATE catalogolotes 
					SET peso_actual = peso_actual - $peso 
				WHERE id_CatalogoLotes = $id_lote";
				mysqli_query($enlace, $q_upd);
			}

			echo json_encode([
				"estado" => 1,
				"mensaje" => "Blending creado con éxito",
				"data" => ["id_blending" => $nuevo_id_blending, "correlativo" => $nuevo_correlativo]
			]);
		} else {
			echo json_encode(["estado" => 0, "mensaje" => "Error al crear cabecera"]);
		}
		break;

	case "get_lista_blending_cabecera":
		$q = "
		SELECT
			bl.id AS id_blending,
			bl.correlativo,
			bl.peso_inicial,
			bl.peso_actual,
			bl.created_at AS fecha_registro,
			calc.total_lotes AS cantidad_lotes,
			CASE
				WHEN bl.estado = 'A' THEN 'Con peso'
				WHEN bl.estado = 'F' THEN 'Agotado'
				ELSE 'Desconocido'
			END AS estado,
			-- Ley de Oro Ponderada (newau)
			ROUND(calc.suma_ponderada_oro / NULLIF(calc.total_peso_seco, 0), 2) AS ley_oro,
			-- Ley de Plata Ponderada (newag)
			ROUND(calc.suma_ponderada_plata / NULLIF(calc.total_peso_seco, 0), 2) AS ley_plata,
			-- Humedad Promedio
			ROUND(calc.avg_h2o, 3) AS humedad_promedio
		FROM
			blending bl
		LEFT JOIN (
			-- Subconsulta centralizada para evitar repetición de JOINs y asegurar resultados exactos al detalle
			SELECT
				id_blending,
				COUNT(id_blending_detalle) AS total_lotes,
				SUM(peso_seco) AS total_peso_seco,
				SUM(peso_seco * ley_oro) AS suma_ponderada_oro,
				SUM(peso_seco * ley_plata) AS suma_ponderada_plata,
				AVG(porc_h20) AS avg_h2o
			FROM (
				SELECT DISTINCT
					bld.id_blending,
					bld.id as id_blending_detalle,
					ROUND(bld.peso_tomado / (1 + (vcd.porc_h20 / 100)), 2) AS peso_seco,
					vcd.porc_h20,
					(
						SELECT ROUND(COALESCE(AVG(anl.valor),0),2)
						FROM tb_leyes_analisis_valor anl
						WHERE anl.cod_lote = lot.ccod_Lote 
						AND anl.id_grupo = 3 
						AND anl.abv_elemento = 'newau' 
						AND anl.is_select = 1
					) AS ley_oro,
					(
						SELECT ROUND(COALESCE(AVG(anl.valor),0),2)
						FROM tb_leyes_analisis_valor anl
						WHERE anl.cod_lote = lot.ccod_Lote 
						AND anl.id_grupo = 3 
						AND anl.abv_elemento = 'newag' 
						AND anl.is_select = 1
					) AS ley_plata
				FROM
					catalogolotes lot
				INNER JOIN blending_detalle bld ON
					bld.id_lote = lot.id_CatalogoLotes
				INNER JOIN valorizacion_compramineral_detalle vcd ON
					vcd.cod_lote = lot.ccod_Lote
				INNER JOIN valorizacion_compramineral vc ON
					vc.Id = vcd.id_valorizacion
			) as sub_detalles
			GROUP BY id_blending
		) calc ON calc.id_blending = bl.id
		ORDER BY 
			bl.correlativo DESC;
		";

		$result = mysqli_query($enlace, $q);
		$blendings = [];

		if ($result) {
			while ($b = mysqli_fetch_assoc($result)) {
				$blendings[] = $b;
			}
		}

		echo json_encode([
			"estado" => 1,
			"data" => ["blendings" => $blendings]
		]);
		break;

	case "get_blending_detalle_by_blending":
		$id_blending = intval($_POST["id_blending"] ?? 0);
		$q = "
		SELECT DISTINCT
			bld.id_blending,
			bld.id as id_blending_detalle,
			lot.id_CatalogoLotes AS id_lote,
            prov.documento as documento_proveedor,
            prov.razon_social as nombre_proveedor,
			vcd.cod_gel AS codigo_gel,
            vcd.cod_lote AS codigo_lote,
			bld.peso_tomado AS peso_humedo,
			vcd.porc_h20 AS porcentaje_humedad,
			ROUND(
				bld.peso_tomado /(1 +(vcd.porc_h20 / 100)),
				2
			) AS peso_seco,
            (
                SELECT
                    ROUND(COALESCE(AVG(anl.valor),0),2) AS promedio
                FROM
                    tb_leyes_analisis_valor anl
                WHERE
                    -- codigo del lote del primer tramo
                    anl.cod_lote = lot.ccod_Lote AND 
                    -- el grupo: 1: Lotes, 2: Sacos, 3: Consolidadas (las que importan)
                    anl.id_grupo = 3 AND 
                    -- elementos quimico: newau|newag
                    anl.abv_elemento = 'newau' AND 
                    -- que haya sido una ley seleccionada
                    anl.is_select = 1
            ) as ley_oro,
            (
                SELECT
                    ROUND(COALESCE(AVG(anl.valor),0),2) AS promedio
                FROM
                    tb_leyes_analisis_valor anl
                WHERE
                    -- codigo del lote del primer tramo
                    anl.cod_lote = lot.ccod_Lote AND 
                    -- el grupo: 1: Lotes, 2: Sacos, 3: Consolidadas (las que importan)
                    anl.id_grupo = 3 AND 
                    -- elementos quimico: newau|newag
                    anl.abv_elemento = 'newag' AND 
                    -- que haya sido una ley seleccionada
                    anl.is_select = 1
            ) as ley_plata
		FROM
			catalogolotes lot
		INNER JOIN blending_detalle bld ON
			bld.id_lote = lot.id_CatalogoLotes
		INNER JOIN valorizacion_compramineral_detalle vcd ON
			vcd.cod_lote = lot.ccod_Lote
		INNER JOIN valorizacion_compramineral vc ON
			vc.Id = vcd.id_valorizacion
        INNER JOIN tb_clientes prov on prov.Id = vc.id_proveedor
		WHERE
			bld.id_blending = $id_blending
		ORDER BY codigo_gel;
		";

		$result = mysqli_query($enlace, $q);
		$detalle_blending = [];

		if ($result) {
			while ($bd = mysqli_fetch_assoc($result)) {
				$detalle_blending[] = $bd;
			}
		}

		echo json_encode([
			"estado" => 1,
			"data" => ["detalle_blending" => $detalle_blending]
		]);
