	case "get_minerales_to_despacho_by_proveedor":
		$id_proveedor = intval($_POST["id_proveedor"] ?? 0);
		$id_planta = intval($_POST["id_planta"] ?? 0);

		// obtener los lotes del proveedor
		$q_lotes = "
		SELECT DISTINCT
			lot.id_CatalogoLotes AS id_mineral,
			vcd.cod_gel AS codigo,
			lot.nPesoNetoBalanza AS peso_inicial,
			lot.peso_actual,
			FALSE as is_blending,
			1 as all_proveedores_asociados -- Lote individual siempre es 1 por lógica de negocio previa
		FROM catalogolotes lot
		INNER JOIN valorizacion_compramineral_detalle vcd ON vcd.cod_lote = lot.ccod_Lote
		INNER JOIN valorizacion_compramineral vc ON vc.Id = vcd.id_valorizacion
		INNER JOIN comprobante_pago cp ON cp.id_valorizacion = vc.Id
		WHERE 
			cp.estado IN('A', 'B', 'C') AND 
			ROUND(lot.peso_actual, 2) > 0 AND 
			vc.id_proveedor = $id_proveedor
		ORDER BY codigo;
		";

		// obtener lista de blendings - con un indicador de si se puede o no usar
		$q_blendings = "
		SELECT DISTINCT
			bl.id AS id_mineral,
			bl.correlativo AS codigo,
			bl.peso_inicial,
			bl.peso_actual,
			TRUE AS is_blending,
			-- FLAG: Si existe al menos un lote sin planta_proveedor, devuelve 0, si no 1
			(
				SELECT 
					CASE 
						WHEN COUNT(*) > 0 THEN 0 ELSE 1
					END
				FROM
					blending_detalle bld_sub
				INNER JOIN catalogolotes lot_sub ON
					lot_sub.id_CatalogoLotes = bld_sub.id_lote
				INNER JOIN valorizacion_compramineral_detalle vcd_sub ON
					vcd_sub.cod_lote = lot_sub.ccod_Lote
				INNER JOIN valorizacion_compramineral vc_sub ON
					vc_sub.Id = vcd_sub.id_valorizacion
				LEFT JOIN planta_proveedor plp_sub ON
					plp_sub.id_proveedor = vc_sub.id_proveedor AND plp_sub.id_planta = $id_planta
				WHERE
					bld_sub.id_blending = bl.id AND plp_sub.id_proveedor IS NULL
			) AS all_proveedores_asociados
		FROM
			blending bl
		WHERE
			bl.estado = 'A' AND ROUND(bl.peso_actual, 2) > 0 AND 
			EXISTS(
				SELECT
					1
				FROM
					blending_detalle bld_ex
				INNER JOIN catalogolotes lot_ex ON
					lot_ex.id_CatalogoLotes = bld_ex.id_lote
				INNER JOIN valorizacion_compramineral_detalle vcd_ex ON
					vcd_ex.cod_lote = lot_ex.ccod_Lote
				INNER JOIN valorizacion_compramineral vc_ex ON
					vc_ex.Id = vcd_ex.id_valorizacion
				WHERE
					bld_ex.id_blending = bl.id AND vc_ex.id_proveedor = $id_proveedor
			)
		ORDER BY
			bl.numero_correlativo;
		";

		$minerales = [];

		// Ejecutar Lotes
		$resLotes = mysqli_query($enlace, $q_lotes);
		if ($resLotes) {
			while ($l = mysqli_fetch_assoc($resLotes)) {
				$l['detalles_blending'] = []; // Lotes individuales no tienen este detalle
				$minerales[] = $l;
			}
		}

		// Ejecutar Blendings
		$resBlendings = mysqli_query($enlace, $q_blendings);
		if ($resBlendings) {
			while ($b = mysqli_fetch_assoc($resBlendings)) {
				$b['all_proveedores_asociados'] = intval($b['all_proveedores_asociados']);
				$b['detalles_blending'] = [];

				// SI EL FLAG ES 0, BUSCAMOS EL DETALLE DE SUS LOTES Y PROVEEDORES
				if ($b['all_proveedores_asociados'] === 0) {
					$id_blending = $b['id_mineral'];
					$q_detalles = "
					SELECT DISTINCT
						lot.ccod_Lote AS codigo_lote,
						vc.id_proveedor,
						prov.documento,
						prov.razon_social,
						IF(plp.id_proveedor IS NULL, 0, 1) AS asociado_planta
					FROM
						blending_detalle bld
					INNER JOIN catalogolotes lot ON
						lot.id_CatalogoLotes = bld.id_lote
					INNER JOIN valorizacion_compramineral_detalle vcd ON
						vcd.cod_lote = lot.ccod_Lote
					INNER JOIN valorizacion_compramineral vc ON
						vc.Id = vcd.id_valorizacion
					LEFT JOIN planta_proveedor plp ON
						plp.id_proveedor = vc.id_proveedor AND plp.id_planta = $id_planta
					LEFT JOIN tb_clientes prov on prov.Id = vc.id_proveedor
					WHERE
						bld.id_blending = $id_blending
					";

					$resDet = mysqli_query($enlace, $q_detalles);
					while ($det = mysqli_fetch_assoc($resDet)) {
						$b['detalles_blending'][] = $det;
					}
				}
				$minerales[] = $b;
			}
		}

		echo json_encode([
			"estado" => 1,
			"data" => ["minerales" => $minerales]
		]);
		break;

	case "get_despacho_detalle_by_despacho":
		$id_despacho = intval($_POST["id_despacho"] ?? 0);
		$q = "
		SELECT
			dsd.id as id_despacho_detalle,
			CASE
				WHEN dsd.is_blending = 1 THEN (
					SELECT 
						bln.correlativo 
					FROM blending bln 
					WHERE bln.id = dsd.id_mineral
					LIMIT 1
					)
				WHEN dsd.is_blending = 0 THEN (
					SELECT 
						vcd.cod_gel
					FROM catalogolotes lot 
					INNER JOIN valorizacion_compramineral_detalle vcd ON vcd.cod_lote = lot.ccod_Lote
					INNER JOIN valorizacion_compramineral vc on vc.Id = vcd.id_valorizacion
					INNER JOIN comprobante_pago cp on cp.id_valorizacion = vc.Id
					WHERE cp.estado IN('A', 'B', 'C') AND lot.id_CatalogoLotes = dsd.id_mineral
					LIMIT 1
				)
			END AS codigo,
			dsd.is_blending,
			dsd.peso_tomado,
			dsd.peso_actual,
			dsd.peso_actual_log,
			(dsd.peso_tomado - dsd.peso_actual) as peso_distribuido,
			dsd.estado
		FROM
			despacho_detalle dsd
		WHERE
			dsd.id_despacho = $id_despacho
		ORDER BY codigo;
		";

		$result = mysqli_query($enlace, $q);
		$detalle_blending = [];

		if ($result) {
			while ($bd = mysqli_fetch_assoc($result)) {
				$detalle_blending[] = $bd;
			}
		}

		echo json_encode([
			"estado" => 1,
			"data" => ["detalle_blending" => $detalle_blending]
		]);
		break;

	case "crear_despacho":
		$minerales = $_POST["minerales"]; // { "id_mineral" : "", "is_blending": "", "peso_tomado": ""}
		$id_proveedor = intval($_POST["id_proveedor"] ?? 0);
		$id_planta = intval($_POST["id_planta"] ?? 0);


		// calcular el nuevo correlativo
		$nuevo_numero_correlativo = getNuevoNumeroCorrelativoDespacho($enlace);
		$year_short = date('y');
		$month_short = date('m');
		$day_short = date('d');
		$numero_con_ceros = str_pad($nuevo_numero_correlativo, 5, "0", STR_PAD_LEFT);
		$nuevo_correlativo = "DSP-" . $year_short . "-" . $month_short . "-" . $day_short . "-" . $numero_con_ceros;
		$estado_inicial = 'A';

		// verificar stock y calcular peso total
		foreach ($minerales as $min) {
			$id_mineral = intval($min['id_mineral']);
			$peso_solicitado = floatval($min['peso_tomado']);
			$is_blending = filter_var($min['is_blending'], FILTER_VALIDATE_BOOLEAN);

			if ($is_blending) {
				// Es un blending
				$res_stock = mysqli_query($enlace, "
				SELECT 
					peso_actual, 
					correlativo as codigo
				FROM blending 
				WHERE id = $id_mineral
				");
			} else {
				// Es un lote
				$res_stock = mysqli_query($enlace, "
				SELECT 
					peso_actual, 
					ccod_Lote as codigo 
				FROM catalogolotes 
				WHERE id_CatalogoLotes = $id_mineral
				");
			}

			$row_stock = mysqli_fetch_assoc($res_stock);

			if (!$row_stock || round($row_stock['peso_actual'], 2) < round($peso_solicitado, 2)) {
				$codigo = $row_stock ? $row_stock['codigo'] : "ID: $id_mineral";
				echo json_encode(["estado" => 0, "mensaje" => "El mineral $codigo no tiene peso suficiente."]);
				exit;
			}
		}

		// INSERTAR CABECERA
		$q_cabecera = "
		INSERT INTO despacho(
			id_planta,
			id_proveedor,
			correlativo,
			numero_correlativo,
			estado
		)
		VALUES(
			$id_planta,
			$id_proveedor,
			'$nuevo_correlativo',
			$nuevo_numero_correlativo,
			'$estado_inicial'
		)";

		if (mysqli_query($enlace, $q_cabecera)) {
			$nuevo_id_despacho = mysqli_insert_id($enlace); // el ID generado

			// Insertar detalles y actualizar stock
			foreach ($minerales as $min) {
				$id_mineral = intval($min['id_mineral']);
				$peso = floatval($min['peso_tomado']);
				$is_blending = filter_var($min['is_blending'], FILTER_VALIDATE_BOOLEAN);
				$is_blending_int = $is_blending ? 1 : 0;

				// Obtener peso actual para log
				if ($is_blending) {
					$res_log = mysqli_query($enlace, "SELECT peso_actual FROM blending WHERE id = $id_mineral");
				} else {
					$res_log = mysqli_query($enlace, "SELECT peso_actual FROM catalogolotes WHERE id_CatalogoLotes = $id_mineral");
				}

				$row_log = mysqli_fetch_assoc($res_log);
				$peso_actual_log = $row_log['peso_actual'];

				// Insertar detalle
				$q_det = "
				INSERT INTO despacho_detalle(
					id_mineral,
					id_despacho,
					is_blending,
					peso_tomado,
					peso_actual,
					peso_actual_log,
					estado
				)
				VALUES(
					$id_mineral,
					$nuevo_id_despacho,
					$is_blending_int,
					$peso,
					$peso,
					$peso_actual_log,
					'$estado_inicial'
				)";
				mysqli_query($enlace, $q_det);

				// Actualizar peso en catálogo o blending
				if ($is_blending) {
					$q_upd = "UPDATE blending SET peso_actual = peso_actual - $peso WHERE id = $id_mineral";
				} else {
					$q_upd = "UPDATE catalogolotes SET peso_actual = peso_actual - $peso WHERE id_CatalogoLotes = $id_mineral";
				}
				mysqli_query($enlace, $q_upd);
			}

			echo json_encode([
				"estado" => 1,
				"mensaje" => "Despacho creado con éxito",
				"data" => ["id_despacho" => $nuevo_id_despacho, "correlativo" => $nuevo_correlativo]
			]);
		} else {
			echo json_encode(["estado" => 0, "mensaje" => "Error al crear cabecera"]);
		}
		break;

	case "get_lista_transportistas":
		$q = "
		SELECT
			trn.Id AS id_transportista,
			trn.documento,
			trn.razon_social
