	case "get_minerales_of_despacho_to_distribucion":
		$id_despacho = intval($_POST["id_despacho"] ?? 0);

		$q = "
		SELECT DISTINCT
			dsd.id as id_despacho_detalle,
			dsd.id_despacho,
			dsd.id_mineral,
			CASE
				WHEN dsd.is_blending = 1 THEN (
					SELECT 
						bln.correlativo 
					FROM blending bln 
					WHERE bln.id = dsd.id_mineral)
				WHEN dsd.is_blending = 0 THEN (
					SELECT DISTINCT
						vcd.cod_gel
					FROM catalogolotes lot 
					INNER JOIN valorizacion_compramineral_detalle vcd ON vcd.cod_lote = lot.ccod_Lote
					INNER JOIN valorizacion_compramineral vc on vc.Id = vcd.id_valorizacion
					INNER JOIN comprobante_pago cp on cp.id_valorizacion = vc.Id
					WHERE cp.estado IN('A', 'B', 'C') AND lot.id_CatalogoLotes = dsd.id_mineral
                    LIMIT 1
				)
			END AS codigo,
			dsd.is_blending,
			dsd.peso_actual_log,
			dsd.peso_tomado,
			dsd.peso_actual
		FROM
			despacho_detalle dsd
		WHERE
			dsd.id_despacho = $id_despacho AND 
			dsd.peso_actual > 0 AND
			dsd.estado = 'A'
		";
		$result = mysqli_query($enlace, $q);
		$minerales = [];
		if ($result) {
			while ($r = mysqli_fetch_assoc($result)) {
				$minerales[] = $r;
			}
		}
		echo json_encode(["estado" => 1, "data" => ["minerales" => $minerales]]);
		break;

	case "crear_distribucion":
		$id_unidad = intval($_POST["id_unidad"] ?? 0);
		$id_empresa_transporte = intval($_POST["id_empresa_transporte"] ?? 0);
		$id_tolva = intval($_POST["id_tolva"] ?? 0);
		$id_empresa_transporte_tolva = intval($_POST["id_empresa_transporte_tolva"] ?? 0);
		$id_despacho = intval($_POST["id_despacho"] ?? 0);
		$serie_segunda_placa = mysqli_real_escape_string($enlace, $_POST["serie_segunda_placa"] ?? '');
		$numero_segunda_placa = mysqli_real_escape_string($enlace, $_POST["numero_segunda_placa"] ?? '');
		$fecha_estimada = mysqli_real_escape_string($enlace, $_POST["fecha_estimada"] ?? '');
		$estado_inicial = $_POST["estado"] ?? 'A';
		$id_usuario_registro = intval($_SESSION["Id"] ?? 0);
		$detalle = $_POST["detalle"]; // id_despacho_detalle - peso_tomado - tipo_carga - cantidad_bigbags

		if ($id_unidad <= 0 || $id_empresa_transporte <= 0 || $id_despacho <= 0 || empty($detalle)) {
			echo json_encode(["estado" => 0, "mensaje" => "Datos incompletos"]);
			exit;
		}

		foreach ($detalle as $item) {
			$id_dd = intval($item['id_despacho_detalle']);
			$peso = floatval($item['peso_tomado']);
			$res_chk = mysqli_query($enlace, "SELECT peso_actual FROM despacho_detalle WHERE id = $id_dd");
			$row_chk = mysqli_fetch_assoc($res_chk);

			// New logic for validation
			$tipo_carga = intval($item['tipo_carga']);
			$cantidad_bigbags = intval($item['cantidad_bigbags'] ?? 0);

			if (!$row_chk || round($row_chk['peso_actual'], 2) < round($peso, 2)) {
				echo json_encode(["estado" => 0, "mensaje" => "Peso insuficiente."]);
				exit;
			}

			if ($tipo_carga == 2 && $cantidad_bigbags <= 0) {
				echo json_encode(["estado" => 0, "mensaje" => "Cantidad de BigBags inválida."]);
				exit;
			}
		}

		$q_cabecera = "
		INSERT INTO distribucion(
			id_unidad, 
			id_despacho, 
			id_empresa_transporte,
			id_tolva,
			id_empresa_transporte_tolva,
			serie_segunda_placa,
			numero_segunda_placa,
			fecha_estimada, 
			estado,
			id_usuario_registro
		) VALUES(
		 	$id_unidad, 
			$id_despacho, 
			$id_empresa_transporte,
			" . ($id_tolva > 0 ? $id_tolva : "NULL") . ",
			" . ($id_empresa_transporte_tolva > 0 ? $id_empresa_transporte_tolva : "NULL") . ",
			'$serie_segunda_placa',
			'$numero_segunda_placa',
			'$fecha_estimada', 
			'$estado_inicial',
			$id_usuario_registro
		)
		";

		if (mysqli_query($enlace, $q_cabecera)) {
			$id_distribucion = mysqli_insert_id($enlace);
			f_LogDistribucion($enlace, $id_distribucion, 'Registrado', 'Distribución creada.');
			foreach ($detalle as $item) {
				$id_dd = intval($item['id_despacho_detalle']);
				$peso = floatval($item['peso_tomado']);
				$tipo_carga = intval($item['tipo_carga']);
				$cantidad_bigbags = ($tipo_carga == 2) ? intval($item['cantidad_bigbags']) : 'NULL';

				$res_log = mysqli_query($enlace, "SELECT peso_tomado, peso_actual FROM despacho_detalle WHERE id = $id_dd");
				$row_log = mysqli_fetch_assoc($res_log);
				$peso_tomado_log = $row_log['peso_tomado'];
				$peso_actual_log = $row_log['peso_actual'];

				// solo si la distribucion_detalle NO tomara todo el peso de un despacho_detalle, el campo
				// numero_parte tendra un numero, caso contrario sera null
				// el que sea null significara que estara usando todo el peso del despacho_detalle
				$num_parte = "NULL";
				if ($peso != $peso_tomado_log) {
					$res_parte = mysqli_query($enlace, "SELECT COUNT(id) + 1 as num FROM distribucion_detalle WHERE id_despacho_detalle = $id_dd");
					$row_parte = mysqli_fetch_assoc($res_parte);
					$num_parte = $row_parte['num'] ?? 1;
				}

				$q_det = "
				INSERT INTO distribucion_detalle(
					id_despacho_detalle, 
					id_distribucion, 
					numero_parte, 
					peso_tomado, 
					peso_actual_log,
					tipo_carga,
                    cantidad_bigbags
				) VALUES(
					$id_dd, 
					$id_distribucion, 
					$num_parte, 
					$peso, 
					$peso_actual_log,
					$tipo_carga,
                    $cantidad_bigbags
				)
				";

				mysqli_query($enlace, $q_det);
				mysqli_query($enlace, "UPDATE despacho_detalle SET peso_actual = peso_actual - $peso WHERE id = $id_dd");
			}
			echo json_encode(["estado" => 1, "mensaje" => "Distribución creada con éxito"]);
		} else {
			echo json_encode(["estado" => 0, "mensaje" => "Error al crear cabecera"]);
		}
		break;

	case "cerrar_distribucion":
		$id_distribucion = intval($_POST["id_distribucion"] ?? 0);
		$id_usuario_cierre = intval($_SESSION["Id"] ?? 0);

		if ($id_distribucion <= 0) {
			echo json_encode(["estado" => 0, "mensaje" => "ID no válido"]);
			exit;
		}

		$q_upd = "
		UPDATE distribucion 
		SET 
			estado_cierre = '1', 
			fecha_hora_cierre = NOW(), 
			id_usuario_cierre = $id_usuario_cierre 
		WHERE id = $id_distribucion
		";

		if (mysqli_query($enlace, $q_upd)) {
			f_LogDistribucion($enlace, $id_distribucion, "Distribucion cerrada", "Todo listo para recepcionar a la unidad.");
			echo json_encode(["estado" => 1, "mensaje" => "Distribución cerrada con éxito"]);
		} else {
			echo json_encode(["estado" => 0, "mensaje" => "Error al cerrar"]);
		}
		break;

	case "abrir_distribucion":
		$id_distribucion = intval($_POST["id_distribucion"] ?? 0);
		$id_usuario_apertura = intval($_SESSION["Id"] ?? 0);

		if ($id_distribucion <= 0) {
			echo json_encode(["estado" => 0, "mensaje" => "ID no válido"]);
			exit;
		}

		$q_upd = "
		UPDATE distribucion 
		SET 
			estado_cierre = '0', 
			fecha_hora_cierre = NULL, 
			id_usuario_cierre = NULL 
		WHERE id = $id_distribucion
		";

		if (mysqli_query($enlace, $q_upd)) {
			f_LogDistribucion($enlace, $id_distribucion, "Carga Reabierta", "Se reabrió la carga para su modificación.");
			echo json_encode(["estado" => 1, "mensaje" => "Distribución reabierta con éxito"]);
		} else {
			echo json_encode(["estado" => 0, "mensaje" => "Error al reabrir"]);
		}
		break;

	case "marcar_llegada_planta_destino":
		$id_distribucion = intval($_POST["id_distribucion"] ?? 0);
		$fecha_hora_llegada = mysqli_real_escape_string($enlace, $_POST["fecha_hora_llegada"] ?? '');

		if ($id_distribucion <= 0 || empty($fecha_hora_llegada)) {
			echo json_encode(["estado" => 0, "mensaje" => "Datos inválidos"]);
			exit;
		}

		$q_upd = "
		UPDATE distribucion 
		SET 
			estado = 'D', 
			fecha_hora_llegada_planta_destino = '$fecha_hora_llegada'
		WHERE id = $id_distribucion AND estado = 'C'
		";

		if (mysqli_query($enlace, $q_upd)) {
			if (mysqli_affected_rows($enlace) > 0) {
				f_LogDistribucion($enlace, $id_distribucion, "Llegada Destino", "La unidad llegó a la planta de destino.");
				echo json_encode(["estado" => 1, "mensaje" => "Llegada a destino registrada con éxito"]);
			} else {
				echo json_encode(["estado" => 0, "mensaje" => "No se pudo actualizar. Verifique que la distribución esté en estado 'Salió de planta'."]);
			}
		} else {
			echo json_encode(["estado" => 0, "mensaje" => "Error al registrar llegada"]);
		}
		break;

	case "get_distribuciones_by_despacho":
		$id_despacho = intval($_POST["id_despacho"] ?? 0);
		$q = "
		SELECT
			dist.id as id_distribucion,
			dist.id_unidad,
			dist.id_despacho,
			trn.documento as documento_transportista,
			trn.razon_social as nombre_transportista,
			tpv.descripcion as tipo_vehiculo,
			uni.cplaca as placa,
			dist.serie_segunda_placa,
			dist.numero_segunda_placa,
			uni.nCapacidad as capacidad,
			(
				SELECT 
					SUM(dstd.peso_tomado)
				FROM distribucion_detalle dstd
				WHERE dstd.id_distribucion = dist.id
			) as peso_acumulado,
			dist.fecha_estimada,
			dist.created_at as fecha_registro,
			CONCAT(IFNULL(E.nombres, ''), ' ', IFNULL(E.apellido_paterno, '')) as usuario_registro,
			dist.fecha_hora_llegada,
			dist.fecha_hora_salida,
			dist.estado,
			dist.estado_peso,
			dist.estado_cierre,
			dist.fecha_hora_cierre,
			dist.fecha_hora_llegada_planta_destino,
			CONCAT(IFNULL(E2.nombres, ''), ' ', IFNULL(E2.apellido_paterno, '')) as usuario_cierre
		FROM
			distribucion dist
		INNER JOIN transporte uni on uni.id_transporte = dist.id_unidad
		INNER JOIN tb_clientes trn on trn.Id = dist.id_empresa_transporte
		INNER JOIN tbconfig_tipovehiculo tpv on tpv.Id = uni.id_tipovehiculo
		LEFT JOIN tb_usuario U ON dist.id_usuario_registro = U.Id
		LEFT JOIN tb_empleados E ON U.id_empleado = E.Id
		LEFT JOIN tb_usuario U2 ON dist.id_usuario_cierre = U2.Id
		LEFT JOIN tb_empleados E2 ON U2.id_empleado = E2.Id
		WHERE dist.id_despacho = $id_despacho
		ORDER BY dist.fecha_estimada ASC, dist.id ASC;
		";
		$result = mysqli_query($enlace, $q);
		$distribuciones = [];
		if ($result) {
			while ($r = mysqli_fetch_assoc($result)) {
				$distribuciones[] = $r;
			}
		}
		echo json_encode(["estado" => 1, "data" => ["distribuciones" => $distribuciones]]);
		break;

	case "registrar_carreta_rapida":
		$id_transportista = intval($_POST["id_transportista"] ?? 0);
		$placa = mysqli_real_escape_string($enlace, strtoupper(trim($_POST["placa"] ?? '')));

		if ($id_transportista <= 0 || empty($placa)) {
			echo json_encode(["estado" => 0, "mensaje" => "Datos incompletos"]);
			exit;
		}

		// Verificar si ya existe
		$res_ex = mysqli_query($enlace, "SELECT id_transporte FROM transporte WHERE cplaca = '$placa'");
		if ($res_ex && mysqli_num_rows($res_ex) > 0) {
			$row = mysqli_fetch_assoc($res_ex);
			echo json_encode(["estado" => 1, "mensaje" => "La carreta ya existe.", "data" => ["id_transporte" => $row['id_transporte']]]);
			exit;
		}

		$q = "INSERT INTO transporte (cplaca, id_Transportista, id_tipovehiculo, cEstado_Registro) VALUES ('$placa', $id_transportista, 7, 'A')";
		if (mysqli_query($enlace, $q)) {
			echo json_encode(["estado" => 1, "mensaje" => "Carreta registrada.", "data" => ["id_transporte" => mysqli_insert_id($enlace)]]);
		} else {
			echo json_encode(["estado" => 0, "mensaje" => "Error al registrar: " . mysqli_error($enlace)]);
		}
		break;

	case "get_detalle_distribucion_by_distribucion":
		$id_distribucion = intval($_POST["id_distribucion"] ?? 0);
		$q = "
		SELECT
			dst.id,
			dst.id_distribucion,
			dst.id_despacho_detalle,
			dst.codigo_en_planta_destino,
			dst.peso_en_planta_destino,
			dst.ley_oro_en_planta_destino,
			dst.ley_plata_en_planta_destino,
			dst.ley_humedad_en_planta_destino,
			dst.ticket_balanza,
			dst.numero_ticket_balanza,
			CASE
				WHEN dsd.is_blending = 1 THEN (
					SELECT
						bl.correlativo
					FROM blending bl
					WHERE bl.id = dsd.id_mineral
				)
				WHEN dsd.is_blending = 0 THEN (
					SELECT
						vcd.cod_gel
					FROM catalogolotes lot
					INNER JOIN valorizacion_compramineral_detalle vcd on vcd.cod_lote = lot.ccod_Lote
					WHERE lot.id_CatalogoLotes = dsd.id_mineral
					LIMIT 1
				)
			END AS codigo,
			dsd.is_blending,
			dst.peso_actual_log,
			dst.peso_tomado,
			dst.peso_tara,
			dst.peso_bruto,
			dst.peso_neto,
			(dst.peso_actual_log - dst.peso_tomado) as peso_restante,
			dst.numero_parte,
			dst.created_at as fecha_registro,
            CASE
            	WHEN dst.tipo_carga = 1 THEN ('Sacos')
                WHEN dst.tipo_carga = 2 THEN (CONCAT('Big Bags | ', dst.cantidad_bigbags))
            END as tipo_carga,
            dst.cantidad_bigbags
		FROM
			distribucion_detalle dst
		INNER JOIN despacho_detalle dsd on dsd.id = dst.id_despacho_detalle
		WHERE dst.id_distribucion = $id_distribucion
		";
		$result = mysqli_query($enlace, $q);
		$detalles = [];
		if ($result) {
			while ($r = mysqli_fetch_assoc($result)) {
				$detalles[] = $r;
			}
		}
		echo json_encode(["estado" => 1, "data" => ["detalles" => $detalles]]);
		break;

	case "guardar_detalles_destino":
		$detalles = json_decode($_POST["detalles"] ?? '[]', true);

		if (empty($detalles) || !is_array($detalles)) {
			echo json_encode(["estado" => 0, "mensaje" => "Datos inválidos"]);
			exit;
		}

		$successCount = 0;
		foreach ($detalles as $det) {
			$id = intval($det["id"] ?? 0);
			$codigo = mysqli_real_escape_string($enlace, $det["codigo"] ?? '');
			$peso = floatval($det["peso"] ?? 0);
			$ley_oro = floatval($det["ley_oro"] ?? 0);
			$ley_plata = floatval($det["ley_plata"] ?? 0);
			$ley_humedad = floatval($det["ley_humedad"] ?? 0);

			if ($id > 0) {
				$q_upd = "
				UPDATE distribucion_detalle 
				SET 
					codigo_en_planta_destino = '$codigo',
					peso_en_planta_destino = $peso,
					ley_oro_en_planta_destino = $ley_oro,
					ley_plata_en_planta_destino = $ley_plata,
					ley_humedad_en_planta_destino = $ley_humedad
				WHERE id = $id
				";

				if (mysqli_query($enlace, $q_upd)) {
					$successCount++;
				}
			}
		}

		echo json_encode([
			"estado" => 1,
			"mensaje" => "Se actualizaron $successCount detalles correctamente"
		]);
		break;


	case "anular_blending":
		$id_blending = intval($_POST["id_blending"] ?? 0);

		// Si el despacho fue borrado, el registro en despacho_detalle ya no existe.
		$q_check = "
			SELECT COUNT(id) as total 
			FROM despacho_detalle 
			WHERE id_mineral = $id_blending 
			AND is_blending = 1 
		";
		$res_check = mysqli_query($enlace, $q_check);
		$row_check = mysqli_fetch_assoc($res_check);

		if ($row_check['total'] > 0) {
			echo json_encode(["estado" => 0, "mensaje" => "No se puede eliminar. El blending está siendo usado en un despacho."]);
			exit;
		}

		// 2. Obtener lotes originales para devolver peso
		$q_det = "SELECT id_lote, peso_tomado FROM blending_detalle WHERE id_blending = $id_blending";
		$res_det = mysqli_query($enlace, $q_det);

		while ($d = mysqli_fetch_assoc($res_det)) {
			$id_lote = $d['id_lote'];
			$peso = $d['peso_tomado'];

			// Devolver peso al lote original
			$q_upd_lote = "UPDATE catalogolotes SET peso_actual = peso_actual + $peso WHERE id_CatalogoLotes = $id_lote";
			mysqli_query($enlace, $q_upd_lote);
		}

		// Eliminar Blending y Detalle 
		mysqli_query($enlace, "DELETE FROM blending_detalle WHERE id_blending = $id_blending");
		if (mysqli_query($enlace, "DELETE FROM blending WHERE id = $id_blending")) {
			echo json_encode(["estado" => 1, "mensaje" => "Blending eliminado y stock revertido correctamente."]);
		} else {
			echo json_encode(["estado" => 0, "mensaje" => "Error al eliminar blending."]);
		}
		break;

	case "anular_despacho":
		$id_despacho = intval($_POST["id_despacho"] ?? 0);
		$q_dists = "SELECT id, estado, IFNULL(estado_cierre, '0') as estado_cierre FROM distribucion WHERE id_despacho = $id_despacho";
		$r_dists = mysqli_query($enlace, $q_dists);
		while ($dis = mysqli_fetch_assoc($r_dists)) {
			// No se puede anular un despacho si tiene alguna unidad ya en planta o que de planta o ya fue cerrada
			if ($dis['estado'] == 'B' || $dis['estado'] == 'C' || $dis['estado_cierre'] == '1') {
				echo json_encode(["estado" => 0, "mensaje" => "No se puede eliminar. Existen unidades en planta, emitidas o aprobadas."]);
				exit;
			}
		}

		// Revertir pesos a Origen (Blending o Lote)
		$q_det = "SELECT id, id_mineral, is_blending, peso_tomado FROM despacho_detalle WHERE id_despacho = $id_despacho";
		$res_det = mysqli_query($enlace, $q_det);

		while ($d = mysqli_fetch_assoc($res_det)) {
			$id_mineral = $d['id_mineral'];
			$peso = $d['peso_tomado'];
			$is_blending = $d['is_blending'];

			if ($is_blending == 1) {
				mysqli_query($enlace, "UPDATE blending SET peso_actual = peso_actual + $peso WHERE id = $id_mineral");
			} else {
				mysqli_query($enlace, "UPDATE catalogolotes SET peso_actual = peso_actual + $peso WHERE id_CatalogoLotes = $id_mineral");
			}
		}

		// Eliminar Distribuciones asociadas
		// Obtener IDs de distribuciones
		$r_dists = mysqli_query($enlace, $q_dists);
		while ($dis = mysqli_fetch_assoc($r_dists)) {
			$id_dist = $dis['id'];
			mysqli_query($enlace, "DELETE FROM distribucion_detalle WHERE id_distribucion = $id_dist");
			mysqli_query($enlace, "DELETE FROM distribucion_log WHERE id_distribucion = $id_dist");
		}
		mysqli_query($enlace, "DELETE FROM distribucion WHERE id_despacho = $id_despacho");

		// Eliminar Despacho y Detalle
		mysqli_query($enlace, "DELETE FROM despacho_detalle WHERE id_despacho = $id_despacho");
		if (mysqli_query($enlace, "DELETE FROM despacho WHERE id = $id_despacho")) {
			echo json_encode(["estado" => 1, "mensaje" => "Despacho y sus distribuciones eliminados. Stock revertido."]);
		} else {
			echo json_encode(["estado" => 0, "mensaje" => "Error al eliminar despacho."]);
		}
		break;

	case "anular_distribucion":
		$id_distribucion = intval($_POST["id_distribucion"] ?? 0);

		// Validar estado de distribucion
		$q_val_dis = "SELECT estado FROM distribucion WHERE id = $id_distribucion";
		$res_val_dis = mysqli_query($enlace, $q_val_dis);
		if ($row_val_dis = mysqli_fetch_assoc($res_val_dis)) {
			if ($row_val_dis['estado'] == 'B' || $row_val_dis['estado'] == 'C') {
				echo json_encode(["estado" => 0, "mensaje" => "No se puede eliminar. La unidad ya ingreso a planta."]);
				exit;
			}
		}

		// Devolver peso al despacho_detalle
		$q_det = "SELECT id_despacho_detalle, peso_tomado FROM distribucion_detalle WHERE id_distribucion = $id_distribucion";
		$res_det = mysqli_query($enlace, $q_det);

		while ($d = mysqli_fetch_assoc($res_det)) {
			$id_dd = $d['id_despacho_detalle'];
			$peso = $d['peso_tomado'];

			// Devolver peso a despacho_detalle
			mysqli_query($enlace, "UPDATE despacho_detalle SET peso_actual = peso_actual + $peso WHERE id = $id_dd");
		}

		// Eliminar Distribucion
		mysqli_query($enlace, "DELETE FROM distribucion_detalle WHERE id_distribucion = $id_distribucion");
		mysqli_query($enlace, "DELETE FROM distribucion_log WHERE id_distribucion = $id_distribucion");
		if (mysqli_query($enlace, "DELETE FROM distribucion WHERE id = $id_distribucion")) {
			echo json_encode(["estado" => 1, "mensaje" => "Distribución eliminada y peso revertido."]);
		} else {
			echo json_encode(["estado" => 0, "mensaje" => "Error al eliminar distribución."]);
		}
		break;

	case "verificar_uso_unidad_en_distribuciones":
		$id_unidad = intval($_POST["id_unidad"] ?? 0);
		$fecha_estimada = mysqli_real_escape_string($enlace, $_POST["fecha_estimada"] ?? '');

		$q = "
			-- si la unidad ha sido o sera usada en alguna distribucion
			-- donde la diferencia entre la fecha de llegada de la unidad 
			-- de la nueva distribucion con la fecha de llegada de la 
			-- alguna distribucion antigua NO supera las 48 horas
			SELECT DISTINCT
				desp.correlativo
			FROM
				distribucion dist
			INNER JOIN despacho desp on desp.id = dist.id_despacho
			WHERE
				dist.id_unidad = $id_unidad AND ABS(
					DATEDIFF(
						dist.fecha_estimada,
						'$fecha_estimada'
					)
				) <= 2;
		";

		$result = mysqli_query($enlace, $q);
		$despachos = [];

		while ($row = mysqli_fetch_assoc($result)) {
			$despachos[] = $row['correlativo'];
		}

		echo json_encode([
			"estado" => 1,
			"data" => [
				"en_uso" => !empty($despachos),
				"despachos_correlativos" => $despachos
			]
		]);
		break;

	case "get_ley_promedio_oro_by_lote":
		$codigo_lote = $_POST["codigo_lote"] ?? "";

		$q = "
		SELECT
			ROUND(COALESCE(AVG(anl.valor),0),2) AS promedio
		FROM
			tb_leyes_analisis_valor anl
		WHERE
			-- filtrando por:
			--
			-- codigo del lote del primer tramo
			anl.cod_lote = '$codigo_lote' AND 
			-- el grupo: 1: Lotes, 2: Sacos, 3: Consolidadas (las que importan)
			anl.id_grupo = 3 AND 
			-- elementos quimico: newau|newag
			anl.abv_elemento = 'newau' AND 
			-- que haya sido una ley seleccionada
			anl.is_select = 1
		";

		$result = mysqli_query($enlace, $q);
		$despachos = [];

		while ($row = mysqli_fetch_assoc($result)) {
			$despachos[] = $row['correlativo'];
		}

		echo json_encode([
			"estado" => 1,
			"data" => [
				"en_uso" => !empty($despachos),
				"despachos_correlativos" => $despachos
			]
		]);
		break;

	case "get_ley_promedio_plata_by_lote":
