				"mensaje" => "Error de base de datos",
				"error" => mysqli_error($enlace)
			]);
		}
		break;

	case "get_distribuciones_to_despacho":
		$estado = 0;
		$mensaje = '';
		$fecha_inicio = mysqli_real_escape_string($enlace, $_POST["fecha_inicio"] ?? '');
		$fecha_fin = mysqli_real_escape_string($enlace, $_POST["fecha_fin"] ?? '');
		$filtro_placa = mysqli_real_escape_string($enlace, $_POST["filtro_placa"] ?? '');
		$id_sucursal = $_SESSION["id_sucursal"];

		$filtro_por_fechas = "";
		if (!empty($fecha_inicio) && !empty($fecha_fin)) {
			$filtro_por_fechas = " AND (DATE(d.fecha_hora_llegada) BETWEEN '$fecha_inicio' AND '$fecha_fin' OR (d.fecha_hora_llegada IS NULL AND DATE(d.fecha_estimada) BETWEEN '$fecha_inicio' AND '$fecha_fin')) ";
		}

		$filtro_por_placa = "";
		if (!empty($filtro_placa)) {
			$filtro_por_placa = " AND (t.cplaca LIKE '%$filtro_placa%' OR CONCAT(d.serie_segunda_placa, '-', d.numero_segunda_placa) LIKE '%$filtro_placa%') ";
		}

		$q_unidades = "
		SELECT
			d.id AS id_distribucion,
			DATE_FORMAT(d.fecha_hora_llegada, '%d/%m/%Y %H:%i:%s') as fecha_hora_llegada,
			DATE_FORMAT(d.fecha_estimada, '%d/%m/%Y') as fecha_estimada,
			t.cplaca AS placa1,
			CONCAT(d.serie_segunda_placa, '-', d.numero_segunda_placa) AS placa2,
			desp.correlativo,
			cli.documento as transportista_ruc,
			cli.razon_social as transportista_rs,
			tv.descripcion as tipo_vehiculo,
			con.dni_licencia as conductor_dni,
			con.nombres as conductor_nombres,
			d.observacion,
            d.estado,
			d.estado_peso,
			(
				SELECT SUM(dd.peso_tomado) 
				FROM distribucion_detalle dd 
				WHERE dd.id_distribucion = d.id
			) as peso_esperado,
			(
				SELECT COUNT(*) 
				FROM distribucion_detalle dd2 
				WHERE dd2.id_distribucion = d.id AND (dd2.peso_neto IS NULL OR dd2.peso_neto <= 0)
			) as incompletos,
			(
				SELECT COUNT(*) 
				FROM distribucion_detalle dd3 
				WHERE dd3.id_distribucion = d.id AND dd3.peso_tara > 0
			) as con_tara,
			(
				SELECT COUNT(*) 
				FROM distribucion_detalle dd4 
				WHERE dd4.id_distribucion = d.id
			) as total_detalles
		FROM
			distribucion d
		INNER JOIN transporte t ON d.id_unidad = t.id_transporte
		INNER JOIN despacho desp ON d.id_despacho = desp.id
		LEFT JOIN tb_clientes cli ON d.id_empresa_transporte = cli.id
		LEFT JOIN tbconfig_tipovehiculo tv ON t.id_tipovehiculo = tv.id
		LEFT JOIN tbconfig_conductores con ON d.id_conductor = con.Id
		WHERE
			d.fecha_hora_llegada IS NOT NULL AND 
			d.fecha_hora_salida IS NULL AND
            -- solo listar si aun tiene lotes por pesar: peso neto null
            EXISTS(
                SELECT
                	dsd.id
                FROM distribucion_detalle dsd
                WHERE 
                	dsd.id_distribucion = d.id AND
                	dsd.peso_neto IS NULL
            ) AND
			 d.id_sucursal = $id_sucursal
			$filtro_por_fechas
			$filtro_por_placa
		ORDER BY
			d.fecha_hora_llegada DESC, d.fecha_estimada DESC
		";

		saveLog(["sql" => $q_unidades]);

		$result = mysqli_query($enlace, $q_unidades);
		$data = [];

		if ($result) {
			while ($row = mysqli_fetch_assoc($result)) {
				$data[] = $row;
			}
			$estado = 1;
		} else {
			$mensaje = mysqli_error($enlace);
		}

		echo json_encode(["estado" => $estado, "data" => $data, "mensaje" => $mensaje]);
		break;

	case "get_detalle_distribucion_to_despacho":
		$estado = 0;
		$mensaje = '';

		$id_distribucion = intval($_POST['id_distribucion'] ?? 0);
		$q_detalles = "
		SELECT
			dis.id AS id_distribucion_detalle,
			dis.tipo_carga,
			dis.cantidad_bigbags,
			dis.numero_parte,
			dis.ticket_balanza,
			dis.numero_ticket_balanza,
			dis.peso_tomado,
			CASE
				WHEN dsd.is_blending = 1 THEN(
					-- peso seco promedio del blending (Peso Seco Total / Peso Humedo Total)
					SELECT 
						(SUM(bld.peso_tomado / (1 + (vcd.porc_h20 / 100))) / SUM(bld.peso_tomado)) * dis.peso_tomado
					FROM blending_detalle bld
					INNER JOIN catalogolotes lot ON bld.id_lote = lot.id_CatalogoLotes
					INNER JOIN valorizacion_compramineral_detalle vcd ON vcd.cod_lote = lot.ccod_Lote
					WHERE bld.id_blending = dsd.id_mineral
				)
				WHEN dsd.is_blending != 1 THEN(
					SELECT DISTINCT
						ROUND(dis.peso_tomado / (1 + (vcd.porc_h20 / 100)),2) as peso_seco
					FROM catalogolotes lot
					INNER JOIN valorizacion_compramineral_detalle vcd ON vcd.cod_lote = lot.ccod_Lote
					WHERE dsd.id_mineral = lot.id_CatalogoLotes
				)
			END AS peso_seco,
			dis.peso_tara,
			dis.peso_bruto,
			dis.peso_neto,
			dsd.is_blending,
			CASE WHEN dsd.is_blending = 1 THEN(
			SELECT
				bld.correlativo
			FROM
				blending bld
			WHERE
				bld.id = dsd.id_mineral
			LIMIT 1
		) ELSE(
			SELECT
				vcd.cod_gel
			FROM
				catalogolotes lot
			INNER JOIN valorizacion_compramineral_detalle vcd ON
				vcd.cod_lote = lot.ccod_Lote
			WHERE
				lot.id_CatalogoLotes = dsd.id_mineral
			LIMIT 1
		)
		END AS codigo_mineral
		FROM
			distribucion_detalle dis
		INNER JOIN despacho_detalle dsd ON
			dsd.id = dis.id_despacho_detalle
		WHERE
			dis.id_distribucion = $id_distribucion;
		";
		$res_detalles = mysqli_query($enlace, $q_detalles);

		$data = [];
		if ($res_detalles) {
			while ($row = mysqli_fetch_assoc($res_detalles)) {
				$data[] = $row;
			}
			$estado = 1;
		} else {
			$mensaje = mysqli_error($enlace);
		}

		echo json_encode(["estado" => $estado, "data" => $data, "mensaje" => $mensaje]);
		break;

	case "update_PesajesSegundoTramo":
		$id_distribucion_detalle = intval($_POST["id_distribucion_detalle"] ?? 0);
		$peso_tara = floatval($_POST["peso_tara"] ?? 0);
		$peso_bruto = floatval($_POST["peso_bruto"] ?? 0);
		$peso_neto = floatval($_POST["peso_neto"] ?? 0);
		$cantidad_bigbags = isset($_POST["cantidad_bigbags"]) && is_numeric($_POST["cantidad_bigbags"]) ? intval($_POST["cantidad_bigbags"]) : 'NULL';

		// Primero revisamos si ya tiene ticket
		$q_check = "SELECT ticket_balanza FROM distribucion_detalle WHERE id = $id_distribucion_detalle";
		$res_check = mysqli_query($enlace, $q_check);
		$row_check = mysqli_fetch_assoc($res_check);

		$ticket_balanza = $row_check['ticket_balanza'];
		$ticket_fields = "";

		if (empty($ticket_balanza)) {
			$nuevo_ticket = getNuevoNumeroCorrelativoDetalleDistribucion($enlace);
			$t_num = $nuevo_ticket['numero_ticket_balanza'];
			$t_txt = $nuevo_ticket['ticket_balanza'];
			$ticket_fields = ", numero_ticket_balanza = $t_num, ticket_balanza = '$t_txt'";
			$ticket_balanza = $t_txt;
		}

		$q_update = "
			UPDATE distribucion_detalle 
			SET 
				peso_tara = $peso_tara,
				peso_bruto = $peso_bruto,
				peso_neto = $peso_neto,
				cantidad_bigbags = $cantidad_bigbags
				$ticket_fields
			WHERE id = $id_distribucion_detalle
		";

		if (mysqli_query($enlace, $q_update)) {
			// Find parent distribucion
			$q_dist = "SELECT id_distribucion FROM distribucion_detalle WHERE id = $id_distribucion_detalle";
			$res_dist = mysqli_query($enlace, $q_dist);
			if ($row_dist = mysqli_fetch_assoc($res_dist)) {
				$id_distribucion = $row_dist['id_distribucion'];
				// Check if ALL details for this distribucion have peso_neto > 0
				$q_check = "SELECT COUNT(*) as incompletos FROM distribucion_detalle WHERE id_distribucion = $id_distribucion AND (peso_neto IS NULL OR peso_neto <= 0)";
				$res_check = mysqli_query($enlace, $q_check);
				if ($row_check = mysqli_fetch_assoc($res_check)) {
					if ($row_check['incompletos'] == 0) {
						mysqli_query($enlace, "UPDATE distribucion SET estado_peso = 'A' WHERE id = $id_distribucion");
						f_LogDistribucion($enlace, $id_distribucion, 'Pesaje Completo', 'Pesaje en destino completado para todos los items.');
					} else {
						mysqli_query($enlace, "UPDATE distribucion SET estado_peso = 'B' WHERE id = $id_distribucion");
						f_LogDistribucion($enlace, $id_distribucion, 'Pesaje Modificado', 'Se registraron pesajes, pero la distribución sigue incompleta.');
					}
				}
			}
			echo json_encode(["estado" => 1, "mensaje" => "Pesos actualizados correctamente.", "ticket_balanza" => $ticket_balanza]);
		} else {
			echo json_encode(["estado" => 0, "mensaje" => "Error al actualizar los pesos."]);
		}
		break;

	// =====================================================================
	// GUÍAS SEGUNDO TRAMO
	// =====================================================================

	case "get_distribuciones_pendientes_guia_2t":
		$estado = 0;
		$mensaje = '';
		$fecha_inicio = mysqli_real_escape_string($enlace, $_POST["fecha_inicio"] ?? '');
		$fecha_fin = mysqli_real_escape_string($enlace, $_POST["fecha_fin"] ?? '');
		$filtro_placa = mysqli_real_escape_string($enlace, $_POST["filtro_placa"] ?? '');

		$filtro_fechas = "";
		if (!empty($fecha_inicio) && !empty($fecha_fin)) {
			$filtro_fechas = " AND DATE(d.fecha_estimada) BETWEEN '$fecha_inicio' AND '$fecha_fin' ";
		}

		$filtro_placa_sql = "";
		if (!empty($filtro_placa)) {
			$filtro_placa_sql = " AND (t.cplaca LIKE '%$filtro_placa%' OR CONCAT(d.serie_segunda_placa, '-', d.numero_segunda_placa) LIKE '%$filtro_placa%') ";
		}

		$id_sucursal = $_SESSION["id_sucursal"];

		$q = "
		SELECT
			d.id AS id_distribucion,
			d.id_unidad,
			d.id_empresa_transporte,
			d.id_despacho,
			d.id_conductor,
			CONCAT(d.serie_segunda_placa, '-', d.numero_segunda_placa) as segunda_placa,
			DATE_FORMAT(d.fecha_estimada, '%Y-%m-%d') AS fecha_estimada,
			DATE_FORMAT(d.fecha_hora_llegada, '%d/%m/%Y %H:%i') AS fecha_hora_llegada,
			d.estado,
			d.estado_peso,
			d.id_guia_segundo_tramo,
			t.cplaca AS placa1,
			desp.correlativo AS correlativo_despacho,
			cli.documento AS transportista_ruc,
			cli.razon_social AS transportista_rs,
			con.dni_licencia AS conductor_dni,
			con.nombres AS conductor_nombre,
			(
				SELECT SUM(dd.peso_tomado) 
				FROM distribucion_detalle dd 
				WHERE dd.id_distribucion = d.id
			) AS peso_total_tomado,
			(
				SELECT SUM(dd.peso_neto) 
				FROM distribucion_detalle dd 
				WHERE dd.id_distribucion = d.id
			) AS peso_total_neto,
			(
				SELECT SUM(dd.peso_bruto) 
				FROM distribucion_detalle dd 
				WHERE dd.id_distribucion = d.id
			) AS peso_total_bruto,
			(
				SELECT SUM(dd.peso_tara) 
				FROM distribucion_detalle dd 
				WHERE dd.id_distribucion = d.id
			) AS peso_total_tara,
			(
				SELECT COUNT(*) 
				FROM distribucion_detalle dd 
				WHERE dd.id_distribucion = d.id
			) AS total_lotes,
			mrc.descripcion as marca,
			t.codigo_mtc
		FROM
			distribucion d
		INNER JOIN transporte t ON d.id_unidad = t.id_transporte
		INNER JOIN despacho desp ON d.id_despacho = desp.id
		LEFT JOIN tb_clientes cli ON d.id_empresa_transporte = cli.id
		LEFT JOIN tbconfig_conductores con ON d.id_conductor = con.Id
		LEFT JOIN tbconfig_unidadesmarca mrc ON t.id_marca = mrc.Id
		WHERE
			d.estado_peso = 'A'
			AND (d.id_guia_segundo_tramo IS NULL OR d.id_guia_segundo_tramo = 0)
			AND d.estado IN ('B','C') AND
			d.id_sucursal = $id_sucursal
			$filtro_fechas
			$filtro_placa_sql
		ORDER BY
			d.fecha_estimada DESC, t.cplaca ASC
		";

		$result = mysqli_query($enlace, $q);
		$data = [];
		if ($result) {
			while ($row = mysqli_fetch_assoc($result)) {
				$data[] = $row;
			}
			$estado = 1;
		} else {
			$mensaje = mysqli_error($enlace);
		}

		echo json_encode(["estado" => $estado, "data" => $data, "mensaje" => $mensaje]);
		break;

	case "get_guias_generadas_2t":
		$estado = 0;
		$mensaje = '';
		$fecha_inicio = mysqli_real_escape_string($enlace, $_POST["fecha_inicio"] ?? '');
		$fecha_fin = mysqli_real_escape_string($enlace, $_POST["fecha_fin"] ?? '');

		$filtro_fechas = "";
		if (!empty($fecha_inicio) && !empty($fecha_fin)) {
			$filtro_fechas = " AND DATE(g.fecha_hora_emision) BETWEEN '$fecha_inicio' AND '$fecha_fin' ";
		}

		$q = "
		SELECT
			g.id,
			g.id_distribucion,
			g.id_marca_tolva,
			g.id_empresa_transporte_tolva,
			DATE_FORMAT(g.fecha_inicio_traslado,'%d/%m/%Y') AS fecha_inicio_traslado,
			DATE_FORMAT(g.fecha_hora_emision,'%d/%m/%Y %H:%i') AS fecha_hora_emision,
			DATE_FORMAT(g.fecha_hora_planta,'%d/%m/%Y %H:%i') AS fecha_hora_planta,
			g.planta_origen,
			CASE 
				WHEN g.planta_origen = 1 THEN 'Huanchaco' 
				WHEN g.planta_origen = 2 THEN 'Laredo' ELSE '-'
			END AS planta_origen_nombre,
			g.guia_remitente_serie,
			g.guia_remitente_numero,
			g.guia_transportista_serie,
			g.guia_transportista_numero,
			g.sin_guia_transportista,
			g.motivo_traslado,
			g.serie_tolva,
			g.numero_tolva,
			g.numero_mtc_tolva,
			g.estado,
			marca.descripcion AS marca_tolva_nombre,
			emp_tolva.razon_social AS empresa_tolva_nombre,
			-- info de las distribuciones asociadas
			(
				SELECT
					GROUP_CONCAT(DISTINCT t2.cplaca SEPARATOR ', ')
				FROM
					distribucion d2
				INNER JOIN transporte t2 ON d2.id_unidad = t2.id_transporte
				WHERE d2.id_guia_segundo_tramo = g.id
			) AS placas,
			(
				SELECT
					GROUP_CONCAT(DISTINCT cli2.razon_social SEPARATOR ', ')
				FROM
					distribucion d2
				LEFT JOIN tb_clientes cli2 ON d2.id_empresa_transporte = cli2.id
				WHERE d2.id_guia_segundo_tramo = g.id
			) AS empresa_transporte,
			(
				SELECT
					SUM(dd2.peso_neto)
				FROM
					distribucion d2
				INNER JOIN distribucion_detalle dd2 ON dd2.id_distribucion = d2.id
				WHERE d2.id_guia_segundo_tramo = g.id
			) AS peso_total_neto,
			(
				SELECT
					SUM(dd2.peso_bruto)
				FROM
					distribucion d2
				INNER JOIN distribucion_detalle dd2 ON dd2.id_distribucion = d2.id
				WHERE d2.id_guia_segundo_tramo = g.id
			) AS peso_total_bruto,
			(
				SELECT
					SUM(dd2.peso_tara)
				FROM
					distribucion d2
				INNER JOIN distribucion_detalle dd2 ON dd2.id_distribucion = d2.id
				WHERE d2.id_guia_segundo_tramo = g.id
			) AS peso_total_tara,
			(
				SELECT
					COUNT(DISTINCT dd2.id)
				FROM
					distribucion d2
				INNER JOIN distribucion_detalle dd2 ON dd2.id_distribucion = d2.id
				WHERE d2.id_guia_segundo_tramo = g.id
			) AS total_lotes
		FROM
			guia_segundo_tramo g
		LEFT JOIN tbconfig_unidadesmarca marca ON
			g.id_marca_tolva = marca.Id
		LEFT JOIN tb_clientes emp_tolva ON
			g.id_empresa_transporte_tolva = emp_tolva.id
		WHERE
			g.estado != '0' 
			$filtro_fechas
		ORDER BY
			g.id DESC
		";

		$result = mysqli_query($enlace, $q);
		$data = [];
		if ($result) {
			while ($row = mysqli_fetch_assoc($result)) {
				// obtener lotes detallados
				$id_guia = $row['id'];
				$q_lotes = "
					SELECT
						dd.id AS id_detalle,
						dd.tipo_carga,
						dd.cantidad_bigbags,
						dd.numero_parte,
						dd.peso_tomado,
						dd.peso_tara,
						dd.peso_bruto,
						dd.peso_neto,
						CASE WHEN dsd.is_blending = 1 THEN (
							SELECT bld.correlativo FROM blending bld WHERE bld.id = dsd.id_mineral LIMIT 1
						) ELSE (
							SELECT lot.ccod_Lote FROM catalogolotes lot WHERE lot.id_CatalogoLotes = dsd.id_mineral LIMIT 1
						) END AS codigo_mineral,
						dsd.is_blending,
						dist.id_despacho,
						desp.correlativo AS correlativo_despacho
					FROM distribucion dist
					INNER JOIN distribucion_detalle dd ON dd.id_distribucion = dist.id
					INNER JOIN despacho_detalle dsd ON dsd.id = dd.id_despacho_detalle
					INNER JOIN despacho desp ON desp.id = dist.id_despacho
					WHERE dist.id_guia_segundo_tramo = $id_guia
					ORDER BY dist.id, dd.id
				";
				$res_lotes = mysqli_query($enlace, $q_lotes);
				$lotes = [];
				if ($res_lotes) {
					while ($lote = mysqli_fetch_assoc($res_lotes)) {
						$lotes[] = $lote;
					}
				}
				$row['lotes'] = $lotes;
				$data[] = $row;
			}
			$estado = 1;
		} else {
			$mensaje = mysqli_error($enlace);
		}

		echo json_encode(["estado" => $estado, "data" => $data, "mensaje" => $mensaje]);
		break;

