		if (!empty($ids_distribuciones)) {
			$ids_str = implode(',', array_map('intval', $ids_distribuciones));
			$q = "
			SELECT
				dd.id AS id_detalle,
				dd.id_distribucion,
				dd.tipo_carga,
				dd.cantidad_bigbags,
				dd.numero_parte,
				dd.peso_tomado,
				dd.peso_tara,
				dd.peso_bruto,
				dd.peso_neto,
				dsd.is_blending,
				CASE WHEN dsd.is_blending = 1 THEN (
