		// Proveemos un fallback para evitar errores SQL si está vacío
		$in_clause = "0";
		if (!empty($ids_despachos)) {
			// Asumiendo que viene como "1,2,3" limpiamos caracteres extraños
			$ids_clean = preg_replace('/[^0-9,]/', '', $ids_despachos);
			if (!empty($ids_clean)) {
				$in_clause = $ids_clean;
