		INNER JOIN despacho des ON
			des.id_proveedor = prov.id
		WHERE
			des.id IN ($in_clause) AND con.estado = 'A'
		GROUP BY con.Id, con.descripcion
		ORDER BY con.descripcion
		";
		$data = [];
		if ($r = mysqli_query($enlace, $q)) {
